  "duration_minutes" int4,
  "release_date" date,
  "poster_url" text COLLATE "pg_catalog"."default",
  "drama" text COLLATE "pg_catalog"."default",
  "directors" jsonb NOT NULL DEFAULT '[]'::jsonb,
  "actors" jsonb NOT NULL DEFAULT '[]'::jsonb,
