)
;
ALTER TABLE "public"."movies" OWNER TO "root";
COMMENT ON COLUMN "public"."movies"."source_id" IS '站点详情页数字 ID（/detail/:id），用于 upsert 去重';
COMMENT ON COLUMN "public"."movies"."source_url" IS '详情页完整 URL，便于溯源';
COMMENT ON COLUMN "public"."movies"."title" IS '片名';
COMMENT ON COLUMN "public"."movies"."categories" IS '类型标签（jsonb 数组，例如：["剧情","爱情"]）';
COMMENT ON COLUMN "public"."movies"."region" IS '国家/地区';
COMMENT ON COLUMN "public"."movies"."duration_minutes" IS '片长（分钟）';
COMMENT ON COLUMN "public"."movies"."release_date" IS '上映日期';
COMMENT ON COLUMN "public"."movies"."poster_url" IS '海报图片地址';
COMMENT ON COLUMN "public"."movies"."drama" IS '剧情简介';
COMMENT ON COLUMN "public"."movies"."directors" IS '导演姓名（jsonb 数组）';
COMMENT ON COLUMN "public"."movies"."actors" IS '演员列表（jsonb 数组，对象含 name/role/image 等）';
COMMENT ON COLUMN "public"."movies"."rating" IS '评分（一位小数）';
COMMENT ON COLUMN "public"."movies"."created_at" IS '创建时间';
COMMENT ON COLUMN "public"."movies"."updated_at" IS '更新时间';
COMMENT ON COLUMN "public"."movies"."subtitle" IS '剧照图片地址';
COMMENT ON TABLE "public"."movies" IS '电影主数据（抓取自 ssr1.scrape.center）';

