BEGIN;
INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (24, 24, 'https://ssr1.scrape.center/detail/24', '阿飞正传 - Days of Being Wild', '["剧情", "爱情", "犯罪"]', '中国香港', 94, '2018-06-25', 'https://p0.meituan.net/movie/85215b28d568ea8e2c97766edd95f890210522.jpg@464w_644h_1e_1c', '英俊不凡的旭仔阿飞 （张国荣饰）是上海移民，他从未见过生母，自小由养母 （潘迪华饰）养大，因此长大后他对生命中遇到的每一个女人都冷酷无情。放荡不羁的他先后与南华体育会售票员苏丽珍 （张曼玉饰）和舞女咪咪 （刘嘉玲饰）同居，但后来又相继抛弃了她们。旭仔从养母处得知，自己原是混着西班牙和菲律宾贵族血统的私生子旭仔决要找到生母，为此他只身前往菲律宾，可是生母拒见，带着怨恨离开。旭仔在离开香港前，将车子给予歪仔 （张学友饰）。咪咪发现旭仔走了，问歪仔知不知道他在那里，歪仔告诉她旭仔去了菲律宾，并将旭仔的车子卖掉，将钱给她去菲律宾找旭仔。一直暗恋苏丽珍的警察超仔 （刘德华饰）目睹了苏丽珍与旭仔的决裂，并在母亲死后，决定改行去跑船。超仔在菲律宾唐人街又遇上了旭仔，不过他假装自己不认识他。不久，旭仔因为买卖假护照而在一场殴斗中身负重伤，超仔问他记不记得某年4月16日下午3时他在做什么，旭仔说要记得的他永远记得，但是他叫超仔告诉苏丽珍他已经不记得了。最后他守着死在一列异国火车上的旭仔。在这同时，另一个阿飞 （梁朝伟饰）精心打理自己准备出门，继续上演着无脚鸟的故事  。', '[{"name": "王家卫", "image": "https://p0.meituan.net/moviemachine/a415fe2facc573cb79e39bfedfc344bb152810.jpg@128w_170h_1e_1c"}]', '[{"name": "张国荣", "role": "饰：旭仔", "image": "https://p0.meituan.net/movie/5de69a492dcbd3f4b014503d4e95d46c28837.jpg@128w_170h_1e_1c"}, {"name": "张曼玉", "role": "饰：苏丽珍", "image": "https://p0.meituan.net/movie/c48c4d1e6f4065a1ff9bc182ed43aa5048545.jpg@128w_170h_1e_1c"}, {"name": "刘德华", "role": "饰：警察超仔", "image": "https://p0.meituan.net/moviemachine/9312e90f25f5ad40f2ceb4561f6fa08830409.jpg@128w_170h_1e_1c"}, {"name": "刘嘉玲", "role": "饰：梁凤英", "image": "https://p1.meituan.net/movie/af1cc9550261e2170333e501db1b3901135228.jpg@128w_170h_1e_1c"}, {"name": "张学友", "role": "饰：歪仔", "image": "https://p1.meituan.net/movie/1ef687c18472b4d7bcca305a3bad429049885.jpg@128w_170h_1e_1c"}, {"name": "潘迪华", "role": "饰：旭的养母", "image": "https://p1.meituan.net/movie/8c316d4febc4cbf135989a3a4f76dfc324027.jpg@128w_170h_1e_1c"}, {"name": "梁朝伟", "role": "饰：另一个阿飞", "image": "https://p1.meituan.net/movie/89ff0954b9026ccd3be9246d2fae7eab132088.jpg@128w_17