INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (25, 36, 'https://ssr1.scrape.center/detail/36', '7号房的礼物 - 7번방의 선물', '["剧情", "喜剧", "家庭"]', '韩国', 127, '2013-01-23', 'https://p1.meituan.net/movie/a53a0200eba15ba483c905c872db9bf4331099.jpg@464w_644h_1e_1c', '1997年，只有6岁儿童智商的智障男子李龙久（柳成龙 饰）和可爱的女儿艺胜（葛素媛 饰）相依为命，生活虽然简单清贫，却充满幸福。某天，执着为女儿买美少女战士书包的龙久意外卷入一起幼童诱拐奸杀案，而死者竟是警察局长的女儿。龙久懵懂无知，搞不清状况，昏头昏脑就被投入监狱。在7号牢房中，聚集着走私犯蘇杨浩（吴达洙 饰）、诈骗犯崔春浩（朴元尚 饰）、通奸犯姜万范（金正泰 饰）、恐吓犯老徐（金基灿 饰）和抢劫犯申奉植（郑万植 饰）等五毒俱全的“社会渣滓”。龙久孩子般纯洁的心渐渐感动了这几个“大坏蛋”，他们甚至不惜冒险将艺胜带入牢房与父亲相会。黑暗冰冷的监牢内，7号牢房阳光满满……', '[{"name": "李焕庆", "image": "https://p0.meituan.net/movie/ab1ba8d000487833ef0f3efc572c088346214.jpg@128w_170h_1e_1c"}]', '[{"name": "柳承龙", "role": "饰：李龙久", "image": "https://p1.meituan.net/movie/1906a40aaa972f5719948aa73baba37a38861.jpg@128w_170h_1e_1c"}, {"name": "郑镇荣", "role": "饰：科长", "image": "https://p1.meituan.net/movie/9e1a868360304409a61f5196117d308038706.jpg@128w_170h_1e_1c"}, {"name": "朴信惠", "role": "饰：李艺胜（成年）", "image": "https://p1.meituan.net/movie/07bc2b898bca065064823a5184e9046958252.jpg@128w_170h_1e_1c"}, {"name": "葛素媛", "role": "饰：李艺胜（幼年）", "image": "https://p0.meituan.net/movie/56097e3f8fd2202fdd5a9ce27d5ab52b21932.jpg@128w_170h_1e_1c"}, {"name": "金正泰", "role": "饰：姜万范", "image": "https://p1.meituan.net/movie/f81816dd622d697b22db7f540505751547485.jpg@128w_170h_1e_1c"}, {"name": "吴达洙", "role": "饰：蘇杨浩", "image": "https://p0.meituan.net/movie/a3937ce2e6ae57232ff62255dd14728044053.jpg@128w_170h_1e_1c"}, {"name": "朴元尚", "role": "饰：崔春浩", "image": "https://p1.meituan.net/movie/2069cba5cfb731c9b0c2bb6c4189623347241.jpg@128w_170h_1e_1c"}, {"name": "郑涵妃", "role": "饰：班主任", "image": "https://p1.meituan.net/movie/a3835f9c2cccf34d87d3a2dc51b3f01e47846.jpg@128w_170h_1e_1c"}, {"name": "金基灿", "role": "饰：老徐", "image": "https://p1.meituan.net/mmdb/3a