INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (26, 25, 'https://ssr1.scrape.center/detail/25', '爱·回家 - 집으로...', '["剧情", "家庭"]', '韩国', 80, '2002-04-05', 'https://p0.meituan.net/movie/de1142a5dceb901eb939eb0bcfc2f88470909.jpg@464w_644h_1e_1c', '坐完火车，又坐汽车，再走弯弯的山路，妈妈领着7岁的相宇去外婆家。作为单身母亲的她为了方便找工作暂时把相宇留在那里。相宇的外婆不能说话，也不识字，而一直生活在可乐、电子游戏和溜冰鞋世界里的相宇，刚开始无法适应连游戏机、电池都没有得卖的农村生活，他开始表现自己的不满，为了买电池，相宇偷走外婆的银头簪拿去卖；相宇还不顾在一旁缝袜子的外婆，在地板上玩起了溜冰。有一天，想吃炸鸡的相宇通过各种手势，终于成功向外婆表达了自己的意愿，而外婆只理解到鸡肉，做出来的是“泡在水里的鸡”———炖鸡，相宇很生气，推翻了饭碗。面对这一切外婆唯一的表示就是不停用手势表示对不起，因为连买电子游戏机电池的钱都给不起，因为不能满足相宇想吃炸鸡的要求而对不起。', '[{"name": "李廷香", "image": "https://p0.meituan.net/movie/765f392f3b058dbbcdb1a13d97f748ec27618.jpg@128w_170h_1e_1c"}]', '[{"name": "俞承豪", "role": "饰：相宇 Sang-woo", "image": "https://p0.meituan.net/movie/dd04e169bedd79f0069d56bf2e0b0eda37256.jpg@128w_170h_1e_1c"}, {"name": "金艺芬", "role": "饰：外婆 Grandmother", "image": "https://p0.meituan.net/movie/0e29fea6f07804c9c953bba9edc78d5e37207.jpg@128w_170h_1e_1c"}, {"name": "童孝熙", "role": "饰：妈妈 Sang-woo''s Mother", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "闵京勋", "role": "饰：阿哲 Cheol-e", "image": "https://p1.meituan.net/movie/1114308b00cb3217598aa5c5a46ed63423595.jpg@128w_170h_1e_1c"}, {"name": "任恩敬", "role": "饰：慧妍 Hae Yeon", "image": "https://p0.meituan.net/movie/cfac2d2faff1f36d8100d184f5deb17631157.jpg@128w_170h_1e_1c"}]', 9.1, '2026-04-24 03:07:06.443382', '2026-04-24 03:07:06.443382', '["https://p1.meituan.net/movie/6f578a0a38bb48b5c6dc36718e8d7710120516.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/e81a419ea031cbf5890cd41b5804fb5755671.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/61ec2726a6b0da877d58c155def1e81d46782.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/ea395757df1d897e235a13d4db0429f874781.jpg@