.meituan.net/movie/d58f1889b07368268c59afa00a83f2b166277.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/a83fd0decd5b62fee30e8c52cd7df2ff95257.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/06cb42f224de65ccf6ebbfe13658b5d745699.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/e93a55f25b4e6393a6cfc61e744c962e70934.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/6e6af65fc7a2591567938dd963bdfcde106592.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/c507b8fe231496b9b37603d1abd9a11d77000.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/f32d3dd2868bcad77cf7073aea68a45a142024.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/0ec1bb399831479e09752decbe5fbe3433266.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/f025e76e1963b6a65d7b1c9146167e0424013.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/c85bc0ba25225196a12abc8844610aec71967.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/72a71785484628abc98da1d0d4960b3d65312.jpg@106w_106h_1e_1c"]');
INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (27, 26, 'https://ssr1.scrape.center/detail/26', '龙猫 - となりのトトロ', '["动画", "冒险", "奇幻", "家庭"]', '日本', 86, '2018-12-14', 'https://p0.meituan.net/movie/c304c687e287c7c2f9e22cf78257872d277201.jpg@464w_644h_1e_1c', '小月（日高法子 配音）的母亲（岛本须美 配音）生病住院了，父亲（糸井重里 配音）带着她与四岁的妹妹小梅（坂本千夏 配音）到乡间居住。她们对那里的环境都感到十分新奇，也发现了很多有趣的事情。她们遇到了很多小精灵，她们来到属于她们的环境中，看到了她们世界中很多的奇怪事物，更与一只大大胖胖的龙猫（高木均 配音）成为了朋友。龙猫与小精灵们利用他们的神奇力量，为小月与妹妹带来了很多神奇的景观，令她们大开眼界。妹妹小梅常常挂念生病中的母亲，嚷着要姐姐带着她去看母亲，但小月拒绝了。小梅竟然自己前往，不料途中迷路了，小月只好寻找她的龙猫及小精灵朋友们的帮助。', '[{"name": "宫崎骏", "image": "https://p1.meituan.net/movie/5d786f92d2049516338e7be0ea3fa4e048311.jpg@128w_170h_1e_1c"}]', '[{"name": "秦岚", "role": "饰：妈妈（配音）", "image": "https://p0.meituan.net/moviemachine/f90ee6f8ab7ca73b14ba9375e24241c7188078.jpg@128w_170h_1e_1c"}, {"name": "糸井重里", "role": "饰：爸爸 / 草壁先生 とうさん Tatsuo Kusakabe", "image": "https://p1.meituan.net/movie/097357dcffec51e42dd6a3fd8445950039220.jpg@128w_170h_1e_1c"}, {"name": "岛本须美", "role": "饰：妈妈 かあさん Yasuko Kusakabe", "image": "https://p0.meituan.net/movie/c9e9cbb67835b1cf88ed88be35beea9336806.jpg@128w_170h_1e_1c"}, {"name": "千叶繁", "role": "饰：割草的男人 草刈り男 Kusakari-Otoko", "image": "https://p1.meituan.net/movie/728ef52a448c3555eb663fd4a0a8a31f41865.jpg@128w_170h_1e_1c"}, {"name": "中村大树", "role": "饰：三轮车上的男人 Man on Tractor", "image": "https://p1.meituan.net/movie/1620ffb9c07d20e71dcfc87156e93e0733051.jpg@128w_170h_1e_1c"}, {"name": "大谷育江", "role": "饰：其他 その他 Additional Voices", "image": "https://p0.meituan.net/movie/6ad2ef39d8d09d71a519abb9d337eb9f37878.jpg@128w_170h_1e_1c"}, {"name": "日高法子", "role": "饰：小月 サツキ Satsuki", "image": "https://p1.meituan.net/movie/cc174f8f1377be179e0b5e8facead51f31267.jpg@128w_170h_1e_1c"}, {"name": "坂本千夏", "role": "饰：小梅 メイ Mei", "image": "https://p1.meituan.net/movie/d39dd140c0a