INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (28, 27, 'https://ssr1.scrape.center/detail/27', '七武士 - 七人の侍', '["剧情", "动作", "冒险"]', '日本', 207, '1954-04-26', 'https://p1.meituan.net/movie/4ffca83fd972f71e291f8ea8d78a4b58594878.jpg@464w_644h_1e_1c', '日本战国时代，一小山村面临着山贼的威胁，为了保护秋天的收成，村中长老决定让去请武士来保护村子安全，但只能拿出的报酬是一天三顿的白米饭。在城里，他们遭到了武士白眼甚至被打。直到勘兵卫（志村乔 饰）的出现，他现今已沦为浪人，几经考虑最后答应了。他对农民说至少需要七名武士，于是久藏（宫口精二 饰）、胜四郎（木村功 饰）、五郎（稻叶义男 饰）、七郎（加东大介 饰）、平八（千秋实 饰）和菊千代（三船敏郎 饰）等六人也加入了队伍，七个人肩负保卫村子的任务。整个防御准备的过程中，武士与农民间发生许多摩擦也闹出不少笑话。而在一次偷袭行动中，有武士为救农民被火枪打死，很快山贼的反扑随之而来，一场恶战即将开始。', '[{"name": "黑泽明", "image": "https://p0.meituan.net/movie/b39ed6b7bf5554a1373196b44236576812849.jpg@128w_170h_1e_1c"}]', '[{"name": "三船敏郎", "role": "饰：菊千代", "image": "https://p0.meituan.net/movie/76ca515b8eaaa8bf4fa0ac4cf479e89026137.jpg@128w_170h_1e_1c"}, {"name": "志村乔", "role": "饰：岛田勘兵卫", "image": "https://p0.meituan.net/movie/90e8fd03bfe7557767334345b94cc49c38759.jpg@128w_170h_1e_1c"}, {"name": "千秋实", "role": "饰：林田平八", "image": "https://p0.meituan.net/movie/2218ace80458d474890658264406eb8627117.jpg@128w_170h_1e_1c"}, {"name": "加东大介", "role": "饰：七郎次", "image": "https://p1.meituan.net/movie/6e0c027dc7857024208fdbd9ced5b84523360.jpg@128w_170h_1e_1c"}, {"name": "稻叶义男", "role": "饰：片山五郎兵卫", "image": "https://p0.meituan.net/movie/730a964c919fd6d8641e3d12630f9dbd10116.jpg@128w_170h_1e_1c"}, {"name": "宫口精二", "role": "饰：久蔵", "image": "https://p1.meituan.net/movie/8766404f78ec06ca6b553cb0a5dd52cf24804.jpg@128w_170h_1e_1c"}, {"name": "木村功", "role": "饰：冈本胜四郎", "image": "https://p0.meituan.net/movie/ba471b540da518713a732f195f4f61a98011.jpg@128w_170h_1e_1c"}, {"name": "藤原釜足", "role": "饰：万造", "image": "https://p0.meituan.net/movie/3ec1db73d981363fc9f9615227d3a66d38280.jpg@128w_170h_1e_1c"}, {"name": "小杉义男", "role": "饰：茂助", "image": "https://p0.meituan.ne