INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (29, 28, 'https://ssr1.scrape.center/detail/28', '美国往事 - Once Upon a Time in America', '["剧情", "犯罪"]', '意大利、美国', 229, '2015-04-23', 'https://p1.meituan.net/movie/92198a6fc8c3f5d13aa1bdf203572c0f99438.jpg@464w_644h_1e_1c', '二十年代的美国，纽约少年“面条”（罗伯特·德尼罗 饰）和几个同龄朋友一起认识了聪明狡黠的“麦大”（詹姆斯·伍兹 饰），他们开始从事走私活动。不久，面条在一场械斗中杀伤人命，被关进监牢。若干年后，“面条”出狱，当时的小伙伴们已经变成了健壮的青年人，在“麦大”的带领下，他们开始了一系列抢劫、盗窃、敲诈活动。随着犯罪活动的不断深入，“麦大”似乎被胜利冲昏了头脑，竟然把美国联邦储备银行也列入了行动目标。“面条”不忍眼看好友走向毁灭，偷偷打电话报警，想逼迫“麦大”收手。警察与“面条”的朋友展开激烈枪战，“麦大”等人全部被杀。“面条”带着深深的悔恨和痛苦，离开纽约，回到年少时生长的地方。三十五年过去了，几近垂暮的“面条”重新回到纽约的伤心地，他遇见了少时的朋友和旧情人，而当年“麦大”他们的死，背后竟然包含着出乎意料的阴谋。', '[{"name": "赛尔乔·莱翁内", "image": "https://p0.meituan.net/movie/bc6d42116220a072db01371208b5157815631.jpg@128w_170h_1e_1c"}]', '[{"name": "罗伯特·德尼罗", "role": "饰：面条 Noodles", "image": "https://p0.meituan.net/movie/42ac5e3e243291d71f65abf917e9352719444.jpg@128w_170h_1e_1c"}, {"name": "詹姆斯·伍兹", "role": "饰：麦克斯 Max", "image": "https://p1.meituan.net/movie/2f7c997ec7b7a98fc3a0a0be331e9d7936359.jpg@128w_170h_1e_1c"}, {"name": "伊丽莎白·麦戈文", "role": "饰：黛博拉 Deborah Gelly", "image": "https://p1.meituan.net/moviemachine/462986ee3bfcdaee1fa839a34445e65f40444.jpg@128w_170h_1e_1c"}, {"name": "詹妮弗·康纳利", "role": "饰：少年黛博拉 Young Deborah", "image": "https://p1.meituan.net/movie/acba313467461d1e05716c196543e67d54506.jpg@128w_170h_1e_1c"}, {"name": "乔·佩西", "role": "饰：弗兰基 Frankie Minaldi", "image": "https://p1.meituan.net/movie/c6e544e7d2a0145105ee532f16638e8e39939.jpg@128w_170h_1e_1c"}, {"name": "斯科特·科菲", "role": "饰：少年 Teenager (uncredited)", "image": "https://p1.meituan.net/movie/a343914f6d1c198554b6f89bd8a7efa646521.jpg@128w_170h_1e_1c"}, {"name": "理查德·布赖特", "role": "饰：鸡乔 Chicken Joe", "image": "https://p0.meituan.net/movie/757ad90a3a2a26039b70a77169f674629747.jpg@128w_170h_1e_1c"}, {"