INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (30, 29, 'https://ssr1.scrape.center/detail/29', '完美的世界 - A Perfect World', '["剧情", "犯罪"]', '美国', 138, '1993-11-24', 'https://p1.meituan.net/movie/30310858fdab34c7a17cfd7ec8ad8bfc112201.jpg@464w_644h_1e_1c', '单亲孩子菲利普·佩里（T·J·劳瑟 饰）的母亲对他管教甚严，8岁的小菲利普甚至从未参加过一次鬼节讨糖果的游戏。附近州监狱的两名罪犯越狱成功，劫持了菲利普作为人质，向德州边界逃窜。途中，罪犯之一的布奇（凯文·科斯特纳 饰）干掉了鲁莽愚蠢的同伙，却对小菲利普照顾有佳。与此同时，德州警探瑞德（克林特·伊斯特伍德 饰）带着手下和州长特派的犯罪专家萨利（劳拉·邓恩 饰）一同火速追捕布奇。双方在德克萨斯州境内展开了一场公路赛大竞技；而小菲利普也经历了很多从未想过过的刺激与快乐，并与布奇产生了一种近似父子的不寻常感情……', '[{"name": "克林特·伊斯特伍德", "image": "https://p1.meituan.net/moviemachine/d1156c14dd899ada7c2b98bc373021c852875.jpg@128w_170h_1e_1c"}]', '[{"name": "凯文·科斯特纳", "role": "饰：Robert ''Butch'' Haynes", "image": "https://p0.meituan.net/movie/c4331ef1c71624e8192a19bffd6c866c33173.jpg@128w_170h_1e_1c"}, {"name": "克林特·伊斯特伍德", "role": "饰：Chief Red Garnett", "image": "https://p1.meituan.net/moviemachine/d1156c14dd899ada7c2b98bc373021c852875.jpg@128w_170h_1e_1c"}, {"name": "T·J·劳瑟", "role": "饰：菲利普·佩里 Phillip ''Buzz'' Perry", "image": "https://p1.meituan.net/movie/0be007da9d9475185a1bc40edffaaa7e45195.jpg@128w_170h_1e_1c"}, {"name": "劳拉·邓恩", "role": "饰：Sally Gerber", "image": "https://p0.meituan.net/moviemachine/a4c68ea6f5fe5f997f1aeacd1ddd5f7d196388.jpg@128w_170h_1e_1c"}, {"name": "布莱德利·惠特福德", "role": "饰：Bobby Lee", "image": "https://p1.meituan.net/moviemachine/f9e81024debc7d163a3cbaac42638591173059.jpg@128w_170h_1e_1c"}, {"name": "布鲁斯·麦克吉尔", "role": "饰：Paul Saunders", "image": "https://p0.meituan.net/movie/745d8d871a6f3fbd4984195f32bbbec741049.jpg@128w_170h_1e_1c"}, {"name": "基斯·斯扎拉巴基克", "role": "饰：Terry Pugh", "image": "https://p1.meituan.net/movie/5c84d50dea8a5f9134c233293a911b1838310.jpg@128w_170h_1e_1c"}, {"name": "里奥·伯梅斯特", "role": "饰：Tom Adler", "image": "https://p0.meituan.net/movie/6