INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (90, 70, 'https://ssr1.scrape.center/detail/70', '放牛班的春天 - Les choristes', '["剧情", "音乐", "美素", "1"]', '法国、德国、瑞士', 97, '2004-10-16', 'https://p0.meituan.net/movie/70de97ebb6b5251ecb7c3f6d7a782a7f189340.jpg@464w_644h_1e_1c,https://p0.meituan.net/movie/396266d8b711958841b3536a3fa7b868211445.jpg@464w_644h_1e_1c', '1949年的法国乡村，音乐家克莱门特（杰勒德·尊诺 饰）到了一间外号叫“塘低”的男子寄宿学校当助理教师。学校里的学生大部分都是难缠的问题儿童，体罚在这里司空见惯，学校的校长（弗朗西斯·贝尔兰德 饰）只顾自己的前途，残暴高压。性格沉静的克莱门特尝试用自己的方法改善这种状况，他重新创作音乐作品，组织合唱团，决定用音乐的方法来打开学生们封闭的心灵。 然而，事情并不顺利，克莱门特发现学生皮埃尔·莫安琦（尚·巴堤·莫里耶 饰）拥有非同一般的音乐天赋，但是单亲家庭长大的他，性格异常敏感孤僻，怎样释放皮埃尔的音乐才能，让克莱门特头痛不已；同时，他与皮埃尔母亲的感情也渐渐微妙起来。', '[{"name": "克里斯托夫·巴拉蒂"}]', '[{"name": "热拉尔·朱尼奥", "role": "饰：克莱门特·马修老师  Clément Mathieu", "image": "https://p1.meituan.net/moviemachine/000efc241cc6265eae46c8685103b75765150.jpg@128w_170h_1e_1c"}, {"name": "让-巴蒂斯特·莫尼耶", "role": "饰：皮埃尔（少年） Pierre Morhange", "image": "https://p0.meituan.net/movie/9d452830af334b6094750fd76dd0d36917933.jpg@128w_170h_1e_1c"}, {"name": "玛丽·布奈尔", "role": "饰：薇奥莱特（皮埃尔的妈妈） Violette Morhange", "image": "https://p1.meituan.net/movie/68c5b3be81f8efe06d7f3763c6756698161647.jpg@128w_170h_1e_1c"}, {"name": "凯德·麦拉德", "role": "饰：查贝特 Chabert", "image": "https://p0.meituan.net/movie/3e49827af88508220ef5ed0235ffc20446380.jpg@128w_170h_1e_1c"}, {"name": "弗朗索瓦·贝莱昂", "role": "饰：拉齐校长 Rachin", "image": "https://p0.meituan.net/moviemachine/5bc47acf0ad253152d7399506a7c114f47721.jpg@128w_170h_1e_1c"}, {"name": "雅克·贝汉", "role": "饰：皮埃尔(成年) Pierre", "image": "https://p0.meituan.net/movie/664d8122c1abaecedff0e63bffa3bc3b48550.jpg@128w_170h_1e_1c"}, {"name": "让-保罗·博奈雷", "role": "饰：La Père Maxence", "image": "https://p1.meituan.net/movie/34ff27b1f061c5fd9cdef5827d757f4334983.jpg@128w_170h_1e_1c"}, {"name": "马科森斯·珀林", "role": "饰：佩皮诺 Pépinot", "imag