INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (2, 2, 'https://ssr1.scrape.center/detail/2', '这个杀手不太冷 - Léon', '["剧情", "动作", "犯罪"]', '法国', 110, '1994-09-14', 'https://p1.meituan.net/movie/6bea9af4524dfbd0b668eaa7e187c3df767253.jpg@464w_644h_1e_1c', '里昂（让·雷诺 饰）是名孤独的职业杀手，受人雇佣。一天，邻居家小姑娘马蒂尔德（纳塔丽·波特曼 饰）敲开他的房门，要求在他那里暂避杀身之祸。原来邻居家的主人是警方缉毒组的眼线，只因贪污了一小包毒品而遭恶警（加里·奥德曼 饰）杀害全家的惩罚。马蒂尔德 得到里昂的留救，幸免于难，并留在里昂那里。里昂教小女孩使枪，她教里昂法文，两人关系日趋亲密，相处融洽。 女孩想着去报仇，反倒被抓，里昂及时赶到，将女孩救回。混杂着哀怨情仇的正邪之战渐次升级，更大的冲突在所难免……', '[{"name": "吕克·贝松", "image": "https://p0.meituan.net/movie/0e7d67e343bd3372a714093e8340028d40496.jpg@128w_170h_1e_1c"}]', '[{"name": "让·雷诺", "role": "饰：莱昂 Leon", "image": "https://p0.meituan.net/movie/9672179e64740c064ba58bc3a80f378251350.jpg@128w_170h_1e_1c"}, {"name": "加里·奥德曼", "role": "饰：流氓警察史丹菲尔 Stansfield", "image": "https://p0.meituan.net/movie/9f1945dbc62b6959cba7e2d44b09fb94108912.jpg@128w_170h_1e_1c"}, {"name": "娜塔莉·波特曼", "role": "饰：马蒂尔德 Mathilda", "image": "https://p0.meituan.net/moviemachine/15dff7480f937b55205148efbdb980ef184873.jpg@128w_170h_1e_1c"}, {"name": "丹尼·爱罗", "role": "饰：黑帮头目托尼 Tony", "image": "https://p1.meituan.net/movie/8998db01fe8ecd2d3bff90d10a05507e50220.jpg@128w_170h_1e_1c"}, {"name": "彼得·阿佩尔", "role": "饰：莫克 Malky", "image": "https://p0.meituan.net/movie/45084057a5cbe6796ad0f549bdb90b1a30165.jpg@128w_170h_1e_1c"}, {"name": "Willi One Blood", "role": "饰：第一个斯坦菲尔德人 1st Stansfield man", "image": "https://p1.meituan.net/movie/33b93029b2ffb80016df89fafa91164a30931.jpg@128w_170h_1e_1c"}, {"name": "唐·克里奇", "role": "饰：第二个斯坦菲尔德人 2nd Stansfield man", "image": "https://p0.meituan.net/movie/873a7f53ee1cd56f7c78fe6e94f58f5532187.jpg@128w_170h_1e_1c"}, {"name": "Keith A. Glascoe", "role": "饰：第三个斯坦菲尔德人 3 rd Stansfield man", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b336