INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (3, 3, 'https://ssr1.scrape.center/detail/3', '肖申克的救赎 - The Shawshank Redemption', '["剧情", "犯罪"]', '美国', 142, '1994-09-10', 'https://p0.meituan.net/movie/283292171619cdfd5b240c8fd093f1eb255670.jpg@464w_644h_1e_1c', '20世纪40年代末，小有成就的青年银行家安迪（蒂姆·罗宾斯 饰）因涉嫌杀害妻子及她的情人而锒铛入狱。在这座名为肖申克的监狱内，希望似乎虚无缥缈，终身监禁的惩罚无疑注定了安迪接下来灰暗绝望的人生。未过多久，安迪尝试接近囚犯中颇有声望的瑞德（摩根·弗里曼 饰），请求对方帮自己搞来小锤子。以此为契机，二人逐渐熟稔，安迪也仿佛在鱼龙混杂、罪恶横生、黑白混淆的牢狱中找到属于自己的求生之道。他利用自身的专业知识，帮助监狱管理层逃税、洗黑钱，同时凭借与瑞德的交往在犯人中间也渐渐受到礼遇。表面看来，他已如瑞德那样对那堵高墙从憎恨转变为处之泰然，但是对自由的渴望仍促使他朝着心中的希望和目标前进。而关于其罪行的真相，似乎更使这一切朝前推进了一步……', '[{"name": "弗兰克·德拉邦特", "image": "https://p1.meituan.net/movie/22421b54442e627a99af816c3595e4a745789.jpg@128w_170h_1e_1c"}]', '[{"name": "蒂姆·罗宾斯", "role": "饰：安迪 Andy Dufresne", "image": "https://p0.meituan.net/movie/c37f3c953107058ab72b2d08b22f167e42111.jpg@128w_170h_1e_1c"}, {"name": "摩根·弗里曼", "role": "饰：瑞德 Ellis Boyd ''Red'' Redding", "image": "https://p1.meituan.net/movie/10f3327ce886885f809c23d0adb67fb049302.jpg@128w_170h_1e_1c"}, {"name": "鲍勃·冈顿", "role": "饰：典狱长诺顿 Warden Samuel Norton", "image": "https://p0.meituan.net/moviemachine/0cd0373955cae450d1a616c96fefcd4449739.jpg@128w_170h_1e_1c"}, {"name": "威廉·桑德勒", "role": "饰：海伍德 Heywood", "image": "https://p0.meituan.net/movie/603afbed507f7a05923c90d80e458bf112645.jpg@128w_170h_1e_1c"}, {"name": "克兰西·布朗", "role": "饰：赫德利 Captain Byron T. Hadley", "image": "https://p1.meituan.net/movie/8d887cbbded2117045da0e417316f24a60543.jpg@128w_170h_1e_1c"}, {"name": "吉尔·贝罗斯", "role": "饰：汤米 Tommy", "image": "https://p0.meituan.net/movie/0c184c78020153a3e4092b2ca4d7e16e52827.jpg@128w_170h_1e_1c"}, {"name": "马克·罗斯顿", "role": "饰：鲍格斯 Bogs Diamond", "image": "https://p1.meituan.net/movie/6c9937278f92f318b0e76e34f3479c1246653.jpg@128w_170h_1e_1c"}, {"name": "詹姆斯·惠特摩", "role": "饰