INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (4, 4, 'https://ssr1.scrape.center/detail/4', '泰坦尼克号 - Titanic', '["剧情", "爱情", "灾难"]', '美国', 194, '1998-04-03', 'https://p1.meituan.net/movie/b607fba7513e7f15eab170aac1e1400d878112.jpg@464w_644h_1e_1c', '1912年4月15日，载着1316号乘客和891名船员的豪华巨轮“泰坦尼克号”与冰山相撞而沉没，这场海难被认为是20世纪人间十大灾难之一。1985年，“泰坦尼克号”的沉船遗骸在北大西洋两英里半的海底被发现。美国探险家洛维特（比尔·帕克斯顿 饰）亲自潜入海底，在船舱的墙壁上看见了一幅画，洛维持的发现立刻引起了一位老妇人（格劳瑞亚·斯图尔特 饰）的注意。已经是101岁高龄的露丝称她就是画中的少女。在潜水舱里，露丝开始叙述当年在船上发生的故事。年轻的贵族少女露丝（凯特·温丝莱特 饰）与穷画家杰克（莱昂纳多·迪卡普里奥 饰）不顾世俗的偏见坠入爱河，然而就在1912年4月14日，一个风平浪静的夜晚，泰坦尼克号撞上了冰山，“永不沉没的”泰坦尼克号面临沉船的命运，罗丝和杰克刚萌芽的爱情也将经历生死的考验，最终不得不永世相隔。老态龙钟的罗丝讲完这段哀恸天地的爱情之后，把那串价值连城的项链“海洋之心”沉入海底，让它陪着杰克和这段爱情长眠海底。', '[{"name": "詹姆斯·卡梅隆", "image": "https://p0.meituan.net/movie/871490cbd3ee1422ed57d7713543283b45250.jpg@128w_170h_1e_1c"}]', '[{"name": "莱昂纳多·迪卡普里奥", "role": "饰：杰克 Jack Dawson", "image": "https://p0.meituan.net/moviemachine/128dd9199573e1114cbbcdfa39fa2442206016.jpg@128w_170h_1e_1c"}, {"name": "凯特·温丝莱特", "role": "饰：露丝 Rose DeWitt Bukater", "image": "https://p0.meituan.net/movie/19532636d4bd4a965ecf3c8ec399936440196.jpg@128w_170h_1e_1c"}, {"name": "比利·赞恩", "role": "饰：卡尔 Caledon ''Cal'' Hockley", "image": "https://p1.meituan.net/movie/6a6ec620f65d2096fd1e4e6a841a10b636473.jpg@128w_170h_1e_1c"}, {"name": "格劳瑞亚·斯图尔特", "role": "饰：老年露丝 Old Rose", "image": "https://p0.meituan.net/movie/bc24925b65f0cc8c0bea3795dc637a8942700.jpg@128w_170h_1e_1c"}, {"name": "凯西·贝茨", "role": "饰：莫莉·布朗 Molly Brown", "image": "https://p0.meituan.net/movie/6ea698d9ddbbfac656f4371483d3e93d36735.jpg@128w_170h_1e_1c"}, {"name": "弗兰西丝·费舍", "role": "饰：Ruth Dewitt Bukater", "image": "https://p0.meituan.net/movie/03e855d5859d1e9e2adee949daa5262458591.jpg@128w_170h_1e_1c"}, {"name": "比尔·帕克斯顿", "role": "饰：Brock Lovett", "image": "https://p0.meituan.net/movie/320f