INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (5, 5, 'https://ssr1.scrape.center/detail/5', '罗马假日 - Roman Holiday', '["剧情", "喜剧", "爱情"]', '美国', 118, '1953-08-20', 'https://p0.meituan.net/movie/289f98ceaa8a0ae737d3dc01cd05ab052213631.jpg@464w_644h_1e_1c', '欧洲某国的安妮公主（奥黛丽·赫本 饰）到访罗马，国务烦身，但她又厌倦繁文缛节。一天晚上，身心俱疲的她偷偷来到民间欣赏夜景，巧遇报社记者乔（格利高里·派克 饰）。二人把手同游，相当快乐。公主更是到乔的家中作客并在那过夜。不料乔无意中发现了公主的真实身份，他决定炮制一个独家新闻，于是乔和朋友、摄影师欧文（埃迪·艾伯特 饰）一起带公主同游罗马，并且偷拍了公主的很多生活照。然而，在接下来与公主的相处中，乔不知不觉恋上了公主。为了保护公主的形象，乔只能忍痛抛弃功成名就的良机，将照片送予了公主。安妮公主在经历了罗马一日假期后，反而体验了自己对国家的责任，毅然返回了大使馆，为了本身的责任而果断抛弃了爱情。', '[{"name": "威廉·惠勒", "image": "https://p1.meituan.net/movie/169af816a0d3f32581d5610b93b6f3467739.jpg@128w_170h_1e_1c"}]', '[{"name": "格利高里·派克", "role": "饰：乔 Joe Bradley", "image": "https://p1.meituan.net/movie/c6abe56ebc74f6d9fe29498a023efb8a91556.jpg@128w_170h_1e_1c"}, {"name": "奥黛丽·赫本", "role": "饰：安妮公主 Princess Ann", "image": "https://p1.meituan.net/movie/97bcea4bf8001374393d86394fe2390e30462.jpg@128w_170h_1e_1c"}, {"name": "埃迪·艾伯特", "role": "饰：欧文 Irving Radovich", "image": "https://p1.meituan.net/movie/3f8c2d73e626c41390ae6bcf8599eaf726703.jpg@128w_170h_1e_1c"}, {"name": "哈特利·鲍尔", "role": "饰：轩尼斯先生 Mr. Hennessy", "image": "https://p1.meituan.net/movie/d44b90db74ee8081063737f9df113c0b24906.jpg@128w_170h_1e_1c"}, {"name": "哈考特·威廉姆斯", "role": "饰：Ambassador", "image": "https://p0.meituan.net/movie/25417a3e0e250de2692b6d3aff41539a46521.jpg@128w_170h_1e_1c"}, {"name": "玛格丽特·罗林斯", "role": "饰：Countess Vereberg", "image": "https://p0.meituan.net/movie/cd7e6f286ba8ce4e1237e93197eadab510455.jpg@128w_170h_1e_1c"}, {"name": "托里奥·卡米纳提", "role": "饰：普鲁弗诺将军 General Provno", "image": "https://p0.meituan.net/movie/3ee6509cc2649b3165b506ad4641e72134009.jpg@128w_170h_1e_1c"}, {"name": "Paolo Carlini", "role": "饰：Mario Delani", "image": "https://p0.meituan.net/movie/f9f876c184787cda40f30a9caec9034935987.jpg@128w_170h_1e_1c"}, {"name": "Claudio Ermelli", "role": "饰：Giovanni", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "保拉·布鲁布尼", "role": "饰：Charwoman", "image": "https://p1.meituan.net/movie/9472842e78ec272ed683712fc327977819869.jpg@128w_170h_1e_1c"}, {"name": "里佐·弗雷多里佐", "role": "饰：出租车司机 Taxicab Driver", "image": "https://p0.meituan.net/movie/eef49d854b94d1fba859300de05024ca8429.jpg@128w_170h_1e_1c"}, {"name": "Laura Solari", "role": "饰：Hennessy''s Secretary", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Gorella Gori", "role": "饰：Shoe Seller", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Armando Ambrogi", "role": "饰：Man on Phone (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Armando Annuale", "role": "饰：与公主跳舞的海军上将 Admiral Dancing with Princess (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "毛里齐奥·阿雷纳", "role": "饰：Young Boy with Car (uncredited)", "image": "https://p0.meituan.net/movie/543fb892e6b77f8f6f2526b0be0d9690130341.jpg@128w_170h_1e_1c"}, {"name": "Silvio Bagolini", "role": "饰：Undetermined Role (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "乌戈·巴莱里尼", "role": "饰：Embassy Aide (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Bruno Baschiera", "role": "饰：Embassy Aide (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Gildo Bocci", "role": "饰：Flower Seller (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1