INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (6, 6, 'https://ssr1.scrape.center/detail/6', '唐伯虎点秋香 - Flirting Scholar', '["喜剧", "爱情", "古装"]', '中国香港', 102, '1993-07-01', 'https://p0.meituan.net/movie/da64660f82b98cdc1b8a3804e69609e041108.jpg@464w_644h_1e_1c', '唐伯虎（周星驰 饰）身为江南四大才子之首，却有道不尽的心酸。宁王想让唐伯虎帮其图谋作反，被唐伯虎拒绝意淫结仇。唐伯虎在与朋友出游时，遇到了貌若天仙的秋香（巩俐 饰）并对她一见钟情，决心要到华府当家丁以追求秋香，唐伯虎被取名华安。期间华太师遇到了宁王上门刁难，幸好有唐伯虎出面相助，并暴露了自己是唐伯虎的身份。秋香才知道华安是自己欣赏的唐伯虎。华夫人跟唐家有怨，因此二人便开始斗法。怎料宁王跟夺命书生再次上门，华夫人不是对手，幸得唐伯虎出手，华夫人也答应把秋香许配给唐伯虎。', '[{"name": "李力持", "image": "https://p1.meituan.net/movie/7c6f180a06f744aee95ab3b8bef29c2633555.jpg@128w_170h_1e_1c"}]', '[{"name": "周星驰", "role": "饰：唐伯虎,华安", "image": "https://p0.meituan.net/movie/5cbe849bb17c8966a423ee015dc21aca41689.jpg@128w_170h_1e_1c"}, {"name": "巩俐", "role": "饰：秋香", "image": "https://p1.meituan.net/moviemachine/b650dcb00c40356934a275515217850f191104.jpg@128w_170h_1e_1c"}, {"name": "郑佩佩", "role": "饰：华夫人", "image": "https://p0.meituan.net/moviemachine/72c8a32b30315b77feb1dffeec46782a149548.jpg@128w_170h_1e_1c"}, {"name": "苑琼丹", "role": "饰：石榴", "image": "https://p0.meituan.net/movie/49c2b8bf9d992980b8b36540092680e942473.jpg@128w_170h_1e_1c"}, {"name": "陈百祥", "role": "饰：祝枝山", "image": "https://p0.meituan.net/movie/809e8f9f820919272a9c5bf4700e7e6e49709.jpg@128w_170h_1e_1c"}, {"name": "朱咪咪", "role": "饰：朱茜", "image": "https://p1.meituan.net/movie/646d2a3a807069cdb3484c2d9435376339769.jpg@128w_170h_1e_1c"}, {"name": "黄霑", "role": "饰：华太师", "image": "https://p1.meituan.net/movie/48f60e5fbd50ad3a33c4dec65873486d30859.jpg@128w_170h_1e_1c"}, {"name": "梁家仁", "role": "饰：武状元", "image": "https://p0.meituan.net/movie/92a83afe9acca8189dcff045ce0204a842532.jpg@128w_170h_1e_1c"}, {"name": "刘家辉", "role": "饰：夺命书生", "image": "https://p1.meituan.net/movie/a3f1b572fd3977862bda935f9ae380bd31933