INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (51, 51, 'https://ssr1.scrape.center/detail/51', '哈利·波特与死亡圣器（下） - Harry Potter and the Deathly Hallows: Part 2', '["剧情", "悬疑", "奇幻", "冒险"]', '英国、美国', 130, '2011-08-04', 'https://p1.meituan.net/movie/bb0eca029cd25329776a4549b3fbe262924727.jpg@464w_644h_1e_1c', '哈利进入与 伏地魔意识连通的幻境，找到了一些魂器，但也让伏地魔发觉了他们的行动。哈利又一次进入幻境后推断出伏地魔的居所，三人来到了此地。他们看到伏地魔命令毒蛇除掉斯内普，以把长者杖魔力传给自己。弥留之际，斯内普把记忆送给哈利，原来他一直爱着哈利的母亲莉莉，因此从来都是站在邓布利多一边。哈利披上隐身斗篷去与伏地魔战斗，发现海格被押作人质。哈利一现出身来就被一咒击倒，醒来时彷佛进入一个生与死的边缘，碰到已死的邓布利多。哈利发觉咒语正巧击溃了藏在自己体内的那一部分伏地魔的灵魂。伏地魔命令海格把貌似死了的哈利带回 霍格沃茨，杀杀士气。哈利趁乱披上隐身斗篷，纳威敏捷地抽出格兰芬多剑砍掉了毒蛇纳吉尼的脑袋，藏在毒蛇体内的伏地魔最后一个魂器就这样被毁掉。哈利在大殿里面直面伏地魔，长老杖在伏地魔手中。哈利猜测长 老杖原来的主人不是斯内普而是马尔福，解除邓布利多武装的是马尔福，而斯内普只是依照邓布利多的愿望把他杀掉。然而解除掉马尔福武力的人却是哈利，所以长老杖真正的力量在哈利这里。所以伏地魔用长老杖对哈利施死咒时，哈利让死咒又反弹到伏地魔身上，伏地魔就这样被结果了。19年后，哈利和金妮有了三个孩子，罗恩和赫敏也有两个孩子。两家人在 国王十字车站送孩子去霍格沃茨学校，在这里他们遇见了不少故人。最终哈利摸着前额上的闪电形疤痕，19年了这块疤痕再也没有痛过。一切都好  。', '[{"name": "大卫·叶茨", "image": "https://p0.meituan.net/movie/bcd12b014ad77eac7f03535284c891f736220.jpg@128w_170h_1e_1c"}]', '[{"name": "丹尼尔·雷德克里夫", "role": "饰：哈利·波特 Harry Potter", "image": "https://p1.meituan.net/movie/07a6401d0b027542671378b1a5d5d3cd10990.jpg@128w_170h_1e_1c"}, {"name": "鲁伯特·格林特", "role": "饰：罗恩·韦斯莱 Ron Weasley", "image": "https://p1.meituan.net/movie/cf6868240cca011a779b7eb1660bea6c33254.jpg@128w_170h_1e_1c"}, {"name": "艾玛·沃特森", "role": "饰：赫敏·格兰杰 Hermione Granger", "image": "https://p1.meituan.net/movie/f338c84b6cbd14d0911cdcab96dd59fe216365.jpg@128w_170h_1e_1c"}, {"name": "拉尔夫·费因斯", "role": "饰：伏地魔 Lord Voldemort", "image": "https://p1.meituan.net/moviemachine/f6fe1b9d07f71485b8081e94be4152c254581.jpg@128w_170h_1e_1c"}, {"name": "艾伦·瑞克曼", "role": "饰：西弗勒斯·斯内普教授 Professor Severus Snape", "image": "https://p0.meituan.net/movie/5b0108d9dd8a4ccc652e112979c4247f7216.jpg@128w_170h_1e_1c"}, {"name": "马修·刘易斯", "role": "饰：纳威·隆巴顿 Neville Longbottom", "image": "https://p0.meituan.net/movie/7965b8962e79653cc81727079337578f35266.jpg@128w_170h_1e_1c"}, {"name": "汤姆·费尔顿", "role": "饰：德拉科·马尔福 Draco Malfoy", "image": "https://p1.meituan.net/movie/cac9fe795ba0ad523bcf3d03a64786c7229057.jpg@128w_170h_1e_1c"}, {"name": "迈克尔·刚本", "role": "饰：阿不思·邓不利多 Professor Albus Dumbledore", "image": "https://p1.meituan.net/movie/6a3db9ec1a0e0a3974bec8d12b2aa1cb36140.jpg@128w_170h_1e_1c"}, {"name": "伊文娜·林奇", "role": "饰：卢娜·洛夫古德 Luna Lovegood", "image": "https://p0.meituan.net/movie/8f16e705a6e00ed884c93dccae817fd940108.jpg@128w_170h_1e_1c"}, {"name": "沃维克·戴维斯", "role": "饰：拉环 Griphook,Professor Filius Flitwick", "image": "https://p0.meituan.net/movie/d9d9aa8b5afa7fff3114af0aaa07599444652.jpg@128w_170h_1e_1c"}, {"name": "詹森·艾萨克", "role": "饰：卢修斯·马尔福 Lucius Malfoy", "image": "https://p0.meituan.net/moviemachine/7bc9797c520d230b95c7629071fe273232920.jpg@128w_170h_1e_1c"}, {"name": "海伦娜·伯翰·卡特", "role": "饰：贝拉特里克斯·莱斯特兰奇Bellatrix Lestrange", "image": "https://p1.meituan.net/movie/be5089e588048e9cb17d2502584df9d563067.jpg@128w_170h_1e_1c"}, {"name": "玛吉·史密斯", "role": "饰：米勒娃教授 Professor Minerva McGonagall", "image": "https://p0.meituan.net/movie/7b7c775bb82a4dcc051e19963a1e27bf209035.jpg@128w_170h_1e_1c"}, {"name": "邦妮·怀特", "role": "饰：金妮·韦斯莱 Ginny Weasley", "image": "https://p0.meituan.net/movie/3b272ed8a312afc7feb2693eeb585a3835352.jpg@128w_170h_1e_1c"}, {"name": "大卫·休里斯", "role": "饰：莱姆斯·卢平 Remus Lupin", "image": "https://p0.meituan.net/movie/3370dae9842b17a809b9ed7628b1193e47146.jpg@128w_170h_1e_1c"}, {"name": "塞伦·希德", "role": "饰：阿不福思·邓布利多 Aberforth Dumbledore", "image": "https://p1.meituan.net/movie/42699bc558626da7a1f3a6aafb28f06b55677.jpg@128w_170h_1e_1c"}, {"name": "朱丽·沃特斯", "role": "饰：莫莉·韦斯莱 Molly Weasley", "image": "https://p1.meituan.net/movie/bfda4fb299cf2542551530a7bf3d2c5b53004.jpg@128w_170h_1e_1c"}, {"name": "乔治·哈里斯", "role": "饰：金斯利·沙克尔 Kingsley Shacklebolt", "image": "https://p0.meit