INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (22, 22, 'https://ssr1.scrape.center/detail/22', '海洋 - Océans', '["纪录片"]', '法国、瑞士、西班牙、美国、阿联酋', 104, '2011-08-12', 'https://p1.meituan.net/movie/a19a7f64a10e133b68de87d2f3bc46f3111417.jpg@464w_644h_1e_1c', '影片讲述了热爱动物又充满幻想的十岁男孩方小奇，由于父母常年在外工作，所以只能在爷爷工作的“极地海洋世界”里度过自己的童年。值得庆幸的是，“海洋世界”里千姿百态的各种海洋动物，让小奇的生活充满了欢乐和幸福。    一天晚上，远在北极的爸爸给小奇来的一封信又使他失望了,信中说我们的科考工作还没完成，因此不能回来给你过生日了。小奇非常难过，便拿着爸爸的信独自来到海豚池边偷偷哭泣。就在这个时候，奇迹发生了！那只平时就跟小奇很要好的小海豚琪琪，突然开口和他‘说话’了！它告诉小奇，它也很难过，天天思念自己的爸爸。两颗心，因为同一种情感被紧紧地联系在一起。    小奇从饲养员那里得知，琪琪是被人类从大海里救回来的。当年它爸爸为了保护它，在和鲨鱼拼搏中受了重伤，现在还不知是生还是死。琪琪的悲惨经历，让小奇决心帮助琪琪找到它的爸爸。    就在小奇和同学们努力准备的时候，琪琪却突然病了。望着不吃不喝的“好朋友”，小奇流下了眼泪。他知道，琪琪的病是因为它见不到爸爸而造成的！情急之下，小奇和维维、洋洋等好朋友把琪琪从“海洋世界”偷运出去，可就在他们的行动将要成功的时候，却被饲养员发现了。小奇不仅被平日里非常疼爱他的爷爷怒斥，还被禁止再来海豚池看琪琪！小奇又气又急，终于也发起了高烧。    小奇怎么也不知道，他和琪琪之间的友谊，他为“海洋朋友”所做的一切努力，同样也打动了一些人的心，他们正在为琪琪重归大海，重见爸爸而暗暗努力着。一段关于人与动物、亲情与友谊、爱与理解的美丽故事，正在那个如梦如幻的海洋世界里上演着……', '[{"name": "雅克·贝汉", "image": "https://p0.meituan.net/movie/664d8122c1abaecedff0e63bffa3bc3b48550.jpg@128w_170h_1e_1c"}, {"name": "雅克·克鲁奥德", "image": "https://p1.meituan.net/movie/e0556f9699c4e3368de997819b529ea039850.jpg@128w_170h_1e_1c"}]', '[{"name": "雅克·贝汉", "role": "饰：法语旁白 Narrator (French version)", "image": "https://p0.meituan.net/movie/664d8122c1abaecedff0e63bffa3bc3b48550.jpg@128w_170h_1e_1c"}, {"name": "姜文", "role": "饰：中文旁白 Narrator (Chinese version)", "image": "https://p1.meituan.net/movie/65405524c6f19d3c04a11cfc639a285238873.jpg@128w_170h_1e_1c"}, {"name": "兰斯洛特·佩林", "role": "饰：本人", "image": "https://p0.meituan.net/movie/473e387474b789c5cf012153ad219a7629876.jpg@128w_170h_1e_1c"}, {"name": "宫泽理惠", "role": "饰：日文旁白 Narrator (Japanese  version)", "image": "https://p1.meituan.net/movie/ac67eeeddaa75e006674e0676c08f91a35326.jpg@128w_170h_1e_1c"}, {"name": "皮尔斯·布鲁斯南", "role": "饰：英文旁白 Narrator (English version)", "image": "https://p0.meituan.net/movie/182d28b9229f41868979765f456ff4af160829.jpg@128w_170h_1e_1c"}, {"name": "阿尔多", "role": "饰：意大利文旁白 Narrator (Italian version)", "image": "https://p0.meituan.net/movie/e0ae438f4154fa59362f3f8573eb114939331.jpg@128w_170h_1e_1c"}, {"name": "小佩德罗·阿门达里斯", "role": "饰：Narrator (Spanish version)", "image": "https://p0.meituan.net/movie/d2f2b8fb3932400e3539d7fcea14a8c4119698.jpg@128w_170h_1e_1c"}, {"name": "马蒂亚斯·勃兰特", "role": "饰：Narrator (German version)", "image": "https://p0.meituan.net/movie/f39a93551f67b300131ad850a953d17d17703.jpg@128w_170h_1e_1c"}, {"name": "Manolo Garcia", "role": "饰：Narrator", "image": "https://p0.meituan.net/movie/e265ba4430f58d38f8faab6f6f281dab41420.jpg@128w_170h_1e_1c"}]', 9.1, '2026-04-24 03:07:06.443382', '2026-04-24 03:07:06.443382', '["https://p0.meituan.net/movie/331414dbd00c422d3ed93b8115fd7db624624.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/9c57d354d01249bce4790021b1fc85fb168187.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/f49e6c9fa62293506ba719510e9396f822210.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/1904c0d65e62dda4c4adddca32903b28126140.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/6810558527c2779a88cd6cfeb60d3e4b86206.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/f92c1aa13f291341bd2c7f1ba051d79d46818.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/9d630ac559884a246b22f14282b1855f41530.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/929b05228354040948e02435e7ea8cab55740.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/a7c7ba6dadbae0f304786ab23821304245629.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/c4a284fe1967b733ed828effcad8f39a34252.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/e0e05c290f158f0e802971c70652823d47655.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/ec582ee5f4691653fbbbdf12eb524039208104.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/ae689d63839f8206d9e2c22fae25566134410.jpg@106w_10