INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (7, 7, 'https://ssr1.scrape.center/detail/7', '乱世佳人 - Gone with the Wind', '["剧情", "爱情", "历史", "战争"]', '美国', 238, '1939-12-15', 'https://p0.meituan.net/movie/223c3e186db3ab4ea3bb14508c709400427933.jpg@464w_644h_1e_1c', '美国南北战争前夕，南方农场塔拉庄园的千金斯嘉丽（费·雯丽 饰）爱上了另一个农场主的儿子艾希礼（李斯利·霍华德 饰），遭到了拒绝，为了报复，她嫁给了自己不爱的男人，艾希礼妻子梅兰（奥莉薇·黛·哈佛兰 饰）的弟弟查尔斯。战争期间，斯嘉丽成为寡妇，失去母亲，挑起生活的重担，不再是当初的千金小姐；战争结束后，她又两度为人妻，嫁给了爱她多年的投机商人瑞德（克拉克·盖博 饰）。然而，纵使经历了生活的艰苦，斯嘉丽对艾希礼的感情仍然没有改变。艾希礼妻子梅兰的去世，给了斯嘉丽一个机会，一边是深爱自己的丈夫瑞德，一边是心心念念多年的艾希礼？斯嘉丽会给自己怎样一个不一样的明天？', '[{"name": "山姆·伍德", "image": "https://p0.meituan.net/movie/a82947e77d1de0cb24b7a7b42d7648a915217.jpg@128w_170h_1e_1c"}, {"name": "维克多·弗莱明", "image": "https://p0.meituan.net/movie/88e0e07ff57a12adc431d5ec5316e7ef27275.jpg@128w_170h_1e_1c"}]', '[{"name": "费雯·丽", "role": "饰：斯嘉丽 Scarlett OHara", "image": "https://p0.meituan.net/movie/9284ced1e9d2079d73b7867613462e7d27022.jpg@128w_170h_1e_1c"}, {"name": "克拉克·盖博", "role": "饰：瑞德 Rhett Butle", "image": "https://p1.meituan.net/movie/2981a65e0cd41de65110ad5d53ba278434589.jpg@128w_170h_1e_1c"}, {"name": "奥利维娅·德哈维兰", "role": "饰：梅兰妮 Melanie Hamilton (as Olivia deHavilland)", "image": "https://p1.meituan.net/movie/0f101450920d2d13d30f125d6d5f25f18475.jpg@128w_170h_1e_1c"}, {"name": "莱斯利·霍华德", "role": "饰：艾希礼  Ashley Wilkes", "image": "https://p0.meituan.net/movie/b9447b0eb28f71e025fcfde569a092e610276.jpg@128w_170h_1e_1c"}, {"name": "海蒂·麦克丹尼尔斯", "role": "饰：Mammy", "image": "https://p1.meituan.net/movie/5d66e3c6a4862cb259b3c2bcbb3296d928508.jpg@128w_170h_1e_1c"}, {"name": "埃迪·安德森", "role": "饰：Uncle Peter (as Eddie Anderson)", "image": "https://p0.meituan.net/movie/4b75565dfc8d022eac0c9f59f563653f33806.jpg@128w_170h_1e_1c"}, {"name": "托马斯.米切尔", "role": "饰：Gerald OHara", "image": "https://p1.meituan.net/movie/9804aa6a681460ec3613b936919615a428080.jpg@128w_170h_1e_1c"}, {"name": "芭芭拉·欧内尔", "role": "饰：Ellen OHara (as Barbara ONeill)", "image": "https://p1.meituan.net/movie/520dac546932a5f11ed6714c1f52903178095.jpg@128w_170h_1e_1c"}, {"name": "伊夫林·凯耶斯", "role": "饰：Suellen OHara", "image": "https://p0.meituan.net/movie/50accaa421250758fda671e80092709330671.jpg@128w_170h_1e_1c"}, {"name": "乔治·里弗斯", "role": "饰：Stuart Tarleton", "image": "https://p0.meituan.net/movie/473a11b32f9a1c44414c7e6cb543a93725378.jpg@128w_170h_1e_1c"}, {"name": "巴特弗莱·麦昆", "role": "饰：Prissy", "image": "https://p1.meituan.net/movie/cada64ffd01dda0e9ac82ddaf8676f1721632.jpg@128w_170h_1e_1c"}, {"name": "维克托·乔里", "role": "饰：Jonas Wilkerson (the overseer)", "image": "https://p1.meituan.net/movie/2e99ef53390b8ff71509d9e5e158664024250.jpg@128w_170h_1e_1c"}, {"name": "埃弗雷特·布朗", "role": "饰：Big Sam", "image": "https://p1.meituan.net/movie/8944e6cb5d5946d51a1008822520ee8d6986.jpg@128w_170h_1e_1c"}, {"name": "霍华德·C·希克曼", "role": "饰：John Wilkes (as Howard Hickman)", "image": "https://p0.meituan.net/movie/ae8f1d4cf294a9e32fdb5a384e45376a7991.jpg@128w_170h_1e_1c"}, {"name": "兰德·布鲁克斯", "role": "饰：Charles Hamilton", "image": "https://p0.meituan.net/movie/f4c13c4bad923e698cdda4448ab3766a8983.jpg@128w_170h_1e_1c"}, {"name": "劳拉·霍普·克鲁斯", "role": "饰：\"Aunt \"\"Pittypat\"\" Hamilton\"", "image": "https://p0.meituan.net/movie/c868b5872f3e8ca61ebae15b1497daa510489.jpg@128w_170h_1e_1c"}, {"name": "哈里·达文波特", "role": "饰：Dr. Meade", "image": "https://p1.meituan.net/movie/8910b366440b783ef8d2402dbefea18934956.jpg@128w_170h_1e_1c"}, {"name": "利昂娜·罗伯特", "role": "饰：Mrs. Meade", "image": "https://p0.meituan.net/movie/6fa20bba890c49bea7463a5fcc15626439899.jpg@128w_170h_1e_1c"}, {"name": "简·达威尔", "role": "饰：Mrs. Dolly Merriwether", "image": "https://p0.meituan.net/movie/572180a1db00b620fa27e43dcb26f50727916.jpg@128w_170h_1e_1c"}, {"name": "保罗·赫斯特", "role": "饰：Yankee deserter", "image": "https://p0.meituan.net/movie/c1e1d31f362788ce35ccd9