INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (11, 8, 'https://ssr1.scrape.center/detail/8', '喜剧之王 - The King of Comedy', '["剧情", "喜剧", "爱情"]', '中国香港', 85, '1999-02-13', 'https://p0.meituan.net/movie/1f0d671f6a37f9d7b015e4682b8b113e174332.jpg@464w_644h_1e_1c', '尹天仇（周星驰 饰）一直醉心戏剧，想成为一名演员，平时除了做跑龙套以外，还会在街坊福利会里开设演员训练班。此时舞小姐柳飘飘在妈妈桑的带领下来到这里要求学做戏，原来柳飘飘有一段非常不愉快的经历，在尹天仇对她指导的过程中，柳飘飘对尹天仇渐生情愫，同时她也成为了夜总会里当红的小姐。尹天仇受到了极多白眼之后，终于得到了大明星鹃姐（莫文蔚 饰）的赏识，提携他担演新戏中的男主角，但没想到突然把他的角色换掉了，令他失望不已。在片场当场务的卧底警员（吴孟达 饰）身份被识穿，尹天仇阴差阳错的帮忙破了案。之后尹天仇继续活跃在街坊福利会的演员训练班里。', '[{"name": "李力持", "image": "https://p1.meituan.net/movie/7c6f180a06f744aee95ab3b8bef29c2633555.jpg@128w_170h_1e_1c"}, {"name": "周星驰", "image": "https://p0.meituan.net/movie/5cbe849bb17c8966a423ee015dc21aca41689.jpg@128w_170h_1e_1c"}]', '[{"name": "周星驰", "role": "饰：尹天仇", "image": "https://p0.meituan.net/movie/5cbe849bb17c8966a423ee015dc21aca41689.jpg@128w_170h_1e_1c"}, {"name": "莫文蔚", "role": "饰：杜娟儿", "image": "https://p1.meituan.net/movie/7a8ec6da5a8612a25519550806545b2e52391.jpg@128w_170h_1e_1c"}, {"name": "张柏芝", "role": "饰：柳飘飘", "image": "https://p0.meituan.net/movie/78b9197bc6f01d71ecb0a72d608e2b6239082.jpg@128w_170h_1e_1c"}, {"name": "郑文辉", "role": "饰：洪爷手下甜筒儿", "image": "https://p0.meituan.net/movie/efd82c0581ef90ffbbaa590db12129a810369.jpg@128w_170h_1e_1c"}, {"name": "林子善", "role": "饰：洪爷", "image": "https://p1.meituan.net/movie/982ed0347b9372855b820c945abff17541928.jpg@128w_170h_1e_1c"}, {"name": "田启文", "role": "饰：洪爷手下", "image": "https://p0.meituan.net/movie/f881fd5848eb7034beeb5c66569bf30d33095.jpg@128w_170h_1e_1c"}, {"name": "吴孟达", "role": "饰：卧底", "image": "https://p1.meituan.net/movie/13d4357722d33b46a9fa52fbe8316f9633831.jpg@128w_170h_1e_1c"}, {"name": "成龙", "role": "饰：替身演员", "image": "https://p1.meituan.net/movie/6f2e5018478106af726afcc7d29c86ab4