INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (15, 10, 'https://ssr1.scrape.center/detail/10', '狮子王 - The Lion King', '["动画", "歌舞", "冒险"]', '美国', 89, '1995-07-15', 'https://p0.meituan.net/movie/27b76fe6cf3903f3d74963f70786001e1438406.jpg@464w_644h_1e_1c', '辛巴是荣耀国的小王子，他的父亲木法沙是一个威严的国王。然而叔叔刀疤却对木法沙的王位觊觎已久。要想坐上王位宝座，刀疤必须除去小王子，于是，刀疤利用种种借口让辛巴外出，然后伺机让鬣狗军团大开杀戒，无奈被木法沙及时来救。后来，在反复的算计下，木法沙惨死在刀疤手下；事后，刀疤别有用心的劝辛巴离开，一方面派鬣狗将他赶尽杀绝，但辛巴却逃出生天。辛巴逃亡中遇到了机智的丁满和善良的彭彭，他们见证了辛巴长成雄壮的大狮子。不久，辛巴意外遇上了少年时的玩伴娜娜，娜娜告知辛巴荣耀国遭遇灾难并鼓励他回去复国，但辛巴却不愿意。后来在法师拉飞奇的引导下，辛巴和父亲的英灵会面并下决心复国。在接下来一场复国救民的斗争中，辛巴领会了责任的真谛，并在朋友和亲人的帮助下获得胜利  。', '[{"name": "罗杰·阿勒斯", "image": "https://p0.meituan.net/movie/ae138a68b64ae733104e6488e4f16ac051904.jpg@128w_170h_1e_1c"}, {"name": "罗伯·明可夫", "image": "https://p1.meituan.net/movie/e064bd1c9d460646489c360d4f7e15e842303.jpg@128w_170h_1e_1c"}]', '[{"name": "马修·布罗德里克", "role": "饰：辛巴（配音） Adult Simba (voice)", "image": "https://p0.meituan.net/moviemachine/39c00b6dfcb83a16526f80be92f666f439076.jpg@128w_170h_1e_1c"}, {"name": "尼基塔·卡兰姆", "role": "饰：青年娜拉（配音） Young Nala (voice)", "image": "https://p1.meituan.net/movie/9569a12aae920b4265acfbf66309817933752.jpg@128w_170h_1e_1c"}, {"name": "詹姆斯·厄尔·琼斯", "role": "饰：木法沙（配音） Mufasa (voice)", "image": "https://p1.meituan.net/movie/d33e08b61c0afafa70efd50b0e39cde353444.jpg@128w_170h_1e_1c"}, {"name": "杰瑞米·艾恩斯", "role": "饰：刀疤（配音） Scar (voice)", "image": "https://p0.meituan.net/moviemachine/0ebceeac80660c5bfdb34e3c4480b812174075.jpg@128w_170h_1e_1c"}, {"name": "吉姆·卡明斯", "role": "饰：艾德（配音） Ed (voice)", "image": "https://p1.meituan.net/movie/b76f5ce38fea475e0b08f90f6add863853784.jpg@128w_170h_1e_1c"}, {"name": "内森·连恩", "role": "饰：蒂莫（配音） Timon (voice)", "image": "https://p1.meituan.net/movie/7e05f80a3f9cead88b8d1955aae1217c32811.jpg@128w_170h_1e_1c"}, {"name": "厄尼·萨贝拉", "role": "饰：