INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (41, 30, 'https://ssr1.scrape.center/detail/30', '上帝之城 - Cidade de Deus', '["剧情", "犯罪"]', '巴西、法国', 130, NULL, 'https://p1.meituan.net/movie/b553d13f30100db731ab6cf45668e52d94703.jpg@464w_644h_1e_1c', '巴西里约热内卢的贫民窟，这里是“上帝之城”，更是魔鬼也会叹息着转身的地方。阿炮（亚历山大·罗德里格斯 饰）带着我们到了这里，他见证了这里二十多年来被残暴、贪婪、复仇、野心、背叛、掠夺所裹挟的混乱生活以及最终导致的一场灾难性的黑帮争斗。虽然从小就要辗转于匪徒间求生存，但胆小怕事的性格与自我保护的本能却使他一直能平安度日。60年代初，阿毛、阿夹和阿呆是这里的“少年三侠”，在抢劫完旅馆之后，他们三人分道扬镳，阿夹重回上帝的怀抱，而阿呆和阿毛纷纷付出了生命的代价。70年，当年“少年三侠”手下的小弟小豆子（道格拉斯·席尔瓦 饰）靠着自己的心狠手辣，不停地吞并别人的地盘，成为了贫民区的“小霸王”，生意也从抢劫升级到了更为暴利的毒品买卖，和他一起飞黄腾达的还有班尼（Phellipe·哈根森 饰）。班尼认识了美丽的安迪丽卡（艾莉丝·布拉加 饰），准备归隐，在送别的晚会上，他意外被对头杀害，悲痛之下，“小霸王”集合人手给班尼报仇，帮派之间的厮杀就此开始。此时的阿炮，机缘巧合下成为了杂志社的见习摄影师，他的相机，照下的却是孩子们持枪核弹的狰狞，和帮派间无休无止的仇杀。', '[{"name": "卡迪亚·兰德", "image": "https://p1.meituan.net/movie/df673f3f340d34be7dc4ffe0b9a8a18c58819.jpg@128w_170h_1e_1c"}, {"name": "费尔南多·梅里尔斯", "image": "https://p0.meituan.net/movie/7c3553aa4fd624bf82afc92d63cb12f147393.jpg@128w_170h_1e_1c"}]', '[{"name": "亚历桑德雷·罗德里格斯", "role": "饰：Buscapé - Rocket", "image": "https://p0.meituan.net/movie/ffed6387f835c797a9e9984b169bb98847780.jpg@128w_170h_1e_1c"}, {"name": "艾莉丝·布拉加", "role": "饰：安吉里卡 Angélica", "image": "https://p1.meituan.net/movie/d0c37be07f28cf2fddb930f1b589620943430.jpg@128w_170h_1e_1c"}, {"name": "莱安德鲁·菲尔米诺", "role": "饰：Zé Pequeno - Li''l Zé", "image": "https://p1.meituan.net/movie/d8f6e5287ba735e6f586ce5fa811708b48136.jpg@128w_170h_1e_1c"}, {"name": "索·豪黑", "role": "饰：玛尼·加里汉 Mané Galinha - Knockout Ned", "image": "https://p0.meituan.net/movie/17e30d99b6a4fb6127a9fb5de553b01c55035.jpg@128w_170h_1e_1c"}, {"name": "道格拉斯·席尔瓦", "role": "饰：Dadinho - Li''l Dice", "image": "https://p0.meituan.net/movie/450a4f51e42c1620089882643860a17336465.jpg@128w_170h_1e_1c"}, {"name": "乔纳森·哈根森", "role": "饰：Cabeleira - Shaggy", "i