INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (42, 31, 'https://ssr1.scrape.center/detail/31', '辩护人 - 변호인', '["剧情"]', '韩国', 127, '2013-12-18', 'https://p0.meituan.net/movie/1433d81b10d116239dbbf02a06ac3c19265682.jpg@464w_644h_1e_1c', '1978年，只有高中学历的宋佑硕（宋康昊 饰）通过多年的艰苦努力，终于通过司法考试，并在成为法官后很快转行成为一名律师。他敏锐地从最新政策中嗅到商机，以不动产代书业务起家。虽然被同行讥讽为随时随地派发名片的夜店小弟，但佑硕不以为忤，一步一步朝着心中的目标迈进。他依靠赚来的钱让妻儿过上富足的生活，也还了七年前在饭店大婶那里欠下的良心债。进入20世纪80年代，韩国民主化斗争愈演愈烈。佑硕全然不管窗外事，关起门来继续赚钱。然而社会的巨变已经不容他置身事外，饭店大婶的儿子朴镇宇因从属的釜山读书联合会被控为左翼社团而遭到逮捕，更受到残酷的虐待和不公的指控。虽然爱钱却更重感情的佑硕，就这样走上了为民主辩护的道路……', '[{"name": "杨宇硕", "image": "https://p0.meituan.net/movie/460c2f3cdc728b256d8815c7f2249d8042131.jpg@128w_170h_1e_1c"}]', '[{"name": "宋永彰", "role": "饰：Judge", "image": "https://p1.meituan.net/movie/42478840d0e118c02f476377163e66ae33718.jpg@128w_170h_1e_1c"}, {"name": "吴达洙", "role": "饰：朴东虎", "image": "https://p0.meituan.net/movie/a3937ce2e6ae57232ff62255dd14728044053.jpg@128w_170h_1e_1c"}, {"name": "郭度沅", "role": "饰：郭秉奎", "image": "https://p0.meituan.net/movie/140752facf084b04fb205b059056f47838790.jpg@128w_170h_1e_1c"}, {"name": "宋康昊", "role": "饰：宋佑硕", "image": "https://p0.meituan.net/movie/4512a6e8a0d435ad473cb55688396b2f41818.jpg@128w_170h_1e_1c"}, {"name": "柳秀荣", "role": "饰：客串律师", "image": "https://p1.meituan.net/movie/b10b64553f9a0aa6a93e22414575257a28315.jpg@128w_170h_1e_1c"}, {"name": "金英爱", "role": "饰：顺爱", "image": "https://p0.meituan.net/movie/d425c3641ded7faa175d9c81b6b02c1420108.jpg@128w_170h_1e_1c"}, {"name": "任时完", "role": "饰：镇宇", "image": "https://p0.meituan.net/movie/720120181d01b3044bcb58872be495cd35166.jpg@128w_170h_1e_1c"}, {"name": "车光洙", "role": "饰：Park Byung-ho", "image": "https://p1.meituan.net/movie/5f253b4521987a9b60c7f9f9056c3ac614534.jpg@128w_170h_1e_1c"}, {"name": "Ki-Jung Han", "role": "饰：Lee Hong-ki", "image": "https://p1.