INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (57, 57, 'https://ssr1.scrape.center/detail/57', '神偷奶爸 - Despicable Me', '["喜剧", "动画", "冒险"]', '美国、法国', 95, '2010-06-20', 'https://p0.meituan.net/movie/85c2bfba6025bfbfb53291ae5924c215308805.jpg@464w_644h_1e_1c', '一直以来，自诩为全世界最让人胆战心惊的超级混蛋的格鲁 （史蒂夫·卡瑞尔配音），始终觉得没有人可以阻挡他充满着邪恶趣味的前进脚步，可是当他与3个小女孩的生命有所交集之后，他很快就意识到，自己即将面对的是有史以来最艰难的挑战。 在一个被白色的尖桩篱笆和茂盛的玫瑰花丛所包围的看似快乐祥和的郊外社区里，坐落着一座全黑色的大房子，周围则是死气沉沉且略显呆板的绿色草坪。周遭邻居所不知道的是，在这座房子的下面，有一个非常隐蔽的巨大的藏匿之处，里面竟然驻扎着一支用心极度险恶的小矮人军队，而他们的头头格鲁则正在计划整个人类历史上最疯狂的抢劫案——没错，他打算偷走月亮。 不管是在什么样的环境下，格鲁天生似乎就只对做一些不道德的坏事感兴趣，简直是越堕落越快乐……除此之外，他背后还有一个可怕的军械库的支持和武装，最擅长的就是发射缩小光线和冷冻光线。格鲁已经做好了最先进的战斗准备，无论是地面还是空中作业，他都有办法应付——他已经想好了，他会毫不犹豫地清除掉任何挡在自己前进路线上的人，不达目的誓不罢休。直到有一天，他遇到了3个来自于孤儿院的小女孩，并与她们共同结成的强大意志力发生了激烈的碰撞  。', '[{"name": "克里斯·雷纳德", "image": "https://p0.meituan.net/movie/9fc7b6e34518b9d52615038d363956fc48754.jpg@128w_170h_1e_1c"}, {"name": "皮埃尔·柯芬", "image": "https://p0.meituan.net/movie/0a0dd39f251835676e1d11c842cc1d1448422.jpg@128w_170h_1e_1c"}]', '[{"name": "史蒂夫·卡瑞尔", "role": "饰：格鲁 Gru (voice)", "image": "https://p1.meituan.net/moviemachine/57e02202d414e5b1b57475b09077127a58126.jpg@128w_170h_1e_1c"}, {"name": "杰森·席格尔", "role": "饰：维克多 Vector (voice)", "image": "https://p1.meituan.net/movie/2314af1daf3c4f9406a83b77e346776a8294.jpg@128w_170h_1e_1c"}, {"name": "拉塞尔·布兰德", "role": "饰：纳法里奥博士 Dr. Nefario (voice)", "image": "https://p0.meituan.net/movie/b3db65cefc66b48b74532a3805c272777218.jpg@128w_170h_1e_1c"}, {"name": "朱莉·安德鲁斯", "role": "饰：格鲁妈妈 Gru''s Mom (voice)", "image": "https://p1.meituan.net/movie/d8127b9c8d27493b7828b28a32ee4a8a5832.jpg@128w_170h_1e_1c"}, {"name": "威尔·阿奈特", "role": "饰：Mr. Perkins (voice)", "image": "https://p0.meituan.net/moviemachine/267ff8641cc17b13763e2ac42b634c89195522.jpg@128w_170h_1e_1c"}, {"name": "克里斯汀·韦格", "role": "饰