9e5062bbc962821fe429bcfe82aca52640.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/fd527ee552574b05a73f91c1249dd1ce74718.jpg@106w_106h_1e_1c"]');
INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (44, 33, 'https://ssr1.scrape.center/detail/33', '海豚湾 - The Cove', '["纪录片"]', '美国', 92, '2009-07-31', 'https://p0.meituan.net/movie/eb2ea56996f21e7fb47b1a0736c7f177258901.jpg@464w_644h_1e_1c', '日本和歌山县太地，是一个景色优美的小渔村，然而这里却常年上演着惨无人道的一幕。每年，数以万计的海豚经过这片海域，他们的旅程却在太地戛然而止。渔民们将海豚驱赶到靠近岸边的一个地方，来自世界各地的海豚训练师挑选合适的对象，剩下的大批海豚则被渔民毫无理由地赶尽杀绝。这些屠杀，这些罪行，因为种种利益而被政府和相关组织所隐瞒。理查德·贝瑞年轻时曾是一名海豚训练师，他所参与拍摄电影《海豚的故事》备受欢迎。但是，一头海豚的死让理查德的心灵受到强烈的震撼。从此，他致力于拯救海豚的活动。不顾当地政府和村民百般阻挠，他和他的摄影团队想方设法潜入太地的海豚屠杀场，只为将罪行公之于众，拯救人类可爱的朋友……', '[{"name": "路易·西霍尤斯", "image": "https://p1.meituan.net/movie/7b3a7d3ed65b5e0f0cf89d4d0d34b1e126818.jpg@128w_170h_1e_1c"}]', '[{"name": "里克·奥巴瑞", "role": "饰：里克·奥巴瑞 Himself", "image": "https://p1.meituan.net/movie/404c98822552575b9061c6be12c1df408840.jpg@128w_170h_1e_1c"}, {"name": "路易·西霍尤斯", "role": "饰：路易·西霍尤斯 Himself", "image": "https://p1.meituan.net/movie/7b3a7d3ed65b5e0f0cf89d4d0d34b1e126818.jpg@128w_170h_1e_1c"}, {"name": "哈迪·琼斯", "role": "饰：哈迪·琼斯 Himself", "image": "https://p0.meituan.net/movie/6893bef07e0af2ef829be6c5ae99283027633.jpg@128w_170h_1e_1c"}, {"name": "森下助二", "role": "饰：森下助二 Himself", "image": "https://p1.meituan.net/movie/14bfea10f1f2ba59f8fe94919846918f25414.jpg@128w_170h_1e_1c"}, {"name": "Greg ''Moondog'' Mooney", "role": "饰：Himself (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Lesley Vogel", "role": "饰：Surfer", "image": "https://p0.meituan.net/movie/b99730cf8639d1702970478013b7d16452966.jpg@128w_170h_1e_1c"}, {"name": "James Triglone", "role": "饰：Surfer", "image": "https://p1.meituan.net/movie/748b9a1698584311e42507376c5b5fe825174.jpg@128w_170h_1e_1c"}, {"name": "Angie Takanami", "role": "饰：Surfer", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3