INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (48, 38, 'https://ssr1.scrape.center/detail/38', '时空恋旅人 - About Time', '["喜剧", "爱情", "奇幻"]', '英国', 123, '2013-09-04', 'https://p0.meituan.net/movie/6d8491386d07cda91967a6fbbd0d0788294693.jpg@464w_644h_1e_1c', '长到21岁的时候，蒂·姆雷克 （多姆纳尔·格里森饰演）突然得知自己有穿越时空的能力。在和往年一样不欢而散的新年派对之后，蒂姆的爸爸 （比尔·奈伊饰演）跟他坦诚布公：我们这个家族的男人，生来就有着穿越时空的神力。蒂姆虽然不能改变历史，但是他能够改变自己生命中发生过的和将要发生的一些小事，所以他决定运用自己的能力，让生活变得美好——说白了他是希望给自己找一个女朋友。然而，这并非像他相信中那么容易。蒂姆从康沃尔海岸搬到了伦敦，受训成为律师，在这里他终于遇上了一位漂亮但不那么自信的姑娘，名叫玛丽（ 瑞秋·麦克亚当斯 饰演）。两人相爱了。然而一次“穿越”当中，蒂姆不小心改变的一件小事就像像“蝴蝶效应”一样让他在将来生活中没有机会遇到玛丽。通过一次又一次的尝试，蒂姆一次又一次地和玛丽相遇，他终于赢得了她的心  。', '[{"name": "理查德·柯蒂斯", "image": "https://p0.meituan.net/movie/10138ec5b871ef53e7e2ed23d6dbbc8240255.jpg@128w_170h_1e_1c"}]', '[{"name": "瑞秋·麦克亚当斯", "role": "饰：玛丽 Mary", "image": "https://p1.meituan.net/movie/f4806f697952f455fd8941c37240fdd442744.jpg@128w_170h_1e_1c"}, {"name": "多姆纳尔·格里森", "role": "饰：蒂姆 Tim", "image": "https://p1.meituan.net/moviemachine/78ff4df04532230185d381d269e7deaa199590.jpg@128w_170h_1e_1c"}, {"name": "比尔·奈伊", "role": "饰：老爸 Tim''s father", "image": "https://p0.meituan.net/moviemachine/5c7c14e04af9e1d24ac7d21a25067af9214023.jpg@128w_170h_1e_1c"}, {"name": "玛歌特·罗比", "role": "饰：夏洛特 Chalotte", "image": "https://p0.meituan.net/movie/514b24ee759cf225bd617314faf46158228317.jpg@128w_170h_1e_1c"}, {"name": "汤姆·霍兰德", "role": "饰：哈利 Harry", "image": "https://p0.meituan.net/movie/4740f706137b51cadf9a22ede7dee0f637388.jpg@128w_170h_1e_1c"}, {"name": "琳赛·邓肯", "role": "饰：母亲 Tim‘s mother", "image": "https://p1.meituan.net/movie/cffc32e613cb610dd9af6be1e3e70f5626601.jpg@128w_170h_1e_1c"}, {"name": "内芙·加切夫", "role": "饰：护士 Nurse", "image": "https://p0.meituan.net/movie/08fe5c03dae774d556c220cf7b458e2d22226.jpg@128w_170h_1e_1c"}, {"name": "凡妮莎·柯比", "role": "饰：乔娜 Joanna", "image