INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (50, 40, 'https://ssr1.scrape.center/detail/40', '教父 - The Godfather', '["剧情", "犯罪"]', '美国', 175, '2015-04-18', 'https://p0.meituan.net/movie/1199dc6273680f175fd9b06c9c36d08a219658.jpg@464w_644h_1e_1c', '40年代的美国，“教父”维托·唐·柯里昂（马龙·白兰度 饰）是黑手党柯里昂家族的首领，带领家族从事非法的勾当，但同时他也是许多弱小平民的保护神，深得人们爱戴。 因为拒绝了毒枭索洛索的毒品交易要求，柯里昂家族和纽约其他几个黑手党家族的矛盾激化。圣诞前夕，索洛索劫持了“教 父”的参谋汤姆，并派人暗杀“教父”；因为内奸的出卖，“教父”的大儿子逊尼被仇家杀害；小儿子麦克（阿尔·帕西诺 饰）也被卷了进来，失去爱妻。黑手党家族之间的矛盾越来越白热化。年老的“教父”面对丧子之痛怎样统领全局？黑手党之间的仇杀如何落幕？谁是家族的内奸？谁又能够成为新一代的“教父”？血雨腥风和温情脉脉，在这部里程碑式的黑帮史诗巨片里真实上演。', '[{"name": "弗朗西斯·福特·科波拉", "image": "https://p1.meituan.net/movie/9528a48ecf56f74e2e9a09f8ade64efd44793.jpg@128w_170h_1e_1c"}]', '[{"name": "马龙·白兰度", "role": "饰：维托 Don Vito Corleone", "image": "https://p0.meituan.net/movie/0dba9e35a415ffc3d3d21b6f01956d17191506.jpg@128w_170h_1e_1c"}, {"name": "阿尔·帕西诺", "role": "饰：迈克尔 Michael Corleone", "image": "https://p0.meituan.net/moviemachine/4015ce1b1bf3c66c46a7cb897a6dc66962381.jpg@128w_170h_1e_1c"}, {"name": "詹姆斯·肯恩", "role": "饰：桑尼 Santino Sonny Corleone", "image": "https://p1.meituan.net/movie/a44b712dca5144911a91d6e809c84f3943291.jpg@128w_170h_1e_1c"}, {"name": "罗伯特·杜瓦尔", "role": "饰：汤姆·哈根 Tom Hagen", "image": "https://p1.meituan.net/movie/c67f8bed6cea1a5ba409f22e622c16d840126.jpg@128w_170h_1e_1c"}, {"name": "黛安·基顿", "role": "饰：凯·亚当斯 Kay Adams", "image": "https://p1.meituan.net/movie/6073b95d1a519d8ba0a2288de6e3061661520.jpg@128w_170h_1e_1c"}, {"name": "理查德·卡斯特尔诺", "role": "饰：Pete Clemenza (as Richard Castellano)", "image": "https://p1.meituan.net/movie/e772fab6ea66d23672351337c1a36c3b51917.jpg@128w_170h_1e_1c"}, {"name": "约翰·凯泽尔", "role": "饰：Fredo Corleone", "image": "https://p1.meituan.net/movie/894db5b656936916b5009f6dfe03b5ea49728.jpg@128w_170h_1e_1c"}, {"name": "阿历克斯·罗克", "role": "饰：M