INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (31, 41, 'https://ssr1.scrape.center/detail/41', '萤火之森 - 蛍火の杜へ', '["剧情", "爱情", "动画", "奇幻"]', '日本', 45, '2011-09-17', 'https://p1.meituan.net/movie/4c55f3bf5fa9660db3cb7014651a0950267034.jpg@464w_644h_1e_1c', '某年夏天，6岁小女孩竹川萤来到爷爷家度假，她闯进了传说住满妖怪的山神森林。正当她因为迷路而焦急万分的时候，一个戴着狐狸面具的大男孩出现在她面前，并引领着萤找到回家的路。虽然萤分外感激，可是男孩却禁止她碰触自己的身体，原来这名叫银的男孩并非人类，他一旦被人类碰触就会烟消云散。在此后的日子里，萤和银成为好朋友，他们走遍了森林的每一个角落玩耍。日复一日，年复一年，每到夏天的时候萤就会如约来到森林和好朋友见面。她遵守着和银的约定，无论如何也不碰触银的身体。随着年龄的增长，萤和银对彼此的情感都悄悄发生了变化，他们共同期待相聚的日子，共同期待拥抱对方…… 本片根据绿川幸的原作改编。', '[{"name": "大森贵弘", "image": "https://p0.meituan.net/movie/c873713e2b7fd5d116e24d763aa722ca44997.jpg@128w_170h_1e_1c"}]', '[{"name": "内山昂辉", "role": "饰：金", "image": "https://p0.meituan.net/movie/97312de8934e02870afa61e2cd752ff532548.jpg@128w_170h_1e_1c"}, {"name": "佐仓绫音", "role": "饰：Hotaru Takegawa,", "image": "https://p1.meituan.net/moviemachine/5738dfbb189ed65bde3c27d86276aa4f48704.jpg@128w_170h_1e_1c"}, {"name": "Izumi Sawada", "role": "饰：Mom", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "山本兼平", "role": "饰：Shadow", "image": "https://p0.meituan.net/movie/bb4735e9a5241220085becfd1acd44f838393.jpg@128w_170h_1e_1c"}, {"name": "辻亲八", "role": "饰：(voice)", "image": "https://p0.meituan.net/movie/21eec429b5edfcf0468a008ba3cae67133711.jpg@128w_170h_1e_1c"}, {"name": "Hayato Taya", "role": "饰：Ryota", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "内田麻美", "role": "饰：(voice)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}]', 8.8, '2026-04-24 03:07:12.503554', '2026-04-24 03:07:12.503554', '["https://p1.meituan.net/movie/81ccac4d23f21c6156d4ce38d5827ab043968.jpg@106w_106h_1e_1c", "http