INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (32, 42, 'https://ssr1.scrape.center/detail/42', '素媛 - 소원', '["剧情"]', '韩国', 123, '2013-10-02', 'https://p0.meituan.net/movie/19653e8af59cf473cd40f9ccc0658d93692304.jpg@464w_644h_1e_1c', '她（李莱 饰）是一个美丽平凡的小女孩，和爸爸妈妈生活在位于街角的家中。家里经营着以她的名字素媛命名的杂货店，母亲（严智媛 饰）作为老板娘日夜忙碌不得闲暇，父亲则在工厂干着繁重的工作。在那个飘雨的早上，素媛打着雨伞独自上学。在离学校近在咫尺的地方，她遭遇一个相貌猥琐、酒气冲天的大叔，由此开启了她的悲剧之旅。柔嫩的小花遭到暴风雨无情摧残，受伤的岂止枝枝叶叶，更是那迎着阳光无忧成长的心。无良媒体铺天盖地大肆渲染，作为受害者的素媛一家仿佛成了周身污秽的耻辱之人，被四周诧异好奇的目光所包围。妈妈悲痛欲绝，几近崩溃。爸爸全力保护女儿，但受伤的小天使却拒绝爸爸的靠近。问凶之路伴随着天使的治愈旅程，美丽的女孩可会再露灿烂笑容？', '[{"name": "李濬益", "image": "https://p1.meituan.net/movie/5573e1c7b5b45e455293f79abbd9277023301.jpg@128w_170h_1e_1c"}]', '[{"name": "李来", "role": "饰：素媛", "image": "https://p0.meituan.net/movie/25a5ee1ae613d226654e5fd4ed7ea4ac40998.jpg@128w_170h_1e_1c"}, {"name": "薛耿求", "role": "饰：素媛父亲", "image": "https://p0.meituan.net/movie/12cb7f687374ba28a616103e1952916c36565.jpg@128w_170h_1e_1c"}, {"name": "严志媛", "role": "饰：素媛母亲", "image": "https://p1.meituan.net/movie/f966c41bdd492d1dbe49226479668b5944077.jpg@128w_170h_1e_1c"}, {"name": "金海淑", "role": "饰：正淑", "image": "https://p0.meituan.net/movie/46b9737c5b0eb8df088118717dd157687751.jpg@128w_170h_1e_1c"}, {"name": "金相浩", "role": "饰：光植父亲", "image": "https://p0.meituan.net/moviemachine/033fb5a925eca4fc0c478bbe9dc0f3dc263118.jpg@128w_170h_1e_1c"}, {"name": "罗美兰", "role": "饰：光植母亲", "image": "https://p1.meituan.net/movie/e71e462699603fa1179e0c9f7554b6fa37669.jpg@128w_170h_1e_1c"}, {"name": "杨真诚", "role": "饰：Do-kyung", "image": "https://p0.meituan.net/movie/8923a6cad678e28d33ead8f730b5d63226213.jpg@128w_170h_1e_1c"}, {"name": "赵福来", "role": "饰：出租可可梦男2", "image": "https://p1.meituan.net/movie/ca265969239ea29b5322b3ec43452d19151004.jpg@128w_170h_1e_1c"}, {"name": "徐贤宇", "role": "饰：(救護人員)", "image": "https://p1.meit