INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (35, 45, 'https://ssr1.scrape.center/detail/45', '大话西游之大圣娶亲 - A Chinese Odyssey Part Two - Cinderella', '["喜剧", "爱情", "奇幻"]', '中国香港、中国大陆', 110, '2014-10-24', 'https://p1.meituan.net/moviemachine/508056769092059fe43a611b949f27d14863831.jpg@464w_644h_1e_1c', '至尊宝（周星驰 饰）被月光宝盒带回到五百年前，遇见紫霞仙子（朱茵 饰），被对方打上烙印成为对方的人，并发觉自己已变成孙悟空。 紫霞与青霞（朱茵 饰）本是如来佛祖座前日月神灯的灯芯（白天是紫霞，晚上是青霞），二人虽然同一肉身却仇恨颇深，因此紫霞立下誓言，谁能拔出她手中的紫青宝剑，谁就是她的意中人。紫青宝剑被至尊宝于不经意间拔出，紫霞决定以身相许，却遭一心记挂白晶晶（莫文蔚 饰）的至尊宝拒绝。后牛魔王救下迷失在沙漠中的紫霞，并逼紫霞与他成婚，关键时刻，至尊宝现身。', '[{"name": "刘镇伟", "image": "https://p0.meituan.net/movie/9a217ecaf62f1425ad9f231721d1a82737169.jpg@128w_170h_1e_1c"}]', '[{"name": "周星驰", "role": "饰：至尊宝,孙悟空", "image": "https://p0.meituan.net/movie/5cbe849bb17c8966a423ee015dc21aca41689.jpg@128w_170h_1e_1c"}, {"name": "朱茵", "role": "饰：紫霞仙子", "image": "https://p0.meituan.net/movie/e08ccd949f407da4c5db2e783c4b7d0646124.jpg@128w_170h_1e_1c"}, {"name": "莫文蔚", "role": "饰：白晶晶", "image": "https://p1.meituan.net/movie/7a8ec6da5a8612a25519550806545b2e52391.jpg@128w_170h_1e_1c"}, {"name": "蔡少芬", "role": "饰：铁扇公主", "image": "https://p1.meituan.net/movie/ba8bdb9e85d16ada41615716468a20cf40682.jpg@128w_170h_1e_1c"}, {"name": "陆树铭", "role": "饰：牛魔王", "image": "https://p1.meituan.net/movie/aaf033c1c0e05588ca6627954e89d4a529516.jpg@128w_170h_1e_1c"}, {"name": "吴孟达", "role": "饰：猪八戒", "image": "https://p1.meituan.net/movie/13d4357722d33b46a9fa52fbe8316f9633831.jpg@128w_170h_1e_1c"}, {"name": "罗家英", "role": "饰：唐三藏", "image": "https://p1.meituan.net/movie/8c2b172e4b3b9a41f05b508fe90985d231462.jpg@128w_170h_1e_1c"}, {"name": "蓝洁瑛", "role": "饰：蜘蛛精", "image": "https://p1.meituan.net/moviemachine/400ee552bb81817f80fd94bcaeed4d1435022.jpg@128w_170h_1e_1c"}, {"name": "刘镇伟", "role": "饰：菩提老祖,山贼葡萄", "image": "https://p0.meituan.net/m