INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (36, 46, 'https://ssr1.scrape.center/detail/46', '新龙门客栈 - New Dragon Gate Inn', '["动作", "爱情", "武侠", "古装"]', '中国香港、中国大陆', 88, '2012-02-24', 'https://p1.meituan.net/movie/7833126c8c21a11571bb52fbdece0acb811449.jpg@464w_644h_1e_1c', '宦官专权的明朝末年，东厂曹少钦（甄子丹 饰）假造圣旨杀害了忠良杨宇轩，并想斩草除根杀死其后代。侠女邱莫言（林青霞 饰）、江湖义士贺虎（任世官 饰）等人冒死救出忠良后代后，逃至边关沙漠里的龙门客栈，与杨宇轩部下周淮安（梁家辉 饰）会合。龙门客栈实则黑店，老板娘金镶玉（张曼玉 饰）利用乱世，以美貌和风骚作诱饵杀人越货聚敛钱财，但她却为英俊潇洒的周淮安动了真心。为了摸清潜藏于龙门客栈中的出关暗道，周淮安将计就计，答应与金镶玉成亲……', '[{"name": "李惠民", "image": "https://p0.meituan.net/movie/0a5cd866d46257a243b5695a41888cc539631.jpg@128w_170h_1e_1c"}, {"name": "姜明海", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}]', '[{"name": "张曼玉", "role": "饰：金镶玉", "image": "https://p0.meituan.net/movie/c48c4d1e6f4065a1ff9bc182ed43aa5048545.jpg@128w_170h_1e_1c"}, {"name": "梁家辉", "role": "饰：周淮安", "image": "https://p1.meituan.net/movie/e21a36816ea12bcbdaa819543e7f881632256.jpg@128w_170h_1e_1c"}, {"name": "甄子丹", "role": "饰：曹少钦", "image": "https://p0.meituan.net/moviemachine/9ccb37abf959c64231184506debf5def146192.jpg@128w_170h_1e_1c"}, {"name": "刘洵", "role": "饰：贾庭", "image": "https://p1.meituan.net/movie/a19cfd0ac7aef81220be64c1069f20f330328.jpg@128w_170h_1e_1c"}, {"name": "吴启华", "role": "饰：路小川", "image": "https://p1.meituan.net/movie/9418616a4f5e4e49d6b8f8faec0da23038379.jpg@128w_170h_1e_1c"}, {"name": "熊欣欣", "role": "饰：魏忠威", "image": "https://p1.meituan.net/movie/f7417455ad4b05d0d54fa26c5062812329543.jpg@128w_170h_1e_1c"}, {"name": "袁祥仁", "role": "饰：铁竹", "image": "https://p0.meituan.net/movie/5b4aee94536c43f81f19bc8f6e765b3e34506.jpg@128w_170h_1e_1c"}, {"name": "任世官", "role": "饰：贺虎", "image": "https://p0.meituan.net/movie/42d73be2ce7861bf380e4c389302fa2146583.jpg@128w_170h_1e_1c"}, {"name": "元