INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (37, 47, 'https://ssr1.scrape.center/detail/47', '触不可及 - Intouchables', '["剧情", "喜剧"]', '法国', 112, '2011-11-02', 'https://p1.meituan.net/movie/1e700e53e4fe29dd5942381bb353c8532239179.jpg@464w_644h_1e_1c', '因为一次跳伞事故，白人富翁菲利普（弗朗索瓦·克鲁塞 饰）瘫痪在床，欲招聘一名全职陪护。由于薪酬高，应聘者云集，个个舌灿莲花，却无法打动他的心。直到黑人德瑞斯（奥玛·赛 饰）的出现才让他作出决定。德希斯刚从监狱出来，背负家庭重担，一心只想寻张辞退信以申领救济金，而且他明显对女助理的兴趣要远大于这份工作。但是菲利普还是一眼相中了这个小伙子。于是，德瑞斯开始了一个月的试用期。虽然舒适的豪宅环境让他倍感虚荣，但是他仍面临很多挑战：不仅要为菲利普作身体复健，还得给他洗浴、灌肠、拆信、穿丝袜等。起初，两人的思维方式与价值观大相径庭，但是，随着了解的不断深入，他们成为了朋友……', '[{"name": "奥利维埃·纳卡什", "image": "https://p1.meituan.net/movie/f5cdfef013549faa83232c4ab6c9992f32088.jpg@128w_170h_1e_1c"}, {"name": "埃里克·托莱达诺", "image": "https://p0.meituan.net/movie/7e98821db07a4c5728647edef3e0f36551701.jpg@128w_170h_1e_1c"}]', '[{"name": "弗朗索瓦·克鲁塞", "role": "饰：菲利普 Philippe", "image": "https://p0.meituan.net/movie/2962918aa660f191157bffc56a45194e45187.jpg@128w_170h_1e_1c"}, {"name": "奥玛·希", "role": "饰：德瑞斯 Driss", "image": "https://p0.meituan.net/movie/b45c550849feb3547c7369ecbf9be10540383.jpg@128w_170h_1e_1c"}, {"name": "安娜·勒尼", "role": "饰：伊冯 Yvonne", "image": "https://p0.meituan.net/movie/c3510a63e38e06a8c93d60fed54e42bd32797.jpg@128w_170h_1e_1c"}, {"name": "奥德雷·弗勒罗", "role": "饰：玛嘉丽 Magalie", "image": "https://p1.meituan.net/movie/c7f2cc0efe7f773e3a4b467ff585bec346570.jpg@128w_170h_1e_1c"}, {"name": "阿尔芭·贝露琪", "role": "饰：艾丽萨 Elisa", "image": "https://p1.meituan.net/movie/d9a885671255f692975ad1087fc97e4b19532.jpg@128w_170h_1e_1c"}, {"name": "Cyril Mendy", "role": "饰：Adama", "image": "https://p1.meituan.net/movie/e4ca04b380ad0fc492cf948ad26f7fbd47251.jpg@128w_170h_1e_1c"}, {"name": "Christian Ameri", "role": "饰：Albert", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Grégoir