INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (38, 48, 'https://ssr1.scrape.center/detail/48', '钢琴家 - The Pianist', '["剧情", "音乐", "传记", "历史", "战争"]', '法国、德国、英国、波兰', 150, '2002-05-24', 'https://p0.meituan.net/movie/bcbe59fc51580317adf94537a61a1a26142090.jpg@464w_644h_1e_1c', '史标曼（艾德里安·布洛迪 饰）是波兰一家电台的钢琴师。二战即将爆发之时，他们全家被迫被赶进华沙的犹太区。在战争的颠沛流离中，家人和亲戚最终被纳粹杀害，而标曼本人也受尽种种羞辱和折磨，他侥幸得到一位朋友的帮助，暂时有了藏身之处。战争愈加猛烈，朋友不得不抛下 他回老家寻得安全的住所养育儿女。此时史标曼恶病缠身，却还要在搜捕中逃亡。在废墟的阁楼上他遇见了一名德国军官，在军官的要求下他弹奏了钢琴曲。美妙的琴声令德国军官萌发了恻隐之心，他暗暗帮助标曼直到俄军对波兰的解放到来……', '[{"name": "罗曼·波兰斯基", "image": "https://p1.meituan.net/movie/62f2954de5c1b9b2c7cc7b6176182b8519789.jpg@128w_170h_1e_1c"}]', '[{"name": "艾德里安·布洛迪", "role": "饰：瓦迪斯瓦夫·斯皮尔曼 Wladyslaw Szpilman", "image": "https://p1.meituan.net/movie/03c65e824adc913ef6cb17412f1445bf38341.jpg@128w_170h_1e_1c"}, {"name": "艾米莉娅·福克斯", "role": "饰：多罗塔 Dorota", "image": "https://p0.meituan.net/movie/e3b9c46ce9e31e451aac928a4db260fe40162.jpg@128w_170h_1e_1c"}, {"name": "米哈乌·热布罗夫斯基", "role": "饰：尤雷克 Jurek", "image": "https://p0.meituan.net/movie/37dcf0c1517a2282d46991e6438ca91036369.jpg@128w_170h_1e_1c"}, {"name": "埃德·斯托帕德", "role": "饰：亨里克 Henryk", "image": "https://p1.meituan.net/movie/47b61b9aa177b2128497ee25f3ae664941175.jpg@128w_170h_1e_1c"}, {"name": "穆琳·利普曼", "role": "饰：母亲 Mother", "image": "https://p1.meituan.net/movie/24e5ed02b0a30d885c5acd07c8b7779a47452.jpg@128w_170h_1e_1c"}, {"name": "弗兰克·芬莱", "role": "饰：父亲 Father", "image": "https://p1.meituan.net/movie/2b99db492737145b596170df4419f9db77203.jpg@128w_170h_1e_1c"}, {"name": "Wanja·穆埃斯", "role": "饰：SS·斯莱汀父亲 SS Slapping Father", "image": "https://p0.meituan.net/movie/7a8926c1a211389a5adbd2748a6678cf40333.jpg@128w_170h_1e_1c"}, {"name": "茱莉亚·蕾娜", "role": "饰：里贾纳 Regina", "image": "https://p0.meituan.net/movie/4dcb6efb322d4d12d5b4c50a32700c7a11383.jpg