INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (39, 49, 'https://ssr1.scrape.center/detail/49', '本杰明·巴顿奇事 - The Curious Case of Benjamin Button', '["剧情", "爱情", "奇幻"]', '美国', 166, '2008-12-25', 'https://p0.meituan.net/movie/2526f77c650bf7cf3d5ee2dccdeac332244951.jpg@464w_644h_1e_1c', '飓风正在侵袭美国新奥尔良，一位病危的老妇睁开了她的睡眼。老妇名叫戴茜（凯特·布兰切特 饰），她叫女儿凯若琳（朱莉娅·奥蒙德 饰）为她阅读一本日记。这本日记的作者叫本杰明·巴顿（布拉德·皮特 饰）。本杰明出生在第一次世界大战停战之时，但生来便像个老人的他被父亲当作怪物，被遗弃在了养老院。本杰明在养老院与老人们一起生活。但谁都没有想到，本杰明逆向发育——越活越年轻！也许“越活越年轻”是某些人的梦想，但真正这样成长的本杰明却有了别人无法理解的烦恼与快乐。穿越半世纪的世界变革，本杰明身处其中，感受别人感受不到的感受。为何母亲会让自己念这本日记？本杰明·巴顿此人与母亲有什么关系？凯若琳陷入了深深的疑惑与好奇之中。', '[{"name": "大卫·芬奇", "image": "https://p0.meituan.net/movie/84620ccacfaca8b87f7ce18367f3647b29797.jpg@128w_170h_1e_1c"}]', '[{"name": "布拉德·皮特", "role": "饰：本杰明·巴顿 Benjamin Button", "image": "https://p0.meituan.net/moviemachine/3e523c730e278d0fe8cbf519a361376d189135.jpg@128w_170h_1e_1c"}, {"name": "凯特·布兰切特", "role": "饰：黛西 Daisy", "image": "https://p0.meituan.net/movie/3e569e1ec99f6f2f1c9bc5d040f1ab5f58008.jpg@128w_170h_1e_1c"}, {"name": "塔拉吉·P·汉森", "role": "饰：奎妮 Queenie", "image": "https://p0.meituan.net/movie/657f86a45b4e651f480c341d1af4dc7255175.jpg@128w_170h_1e_1c"}, {"name": "朱莉娅·奥蒙德", "role": "饰：卡洛琳 Caroline", "image": "https://p0.meituan.net/movie/fa48c557b66bbe41c9fdaf87f22f824131900.jpg@128w_170h_1e_1c"}, {"name": "芳妮·A·钱勃丝", "role": "饰：多萝西·贝克尔 Dorothy Baker", "image": "https://p1.meituan.net/movie/0d24b9a702ae89a4354b0ae6844967e848843.jpg@128w_170h_1e_1c"}, {"name": "伊莱亚斯·科泰斯", "role": "饰：Monsieur Gateau", "image": "https://p1.meituan.net/movie/923fce53670af2a675e42c7240500e7b47085.jpg@128w_170h_1e_1c"}, {"name": "Nadyia Jones", "role": "饰：Loft Dancer (uncredited)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Brianna Womick", "rol