INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (46, 35, 'https://ssr1.scrape.center/detail/35', '恐怖直播 - 더 테러 라이브', '["剧情", "悬疑", "犯罪"]', '韩国', 97, '2013-07-31', 'https://p0.meituan.net/movie/1da0af2570fe697d38c4a37fdfded19b254936.jpg@464w_644h_1e_1c', '韩国首尔某个平凡的早上，广播电台Daily Topic节目的主持人尹英华（河正宇 饰）正就税率改革与听众进行连线，这时一个自称住在首尔昌信洞的普通工人朴鲁圭打入电话，大肆抱怨超高的电费和相关部门对他的威胁。尹英华颇不耐烦，以偏离主题为由强行切断电话。谁知连线无法单方面由电台方面中断，愤怒的朴鲁圭继续抱怨，并扬言炸掉汉江大桥。尹英华不以为然，进而怂恿对方想做就做，谁知话音刚落，窗外的麻浦大桥便炸作废墟。大惊失色的尹英华很快冷静下来，他决定利用这次难得的机会打一次事业的翻身仗。在他的主持下，针对恐怖分子的连线直播就此展开，无关良知的节目拉开帷幕……', '[{"name": "金秉宇", "image": "https://p0.meituan.net/movie/ca3872ee057bf80359d38b53cf5a1c4140904.jpg@128w_170h_1e_1c"}, {"name": "金秉祐", "image": "https://p0.meituan.net/movie/fc74ea2dfa301fcf2a6d855ca3bbc6ae12313.jpg@128w_170h_1e_1c"}]', '[{"name": "河正宇", "role": "饰：尹英华", "image": "https://p0.meituan.net/movie/23b2d512b337582b3d07df20eb01f10440335.jpg@128w_170h_1e_1c"}, {"name": "李璟荣", "role": "饰：Cha Dae-eun", "image": "https://p1.meituan.net/movie/9f1929ab4b18babe8b55b2c1739f131857639.jpg@128w_170h_1e_1c"}, {"name": "李大为", "role": "饰：Park Shin-Woo", "image": "https://p0.meituan.net/movie/e39cc28a79b41c9e0806a5e3c67c46b545573.jpg@128w_170h_1e_1c"}, {"name": "金弘波", "role": "饰：Police commissioner", "image": "https://p1.meituan.net/movie/135e9a3adc3477339e1e223e1c4e01df63735.jpg@128w_170h_1e_1c"}, {"name": "金素真", "role": "饰：Lee Ji-Soo", "image": "https://p0.meituan.net/movie/39702f4e7abd5d6f60e57f94a3fc659912209.jpg@128w_170h_1e_1c"}, {"name": "崔镇浩", "role": "饰：Lee Sang-Jin", "image": "https://p0.meituan.net/movie/a79bbc2d68388f862370f68c28ce708014469.jpg@128w_170h_1e_1c"}, {"name": "Sung-chun Han", "role": "饰：Radio Producer", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "全惠真", "role": "饰：Park Jung-Min",