INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (49, 39, 'https://ssr1.scrape.center/detail/39', '穿条纹睡衣的男孩 - The Boy in the Striped Pajamas', '["剧情", "战争"]', '英国、美国', 94, '2008-08-28', 'https://p1.meituan.net/movie/d5970e36c8868a4b746c80f3b3f8a404174615.jpg@464w_644h_1e_1c', '1940年代的柏林，八岁的小男孩布鲁诺和同学在外面玩耍后回 到家里，发现家里正忙得不可开交。原来身为纳粹军官的父亲被升职将要调遣，母亲正在准备一次聚会。只不过布鲁诺一点儿也高兴不起来，父亲的新职务是在波兰的纳粹集中营，全家都要搬过去，这样他不得不离开心爱的家和伙伴们。一开始布鲁诺很难适应新的生活环境，很快就觉得无聊起来。没有同龄人陪他玩，母亲也禁止他到处走。倒是姐姐从来不讨厌跟他聊天，因为姐姐忙于摆弄自己的布娃娃，或者是跟父亲的同事——一位年轻英俊的男子聊天。布鲁诺从自己房间的窗户往外看，有一处很奇怪的农场，人们都穿着条纹睡衣在干活。正当他想试着多去了解一些的时候，又被警告不许接近那里。实际上就连母亲也不太清楚这里，她以为只是住在某个劳动营的隔壁，丈夫隐瞒了这里是杀人工厂 奥斯维辛集中营的真相。有一天布鲁诺在花园里玩的时候，不小心摔倒把膝盖碰伤了。在厨房干活的穿着条纹睡衣的帕维尔赶过来帮助他包扎了伤口。两人从此结为了好友。在房子周围晃悠了几周之后，布鲁诺终于决定越过界限来到了一个用电线网制成的围墙边，看到围墙的另一边有一个穿着条纹睡衣的男孩在用手推车倒碎石子。他很惊讶终于在这里发现了可以一起玩的同龄人，布鲁诺以后每天都要偷偷来这里和新朋友什穆埃尔见面。数周过去，布鲁诺对于自己的所见所闻愈加感到困惑，家人教导他所有 犹太人都是魔鬼而他与什穆埃尔的关系却越来越紧密。另一方面，父亲决定把他们和妈妈送到海德堡的姑姑那里去。一想到从此无法再见到这位最好的新朋友，布鲁诺感到很绝望。什穆埃尔告诉布鲁诺自己的父亲失踪了三天，布鲁诺决定利用最后的时间为他做些事情，于是也穿上了一件条纹睡衣，从一块松动的铁丝网下爬进集中营。然而，无情的命运却与小男孩布鲁诺开了一个天大的玩笑，他的生命也将从此划上句号  。', '[{"name": "马克·赫尔曼", "image": "https://p0.meituan.net/movie/816d91a816ff194d88636b01dd5e042c30501.jpg@128w_170h_1e_1c"}]', '[{"name": "阿沙·巴特菲尔德", "role": "饰：布鲁诺 Bruno", "image": "https://p0.meituan.net/moviemachine/d7a5efcbb62e02190b431273bd4d53e9136604.jpg@128w_170h_1e_1c"}, {"name": "维拉·法梅加", "role": "饰：布鲁诺母亲", "image": "https://p0.meituan.net/moviemachine/8afe2cd311a078f889c14f2783b4d810179095.jpg@128w_170h_1e_1c"}, {"name": "大卫·休里斯", "role": "饰：布鲁诺父亲", "image": "https://p0.meituan.net/movie/3370dae9842b17a809b9ed7628b1193e47146.jpg@128w_170h_1e_1c"}, {"name": "鲁伯特·弗兰德", "role": "饰：Lt Kotler", "image": "https://p0.meituan.net/movie/b2482e8e07afc2ab0aed7d77fe949f1544489.jpg@128w_170h_1e_1c"}, {"name": "杰克·塞隆", "role": "饰：撒慕尔 Shmuel", "image": "https://p1.meituan.net/movie/9409ccc08607a10c659743ce87ce966734096.jpg@128w_170h_1e_1c"}, {"name": "卡拉·霍根", "role": "饰：Maria", "image": "https://p0.meituan.net/movie/786cda02c239274eb2dadd7801ed1b5826874.jpg@128w_170h_1e_1c"}, {"name": "理查德·约翰逊", "role": "饰：布鲁诺祖父 grandpa", "image": "https://p1.meituan.net/movie/c2cb61bf3951abf4e23c94283c34304e31398.jpg@128w_170h_1e_1c"}, {"name": "大卫·海曼", "role": "饰：Pavel", "image": "https://p0.meituan.net/movie/7366382bba35fed7cccfa9ebd5cf3a2928585.jpg@128w_170h_1e_1c"}, {"name": "谢拉·汉考克", "role": "饰：Grandma", "image": "https://p0.meituan.net/movie/5c5c78439d971f8d43d6836a6f4461be40574.jpg@128w_170h_1e_1c"}, {"name": "安贝尔·比蒂", "role": "饰：Gretel", "image": "https://p1.meituan.net/movie/88609161746f3896404cc62126a49c3c16638.jpg@128w_170h_1e_1c"}, {"name": "祖萨·霍尔", "role": "饰：Berlin Cook", "image": "https://p0.meituan.net/movie/b3d2792515ebf9f4cb99f33e6afead5911843.jpg@128w_170h_1e_1c"}, {"name": "拉斯洛·阿隆", "role": "饰：Lars", "image": "https://p1.meituan.net/movie/795fe8fd193ecb9ec463d8b5d33f3b8e17383.jpg@128w_170h_1e_1c"}, {"name": "Henry Kingsmill", "role": "饰：Karl", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Zac Mattoon O''Brien", "role": "饰：Leon (as Zac Mattoon-O''Brien)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Gábor Harsai", "role": "饰：Elderly Jewish Man (as Gábor Harsay)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "贝拉·费斯彼姆", "role": "饰：Schultz", "image": "https://p0.meituan.net/movie/3a806b238b337bc6ea8ac1de4623aa4f37706.jpg@128w_170h_1e_1c"}, {"name": "Domonkos Németh", "role": "饰：Martin", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "阿提拉·埃杰德", "role": "饰：Heinz", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "伊凡·弗雷贝利", "role": "饰：Meinb