INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (40, 50, 'https://ssr1.scrape.center/detail/50', '倩女幽魂 - A Chinese Ghost Story', '["爱情", "奇幻", "武侠", "古装"]', '中国香港', 98, '2011-04-30', 'https://p1.meituan.net/movie/96d98200d2afb4b87ff189f9c15b6545568339.jpg@464w_644h_1e_1c', '宁采臣 （张国荣饰）赴郭北县收帐，逢大雨，躲入传说纷纭的兰若寺投宿，但为寺内道士燕赤霞 （午马饰）所拒，于是宁采臣偷偷潜入寺中。入夜，宁采臣被一阵琴音吸引，邂逅少女聂小倩 （王祖贤饰）。聂小倩突露杀机，幸燕赤霞赶到，救下宁采臣一命。聂小倩感其正直，心生爱意，但被燕赤霞阻止。宁采臣却误认燕赤霞为杀人犯，欲与聂小倩逃走。树精姥姥 （刘兆铭饰）逼聂小倩杀宁采臣，聂小倩不肯，姥姥命众魔欲杀宁与小倩，燕赤霞再次出现，救 下二人，姥姥重伤。此时宁采臣才知聂小倩原是一游魂，因尸骨被弃荒野而受姥姥控制，每夜四处寻找壮男为姥姥吸引阳精，增益延寿。为免聂小倩再次受辱，宁采臣答应将其尸骨送回乡间安葬。不料聂小倩却被地府石妖抢去为妻。燕赤霞经不住宁采臣相求，再次出手，终于救回小倩  。', '[{"name": "程小东", "image": "https://p1.meituan.net/moviemachine/9825dc7c3aefa70eb07cb690f30e3cb9170000.jpg@128w_170h_1e_1c"}]', '[{"name": "张国荣", "role": "饰：宁采臣", "image": "https://p0.meituan.net/movie/5de69a492dcbd3f4b014503d4e95d46c28837.jpg@128w_170h_1e_1c"}, {"name": "王祖贤", "role": "饰：聂小倩", "image": "https://p0.meituan.net/movie/869285ff731a5aac6c6e329794aee73e35562.jpg@128w_170h_1e_1c"}, {"name": "午马", "role": "饰：燕赤霞", "image": "https://p1.meituan.net/movie/69796542b58e6853227b3a7080b4278242133.jpg@128w_170h_1e_1c"}, {"name": "林威", "role": "饰：夏侯剑客", "image": "https://p0.meituan.net/movie/123d184e41dbe58f3377615ca3a5741526017.jpg@128w_170h_1e_1c"}, {"name": "王晶", "role": "饰：贪官", "image": "https://p0.meituan.net/movie/f66bc9444757e1398d0e07f520f1c2df54686.jpg@128w_170h_1e_1c"}, {"name": "薛芷伦", "role": "饰：小青", "image": "https://p1.meituan.net/movie/097791e9dad318515edc23759e11bfd313449.jpg@128w_170h_1e_1c"}, {"name": "刘兆铭", "role": "饰：姥姥", "image": "https://p1.meituan.net/movie/95abc764e2ebd39c4de59e16d204d6df51106.jpg@128w_170h_1e_1c"}, {"name": "胡大为", "role": "饰：师爷", "image": "https://p0.meituan.net/movie/b69cb3d4efd6ab466c28378df1a69ac937940.jpg@128w_170h_1e_1c"}, {"name": "蒋金", "role": "饰：Policeman (as Kam Chiang)", "image": "https://p1.meituan.net/movie/b94b07f7ba1c128c6f833176854310b214187.jpg@128w_170h_1e_1c"}, {"name": "黄哈", "role": "饰：Boss at Tavern", "image": "https://p1.meituan.net/movie/96a94b2b4bd7639b2d22c4e00d528da336701.jpg@128w_170h_1e_1c"}, {"name": "Mei-Yee Sze", "role": "饰：Paintings Seller", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "杨又祥", "role": "饰：Charm Seller", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}]', 8.9, '2026-04-24 03:07:12.503554', '2026-04-24 03:07:12.503554', '["https://p0.meituan.net/movie/479cbd53065e4820b3c90dbdd42d6d1578981.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/ef1cf6926b66cb68403d2ec1f0683270473587.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/d8ccbd3f512ed87d21871e9b42f5d70241634.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/f9c7301c5950314c33c2144abd70cbe5102683.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/afd4417184e03e6801443ad80eb16d1375334.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/f3fe9116d169a1c6ca89fc251f98d807216586.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/781ab187179337783ad3095a6c182e4a59648.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/0906d96f24d029e78ad8912e5542221385974.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/e278394c3d59ad3567bb08d0228e0afc50325.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/6116ee50930aa0567df623c8f8c295fa45478.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/c8f23012514cdf34637ac78d2ddfa64b72481.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/039fb5e4ecf2fa9f97105adfec3035a962005.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/25c8a8404afe1589543e316b7f0ee27976008.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/83635a797685ad47894cd634af383253249599.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/db9c6f93692d3eab93d3383c3c78e71763407.jpg@106w_106h_1e_1c",