INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (16, 16, 'https://ssr1.scrape.center/detail/16', '一一 - Yi yi: A One and a Two', '["剧情", "爱情", "家庭"]', '中国台湾、日本', 173, '2000-05-15', 'https://p0.meituan.net/movie/6cb23356f9d8e0b506349561c633310d102189.jpg@464w_644h_1e_1c', 'NJ（吴念真 饰）是个很有原则的生意人，同妻子敏敏（金燕玲 饰）、女儿婷婷（李凯莉 饰）、儿子洋洋（张杨洋饰）以及外婆住在台北某所普通公寓里。小舅子的一场麻烦婚礼过后，因为外婆突然中风昏迷，他迎来更加混乱的日子。敏敏公司、家里两头跑，时常感觉自己要被耗空；婷婷一直为外婆的中风内疚，恋爱谈到中途发现自己不过是替代品；NJ更是麻烦重重，公司面临破产，他又不愿放下别人眼里一文不值的自尊。一家人里，似乎只有洋洋没有烦恼，他平静地用照相机拍着各种人的背面，帮他们长出另一双眼睛，然而，洋洋简简单单的一句话，道出更深的悲凉。', '[{"name": "杨德昌", "image": "https://p0.meituan.net/movie/e0227e2fb8e69f0bd86287305a12c55290999.jpg@128w_170h_1e_1c"}]', '[{"name": "吴念真", "role": "饰：简南俊", "image": "https://p1.meituan.net/movie/1374a080d4855ffe2eec0902034caea057277.jpg@128w_170h_1e_1c"}, {"name": "金燕玲", "role": "饰：敏敏", "image": "https://p0.meituan.net/movie/2a9f0e4396681361955ca375c4307a7635002.jpg@128w_170h_1e_1c"}, {"name": "李凯莉", "role": "饰：简婷婷", "image": "https://p0.meituan.net/movie/adddf522224aa96b17fd8419859f995a8602.jpg@128w_170h_1e_1c"}, {"name": "林孟瑾", "role": "饰：莉莉", "image": "https://p0.meituan.net/movie/91b997890f091fe085b712f78e4b303037742.jpg@128w_170h_1e_1c"}, {"name": "张洋洋", "role": "饰：洋洋", "image": "https://p1.meituan.net/movie/b1285ccd6eaca85f1598d92aa94e8dd77814.jpg@128w_170h_1e_1c"}, {"name": "陈以文", "role": "饰：客串", "image": "https://p0.meituan.net/movie/333b6ae4a5de1593523a41015ba05a6328132.jpg@128w_170h_1e_1c"}, {"name": "柯宇纶", "role": "饰：士兵", "image": "https://p0.meituan.net/movie/1ce5c4965d16a44b482b1b543c95d42312943.jpg@128w_170h_1e_1c"}, {"name": "唐如韫", "role": "饰：祖母", "image": "https://p1.meituan.net/movie/abc2fee1bd836ea2bb5f0289d1d04ea322932.jpg@128w_170h_1e_1c"}, {"name": "杨德昌", "role": "饰：钢琴家", "image": "https://p0.meituan.net/movie/e0227e2fb8e69f0bd86287305a12c