INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (19, 19, 'https://ssr1.scrape.center/detail/19', '千与千寻 - 千と千尋の神隠し', '["动画", "冒险", "奇幻", "家庭"]', '日本', 125, '2019-06-21', 'https://p0.meituan.net/movie/30b20139e68c46d02e0893277d633b701292458.jpg@464w_644h_1e_1c', '千寻和爸爸妈妈一同驱车前往新家，在郊外的小路上不慎进入了神秘的隧道——他们去到了另外一个诡异世界—一个中世纪的小镇。远处飘来食物的香味，爸爸妈妈大快朵颐，孰料之后变成了猪！这时小镇上渐渐来了许多样子古怪、半透明的人。千寻仓皇逃出，一个叫小白的人救了他，喂了她阻止身体消失的药，并且告诉她怎样去找锅炉爷爷以及汤婆婆，而且必须获得一份工作才能不被魔法变成别的东西。千寻在小白的帮助下幸运地获得了一份在浴池打杂的工作。渐渐她不再被那些怪模怪样的人吓倒，并从小玲那儿知道了小白是凶恶的汤婆婆的弟子。一次，千寻发现小白被一群白色飞舞的纸人打伤，为了救受伤的小白，她用河神送给她的药丸驱出了小白身体内的封印以及守封印的小妖精，但小白还是没有醒过来。为了救小白，千寻又踏上了她的冒险之旅。', '[{"name": "宫崎骏", "image": "https://p1.meituan.net/movie/5d786f92d2049516338e7be0ea3fa4e048311.jpg@128w_170h_1e_1c"}]', '[{"name": "柊瑠美", "role": "饰：荻野千寻（日语配音）", "image": "https://p1.meituan.net/movie/0d8aee5d74b5236621a4ffcf6eb51c9c31799.jpg@128w_170h_1e_1c"}, {"name": "周冬雨", "role": "饰：荻野千寻（国语配音）", "image": "https://p1.meituan.net/moviemachine/de7fcc999b2b13283f98616a189ac306203395.jpg@128w_170h_1e_1c"}, {"name": "入野自由", "role": "饰：白龙（日语配音）Haku (voice)", "image": "https://p0.meituan.net/movie/58b09d578f37d08083c458e94310a18e27559.jpg@128w_170h_1e_1c"}, {"name": "井柏然", "role": "饰：白龙（国语配音）Haku (voice)", "image": "https://p1.meituan.net/movie/94e98e0026eb8a8506836588bb5657a1174372.jpg@128w_170h_1e_1c"}, {"name": "夏木真理", "role": "饰：汤婆婆（日语配音）", "image": "https://p1.meituan.net/movie/48e17454135e983b5f688db4cd2ffe7237107.jpg@128w_170h_1e_1c"}, {"name": "王琳", "role": "饰：汤婆婆 / 钱婆婆（国语配音）", "image": "https://p1.meituan.net/movie/fc319facd28ec9a4f9c270840735e42840490.jpg@128w_170h_1e_1c"}, {"name": "中村彰男", "role": "饰：无脸男（日语配音）Kaonashi(voice)", "image": "https://p0.meituan.net/movie/dca382883bb25097f9eded354a38a43324422.jpg@128w_170h_1e_1c"}, {"name": "彭昱畅", "role": "饰：无脸男（国语配音）Kaonashi(voice)", "imag