INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (52, 52, 'https://ssr1.scrape.center/detail/52', '甜蜜蜜 - Comrades: Almost a Love Story', '["剧情", "爱情"]', '中国香港', 118, '2015-02-13', 'https://p1.meituan.net/movie/0b0d45b58946078dd24d4945dd6be3b51329411.jpg@464w_644h_1e_1c', '改革开放初期，黎小军（黎明 饰）告别女友小婷（杨恭如 饰）从无锡来到香港讨生活，期望有天挣到大钱把小婷接来与之风风光光地成婚，没料想日子会比想象中的难熬许多。黎小军在快餐店与同样从大陆到港讨生活但避讳谈自己身份的李翘（张曼玉 饰）结识后，因为共同喜爱邓丽君，两人人在异乡的孤独都有了某种程度的缓解，并在交往的过程中生出了真爱，可是世事难料，两人最终无奈分手，黎小军成了小婷的老公，李翘跟了在黑社会做事的豹哥（曾志伟 饰）。然而因为邓丽君，两人的缘分并没到此为止。', '[{"name": "陈可辛", "image": "https://p0.meituan.net/movie/9c314f6ac6cbf1e4d5866abfb55a19b537280.jpg@128w_170h_1e_1c"}, {"name": "赵良骏", "image": "https://p0.meituan.net/movie/16d4b4e04d5a06d67ed43fceaf4d49cd30536.jpg@128w_170h_1e_1c"}]', '[{"name": "黎明", "role": "饰：黎小军", "image": "https://p0.meituan.net/movie/3165ceecfb3cd81737ea55b33385c99441592.jpg@128w_170h_1e_1c"}, {"name": "张曼玉", "role": "饰：李翘", "image": "https://p0.meituan.net/movie/c48c4d1e6f4065a1ff9bc182ed43aa5048545.jpg@128w_170h_1e_1c"}, {"name": "曾志伟", "role": "饰：欧阳豹", "image": "https://p0.meituan.net/movie/1fb88ccc945980801701d50597bae66553347.jpg@128w_170h_1e_1c"}, {"name": "张同祖", "role": "饰：阿恩", "image": "https://p1.meituan.net/movie/2448c99e6cd56f06912ab8269dafcc5d40705.jpg@128w_170h_1e_1c"}, {"name": "杜可风", "role": "饰：卤味斋", "image": "https://p0.meituan.net/movie/b7d251117271bd006a15f9fe0e8d118b34591.jpg@128w_170h_1e_1c"}, {"name": "杨恭如", "role": "饰：方小婷", "image": "https://p0.meituan.net/movie/f70416725a873210d1af23b70ee0496a39761.jpg@128w_170h_1e_1c"}, {"name": "丁羽", "role": "饰：乔治", "image": "https://p0.meituan.net/movie/30dcc141371d08eba37b21cdadd477f028775.jpg@128w_170h_1e_1c"}, {"name": "米歇尔·加布里埃尔", "role": "饰：芥兰", "image": "https://p1.meituan.net/movie/8beb82b418b1183dfc8ed77cd790f08c50848.jpg@128w_170h_1e_1c"}, {"na