INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (53, 53, 'https://ssr1.scrape.center/detail/53', '蝙蝠侠：黑暗骑士崛起 - The Dark Knight Rises', '["剧情", "动作", "科幻", "惊悚", "犯罪"]', '美国、英国', 165, '2012-08-27', 'https://p0.meituan.net/movie/f7f4b4099773268f8290ed033f49dc01377512.jpg@464w_644h_1e_1c', '八年前，蝙蝠侠（克里斯蒂安·贝尔 饰）在黑夜中销声匿迹，一瞬间，他从一位大英雄变成了一个流亡者。因涉嫌杀害地区检察官“双面人”哈维·登特（艾伦·艾克哈特 饰），黑暗骑士和戈登警长（加里·奥德曼 饰）为了大局着想，牺牲了自己的一切。一时间，他们的努力也一度奏效。在打击犯罪的“登特行动”的重压之下，高谭市的犯罪活动有所遏制。　　但这一切随着狡猾的盗贼猫女（安妮·海瑟薇 饰）的到来发生了改变，她这次的出现肩负着神秘任务。然而危险却不止于此。一个名叫贝恩（汤姆·哈迪  饰），脸戴面具的恐怖分子出现了，他对高谭市的恐怖计划迫使布鲁斯停止了自我放逐。但即使他重新披上蝙蝠侠的战袍，可能也不是贝恩的对手……', '[{"name": "克里斯托弗·诺兰", "image": "https://p1.meituan.net/movie/6efb32d3881c82b1503a0a923de500b6152536.jpg@128w_170h_1e_1c"}]', '[{"name": "克里斯蒂安·贝尔", "role": "饰：布鲁斯·韦恩,蝙蝠侠 The Batman", "image": "https://p1.meituan.net/moviemachine/9a631b74966202bd23cf47c7d36c157d44740.jpg@128w_170h_1e_1c"}, {"name": "迈克尔·凯恩", "role": "饰：阿尔弗莱德 Alfred", "image": "https://p0.meituan.net/movie/455ed426d5ea2fb7a31a80d6c4eebdfa53569.jpg@128w_170h_1e_1c"}, {"name": "加里·奥德曼", "role": "饰：吉姆·戈登 Jim Gordon", "image": "https://p0.meituan.net/movie/9f1945dbc62b6959cba7e2d44b09fb94108912.jpg@128w_170h_1e_1c"}, {"name": "安妮·海瑟薇", "role": "饰：瑟琳娜·凯尔,猫女 Selina Kyle,Catwoman", "image": "https://p0.meituan.net/moviemachine/ac5161756bb66857875275b2f445451f171963.jpg@128w_170h_1e_1c"}, {"name": "汤姆·哈迪", "role": "饰：贝恩 Bane", "image": "https://p1.meituan.net/movie/2d2d29aed8ee8aa1768cdf268eb41b0d86228.jpg@128w_170h_1e_1c"}, {"name": "约瑟夫·高登-莱维特", "role": "饰：约翰·布莱克 John Blake", "image": "https://p1.meituan.net/movie/de7e64c9a5c8bfeaef8a2021b4b2f2e855589.jpg@128w_170h_1e_1c"}, {"name": "摩根·弗里曼", "role": "饰：卢修斯·福克斯 Lucius Fox", "image": "https://p1.meituan.net/movie/10f3327ce886885f809c23d0adb67fb049302.jpg@128w_170h_1e_1c"}, {"name": "玛丽昂·歌迪亚", 