ie/1c04febdf9b74be45f656224d69b524d159440.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/63e669aa56e5f39963ddcb1fa803432779666.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/fb2ca4976790d746cee60384078e5bdc86069.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/7203eb18b337979e4f3c8adfef74c47b83332.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/585d7238d7a6ac5f05d060a04b8850ae173180.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/538df3e5201bf83cce6628f7f9d0c15e141041.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/081be0aa2da7515a2a4ed6da7bfda618203486.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/d4d9aee5dfd7c7af163f93d252b5d2d2196193.jpg@106w_106h_1e_1c", "https://p1.meituan.net/movie/987d28b08d8a2fb2e89699e4c09350b4192411.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/341f640dee24022696b2db4a93a91024152233.jpg@106w_106h_1e_1c", "https://p0.meituan.net/movie/2661b05ad4200625d3ee9a5b9978a7bd298520.jpg@106w_106h_1e_1c"]');
INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (1, 1, 'https://ssr1.scrape.center/detail/1', '霸王别姬 - Farewell My Concubine', '["剧情", "音乐"]', '中国内地、中国香港', 171, '1993-07-26', 'https://p0.meituan.net/movie/ce4da3e03e655b5b88ed31b5cd7896cf62472.jpg@464w_644h_1e_1c', '影片借一出《霸王别姬》的京戏，牵扯出三个人之间一段随时代风云变幻的爱恨情仇。段小楼（张丰毅 饰）与程蝶衣（张国荣 饰）是一对打小一起长大的师兄弟，两人一个演生，一个饰旦，一向配合天衣无缝，尤其一出《霸王别姬》，更是誉满京城，为此，两人约定合演一辈子《霸王别姬》。但两人对戏剧与人生关系的理解有本质不同，段小楼深知戏非人生，程蝶衣则是人戏不分。段小楼在认为该成家立业之时迎娶了名妓菊仙（巩俐 饰），致使程蝶衣认定菊仙是可耻的第三者，使段小楼做了叛徒，自此，三人围绕一出《霸王别姬》生出的爱恨情仇战开始随着时代风云的变迁不断升级，终酿成悲剧。', '[{"name": "克里斯托夫·巴拉蒂"}]', '[{"name": "张国荣", "role": "饰：程蝶衣", "image": "https://p0.meituan.net/movie/5de69a492dcbd3f4b014503d4e95d46c28837.jpg@128w_170h_1e_1c"}, {"name": "张丰毅", "role": "饰：段小楼", "image": "https://p0.meituan.net/movie/35e74707f69da838d7ba3422b8f6579840705.jpg@128w_170h_1e_1c"}, {"name": "巩俐", "role": "饰：菊仙", "image": "https://p1.meituan.net/moviemachine/b650dcb00c40356934a275515217850f191104.jpg@128w_170h_1e_1c"}, {"name": "吕齐", "role": "饰：关师傅", "image": "https://p1.meituan.net/movie/30e12a78b5e61916edb1e33ce6fec19b34794.jpg@128w_170h_1e_1c"}, {"name": "英达", "role": "饰：戏园老板", "image": "https://p0.meituan.net/movie/cdedec80554d04a6139dc5270f5e7b5b35118.jpg@128w_170h_1e_1c"}, {"name": "葛优", "role": "饰：袁四爷", "image": "https://p1.meituan.net/moviemachine/cfda0fb23f4415f4ccfe6552d5e2ee0a140241.jpg@128w_170h_1e_1c"}, {"name": "雷汉", "role": "饰：小四（成年）", "image": "https://p1.meituan.net/movie/d71397318a61a90f8f8ebd859a8c4abd11511.jpg@128w_170h_1e_1c"}, {"name": "童弟", "role": "饰：张公公", "image": "https://p0.meituan.net/movie/7a27a05cdb2a825616fea6406807feee10403.jpg@128w_170h_1e_1c"}, {"name": "尹治", "role": "饰：小豆子（少年）", "image": "https://p1.meituan.net/movie/9cdb1f2c1d73e76390f75a3d2f708df930031.jpg@128w_170h_1e_1c"}, {"name": "马明威", "role": "饰：小豆子（童年