INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (8, 11, 'https://ssr1.scrape.center/detail/11', 'V字仇杀队 - V for Vendetta', '["剧情", "动作", "科幻", "惊悚"]', '美国、英国、德国', 132, '2005-12-11', 'https://p1.meituan.net/movie/06ec3c1c647942b1e40bca84036014e9490863.jpg@464w_644h_1e_1c', '在未来英国的极权统治下，一位名叫伊维（娜塔莉·波特曼 饰）的年轻女子死里逃生，被一名叫V（雨果·维文 饰）的带面具怪人救出，V具有不可思议的战斗能力，其诡计变化多端，手段极其残忍。当他摧毁了伦敦两个标志性建筑并控制了被政府摆布的电视广播以后，一场革命爆发了。市民被煽动，并企图以起义来对抗政府的专治与镇压。不料，伊维意外的得知了V的神秘背景，同时也发现了关于自己的一个巨大真相，给人们带来的正义与自由却把整个社会推向残酷与堕落的深渊。', '[{"name": "詹姆斯·麦克特格", "image": "https://p0.meituan.net/movie/c2bda48e9c2e0c3a4345f76bd4a4f06c39423.jpg@128w_170h_1e_1c"}, {"name": "詹姆斯·麦克提格", "image": "https://p0.meituan.net/movie/e133ceb7290073f691d56f016c9e2e1a35946.jpg@128w_170h_1e_1c"}]', '[{"name": "娜塔莉·波特曼", "role": "饰：伊维 Evey", "image": "https://p0.meituan.net/moviemachine/15dff7480f937b55205148efbdb980ef184873.jpg@128w_170h_1e_1c"}, {"name": "雨果·维文", "role": "饰：V,威廉·洛克伍德 V,William Rockwood", "image": "https://p0.meituan.net/movie/ad36d85b06b564c47467194ed8227caf44912.jpg@128w_170h_1e_1c"}, {"name": "斯蒂芬·瑞", "role": "饰：芬奇 Finch", "image": "https://p1.meituan.net/movie/48a83ef0da1f369e9bc233cd664bb32e45872.jpg@128w_170h_1e_1c"}, {"name": "斯蒂芬·弗雷", "role": "饰：迪特里克 Deitrich", "image": "https://p0.meituan.net/movie/308aab15a29e0c4318780a1da491becb32072.jpg@128w_170h_1e_1c"}, {"name": "约翰·赫特", "role": "饰：亚当·苏特勒 Adam Sutler", "image": "https://p0.meituan.net/movie/7d7543f615cb27d6839d8252f1c03ea712634.jpg@128w_170h_1e_1c"}, {"name": "蒂姆·皮戈特-史密斯", "role": "饰：克里迪 Creedy", "image": "https://p0.meituan.net/movie/efe7ef5a89a4c70ad1a12bbf3d20e6fc37569.jpg@128w_170h_1e_1c"}, {"name": "拉珀特·格雷夫斯", "role": "饰：多米尼克 Dominic", "image": "https://p0.meituan.net/movie/e8b155259b5b2c0c1e9b0c0cc85d0b9747911.jpg@128w_170h_1e_1c"}, {"name": "罗杰·阿拉姆", "role": "饰：路易