INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (9, 12, 'https://ssr1.scrape.center/detail/12', '少年派的奇幻漂流 - Life of Pi', '["剧情", "奇幻", "冒险"]', '美国、中国台湾、英国、加拿大', 127, '2012-11-22', 'https://p0.meituan.net/movie/34998e31c6d07475f1add6b8b16fd21d192579.jpg@464w_644h_1e_1c', '《少年派的奇幻漂流》的故事开始于蒙特娄， 也结束于蒙特娄。一名在找寻灵感的作家，无意间得知了皮辛墨利多·帕帖尔的不可思议的故事。被大家称为派的男孩，成长于1970年代的印度朋迪榭里。他的父亲开了一家动物园，派整天与老虎、斑马、河马和其他异国动物为伍，对信仰、人和动物的本性自有一套看法。然而他试图与孟加拉国虎理查德·帕克交好的举动，却引来父亲勃然大怒。派的父亲当场以血淋淋的教训让他知道：动物与人的思考模式不同，一旦忘记这一点就会送命。这次的教训冲击了派对世界无止尽的好奇心，令他永远无法轻忽，最终甚至影响了他被迫经历的旅程。此时印度发生了全面性的改变，动摇了派的多采多姿的世界。在派17岁那一年，他的父母决定举家移民以追求更好的生活。移民能带来新世界的新冒险，却也代表派必须离开他的初恋情人。在选择移民加拿大之后，派的父母关闭动物园、收拾所有家当搭上一艘日籍货船。在船上，他们遇见一位残忍成性的法国厨师。当天深夜在茫茫大海中，原本令派感到刺激无比的暴风雨，才一瞬间就成了吞噬货船的大灾难。船沉了，然而派却奇迹似的活了下来。他搭着救生船在太平洋上漂流，而且有一名最令人意想不到的同伴－理查德·帕克。冒险的旅程开始了。而这头过去在派的面前展露本性的猛虎，则成了派的大敌。然而在学习共存的过程中，理查德·帕克逐渐成为派重返人世的最大希望。派与理查德·帕克面对许多无法想象的挑战， 包括大自然的壮阔以及无情袭击渺小救生船的狂暴。其中一场特别凶猛的暴风雨，为派带来精神上的体验，让他质疑神对他的安排。然而从头到尾，派都没有绝望。一本旧的求生手册、海上的生物光、壮观的飞鱼群在空中画出的虹弧、闪闪发亮的碧波、以及一头跃出海面的座头鲸，都能让派得到喜悦  。', '[{"name": "李安", "image": "https://p1.meituan.net/movie/a0ecc439461c5eae751978d16246a3bd43870.jpg@128w_170h_1e_1c"}]', '[{"name": "苏拉·沙玛", "role": "饰：少年派 Pi Patel", "image": "https://p1.meituan.net/movie/3f5e2a04e2ceb720ea92e8e558e2caef37341.jpg@128w_170h_1e_1c"}, {"name": "伊尔凡·可汗", "role": "饰：成年派 Adult Pi Patel", "image": "https://p0.meituan.net/movie/ee8799ccf2c44984a7ff2c8e107417c534655.jpg@128w_170h_1e_1c"}, {"name": "塔布", "role": "饰：派的母亲 Gita Patel", "image": "https://p0.meituan.net/movie/3fa3cde063996ff217b56e7b4602595754163.jpg@128w_170h_1e_1c"}, {"name": "拉菲·斯波", "role": "饰：作家 Writer", "image": "https://p1.meituan.net/movie/6cd5dd0cc49f1b922df4decac2cec83a40271.jpg@128w_170h_1e_1c"}, {"name": "阿尤什·坦东", "role": "饰：11,12岁的派 Pi Patel (11,12 Years)", "image": "https://p0.meituan.net/movie/dc5cd4fa93