INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (10, 13, 'https://ssr1.scrape.center/detail/13', '美丽心灵 - A Beautiful Mind', '["剧情", "传记"]', '美国', 135, '2001-12-13', 'https://p0.meituan.net/movie/7b7d1f8aa36d7a15463ce6942708a1a7265296.jpg@464w_644h_1e_1c', '英俊而又十分古怪的数学家约翰·纳什 （罗素·克劳饰）念研究生时便发明了他的博弈理论，短短26页的论文在经济、军事等领域产生深远的影响，他开始享有国际声誉。但纳什出众的直觉受到了精神分裂症的困扰，使他向学术上最高层次进军的辉煌历程发生了巨大改变。面对这个曾经击毁了许多人的挑战，纳什在深爱着他的妻子艾丽西亚 （ 詹妮弗·康纳利 饰）的相助下，与被认为是只能好转、无法治愈的疾病作斗争。经过十几年的不懈努力，完全通过意志的力量，他一如既往地坚持工作，并于1994年获得诺贝尔奖，他在博弈论方面颇具前瞻性的工作也成为20世纪最具影响力的理论。而纳什也成了一个不仅拥有美好情感，并具有美丽心灵的人  。', '[{"name": "朗·霍华德", "image": "https://p1.meituan.net/movie/37372b85c6ac6199475fada7b4009cb066903.jpg@128w_170h_1e_1c"}]', '[{"name": "罗素·克洛", "role": "饰：约翰·纳什 John Nash", "image": "https://p0.meituan.net/moviemachine/23a46161d6b8500593e73c1b2acd920e40086.jpg@128w_170h_1e_1c"}, {"name": "詹妮弗·康纳利", "role": "饰：艾莉西亚·纳什 Alicia Nash", "image": "https://p1.meituan.net/movie/acba313467461d1e05716c196543e67d54506.jpg@128w_170h_1e_1c"}, {"name": "艾德·哈里斯", "role": "饰：帕彻 Parcher", "image": "https://p0.meituan.net/movie/7a5201c422d9fcfd06c7ba8572b4418b53237.jpg@128w_170h_1e_1c"}, {"name": "克里斯托弗·普卢默", "role": "饰：罗森博士 Dr. Rosen", "image": "https://p0.meituan.net/movie/63181eeb1456f260295a748147f2131a79584.jpg@128w_170h_1e_1c"}, {"name": "保罗·贝坦尼", "role": "饰：查尔斯 Charles", "image": "https://p1.meituan.net/movie/5da047a0992ad1c0aca09f2e914767b937306.jpg@128w_170h_1e_1c"}, {"name": "亚当·戈德堡", "role": "饰：索尔 Sol", "image": "https://p1.meituan.net/movie/dcad85975932006ea2d510dde6da63df49837.jpg@128w_170h_1e_1c"}, {"name": "乔什·卢卡斯", "role": "饰：汉森 Hansen", "image": "https://p0.meituan.net/moviemachine/0493a7d2cbf7ce0f59712cf9e52f636737156.jpg@128w_170h_1e_1c"}, {"name": "朗·霍华德", "role": "饰：Man at Gouverners Ball       (uncredited)", "image": "https://p1.meitu