INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (58, 58, 'https://ssr1.scrape.center/detail/58', '断背山 - Brokeback Mountain', '["剧情", "爱情", "家庭"]', '美国、加拿大', 134, '2005-09-02', 'https://p0.meituan.net/movie/e71affe126eeb4f8bfcc738cbddeebc8288766.jpg@464w_644h_1e_1c', '1963年的灿烂夏日，怀俄明西部，年轻的牛仔杰克·特维斯特 （ 杰克·吉伦哈尔 饰）与恩尼斯·德尔玛 （ 希斯·莱杰 饰）因同为牧场主乔·阿桂尔 （ 兰迪·奎德 饰）打工而相识。杰克比较健谈，且骑术高超。恩尼斯自幼小父母双亡，性格内向寡语。人迹罕至的断臂山深处，高山牧场的放羊工作单调而艰苦，随时有遭遇野兽袭击的可能。供杰克与恩尼斯栖身的帐篷狭小得只能睡下一人，另一人不得不睡在露天篝火旁，起初二人各自放羊，少有交流。直到有一天，二人晚饭时喝多了酒，夜晚又分外寒冷，于是杰克与恩尼斯同帐共裘而眠。在酒精与荷尔蒙的作用下，他们之间发生了“不该发生的事”，空虚寂寥让两个19岁的青年彼此相爱了。一个人做饭，另一个放羊，篝火边长谈，帐篷内欢爱，同性间的爱情伴随着二人度过了人生中最美好的夏日时光。季节性的放牧工作结束后，迫于世俗的压力，杰克与恩尼斯依依不舍地踏上了各自的生活旅程，杰克凭着精湛的骑术成为了德州的竞技牛仔，依靠着妻子露琳 （ 安妮·海瑟薇 饰）家族的扶植而事业蒸蒸日上；留在牧场的恩尼斯迎娶了自幼相识的阿尔玛 （ 米歇尔·威廉姆斯 饰），每日为待哺的女儿奔忙，过着平凡清苦的日子。弹指间四年过去了，饱受相思之苦的杰克给恩尼斯寄去贺卡，说自己做生意外出时要路过怀俄明，希望能见上一面。重逢后的杰克与恩尼斯深情拥吻，时光的流失并未冲淡二人心中炽热的情感。在随后的十几年中，杰克与恩尼斯都定期约会钓鱼。表面上的婚姻让阿尔玛的内心苦楚不堪，她知道丈夫每年消失在断臂山中与老友杰克钓鱼的真正原因，而杰克与恩尼斯也经受着同性恋所招致的巨大偏见和世俗压力。最终厮守一生的愿望因杰克的意外身亡而落空。在杰克去世后，恩尼斯来到了杰克父母的农场，想把杰克的骨灰带回到二人初次相识的断臂山。在杰克的房间里，他发现了一个秘密：初识时他们各自穿过的衬衫被整齐地套在了同一个衣挂上。这个秘密让恩尼斯潸然泪下，他意识到杰克是多么爱他，自己又多么深爱杰克。但无论爱是怎样的浓烈，最终见证它的只有那座壮美苍郁的断臂山  。', '[{"name": "李安", "image": "https://p1.meituan.net/movie/a0ecc439461c5eae751978d16246a3bd43870.jpg@128w_170h_1e_1c"}]', '[{"name": "希斯·莱杰", "role": "饰：恩尼斯·德尔马 Ennis Del Mar", "image": "https://p0.meituan.net/movie/2465b4a5ce48e939ff94d9f7e5db41e626851.jpg@128w_170h_1e_1c"}, {"name": "杰克·吉伦哈尔", "role": "饰：杰克·崔斯特 Jack Twist", "image": "https://p0.meituan.net/movie/4f8084a86fbd65ec0c3f9e5e29a43c6946105.jpg@128w_170h_1e_1c"}, {"name": "米歇尔·威廉姆斯", "role": "饰：阿尔玛 Alma", "image": "https://p1.meituan.net/movie/acdb8cef0659b0cd2f054e8a523a386587293.jpg@128w_170h_1e_1c"}, {"name": "兰迪·奎德", "role": "饰：乔·阿吉雷 Joe Aguirre", "image": "https://p0.meituan.net/movie/ad6f211bb50724b93a7cb1e56045940135724