INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (81, 61, 'https://ssr1.scrape.center/detail/61', '飞屋环游记 - Up', '["剧情", "喜剧", "动画", "冒险"]', '美国', 96, '2009-08-04', 'https://p0.meituan.net/movie/f9356a376358f1576da3263d998eca7a94624.jpg@464w_644h_1e_1c', '卡尔（爱德华·阿斯纳 配音）是一个以卖气球为生的老头。自从老伴艾丽病逝之后，卡尔就变得沉默寡言起来。回想过去和艾丽在一起的日子，他们曾经多次都梦想着到南美洲的天堂瀑布去探险，可是为生计奔波的两人，却一直没有时间去完成这次旅行。难道就这样抱着遗憾过一辈子吗？这时候，政府计划要在卡尔所住的地方建造一幢摩天大楼，而在这里住了一辈子的卡尔根本不愿意搬家，但政府已经打算将这个难缠的钉子户送到养老院去。卡尔知道政府接下来的打算，他决定，要带着这幢保存了他一生回忆的屋子一起去旅行！在一大堆五颜六色气球的牵引下，整幢房子飞向了空中，卡尔朝着梦想之地进发——不过老卡尔却万万没有想到，这幢飞屋里闯入了一个不速之客，他就是9岁的胖乎乎小男孩罗素（乔丹·长井 配音）。这个小男孩骗老卡尔说是不小心才闯进来的，其实他是因为参加了野外探险者协会，而如果要成为高级会员，必须拿到一枚徽章，而拿到这枚徽章的条件就是帮助一位老人。罗素选中的帮助对象，就是脾气怪怪的老卡尔。老卡尔一开始并不想让罗素跟自己一起旅行，因此策划了很多办法想把这个讨厌的小孩从飞屋里丢下去，但此刻飞屋被卷进了暴风雨云里，卡尔和罗素一起度过了这个难关，罗素也告诉卡尔，他手中的GPS可以让卡尔更加精确的到达旅行的目的地——天堂瀑布。于是，这一老一少的旅途开始了。老不乐意的卡尔在路上还是想了不少办法踢走罗素，最后都无功而返，两人一路斗气地到了南美，在南美的丛林里，他们结识了很多平时根本见不到的动物，有长着长长大嘴的大鸟，还有会说话的小狗……他们都成为了飞屋里的旅客，随着卡尔和罗素一起旅行。眼看就要到目的地天堂瀑布了，爷孙两人却碰上了一个利欲熏心的探险家查尔斯（克里斯托弗·普卢默 配音），查尔斯认为卡尔和罗素破坏了他的好事，因此决定要拆掉他们的飞屋，让他们坠毁……究竟卡尔和罗素如何度过这场危机，顺利地到达天堂瀑布呢？', '[{"name": "彼特·道格特", "image": "https://p1.meituan.net/movie/9d289fe1da507008011e7eb0a5adcfa832671.jpg@128w_170h_1e_1c"}, {"name": "鲍勃·彼德森", "image": "https://p1.meituan.net/movie/48bbab5c76b8e5f40521521c880e076e63878.jpg@128w_170h_1e_1c"}]', '[{"name": "爱德华·阿斯纳", "role": "饰：卡尔·弗雷德里克森 Carl Fredricksen", "image": "https://p1.meituan.net/movie/4a4b415285e48eef132544832aafb8b38750.jpg@128w_170h_1e_1c"}, {"name": "乔丹·长井", "role": "饰：罗素 Russell", "image": "https://p1.meituan.net/movie/e16c1a3377daa3c7f4283f73df11bfea44406.jpg@128w_170h_1e_1c"}, {"name": "鲍勃·彼德森", "role": "饰：道格 Dug", "image": "https://p1.meituan.net/movie/48bbab5c76b8e5f40521521c880e076e63878.jpg@128w_170h_1e_1c"}, {"name": "克里斯托弗·普卢默", "role": "饰：查尔斯 Charles Muntz", "image": "https://p0.meituan.net/m