INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (82, 62, 'https://ssr1.scrape.center/detail/62', '黑客帝国3：矩阵革命 - The Matrix Revolutions', '["动作", "科幻"]', '美国、澳大利亚', 129, '2003-11-05', 'https://p0.meituan.net/movie/2e383b5f5f306f10f9f26d9f1c28cf1d825537.jpg@464w_644h_1e_1c', '第二集中，尼奥（基努·里维斯 饰）没有能从摧毁内部“母体”，他的身体在真实世界的飞船上陷于昏迷，思想却被困在介于“母体”和真实世界的中间地带，这个地方由“火车人”控制。墨菲斯（劳伦斯·菲什伯恩 饰）和崔妮蒂（凯莉-安·摩丝 饰）等人知道了尼奥的情况，在守护天使的带领下，找到了“火车人”的控制者梅罗纹奇，经过一番激斗，将尼奥救了出来。此时，电子乌贼部队对锡安发起了猛烈的攻击，人类组织所有机甲战士展开顽强的抵抗，形势危在旦夕；尼奥和崔妮蒂驾驶了一艘飞船克服重重困难，到达机器城市，尼奥终于见到了机器世界的统治者“机器大帝”，双发谈判并达成了协议：尼奥除掉不受“母体”控制的史密斯，以换取锡安的和平。在“母体”中，尼奥和史密斯展开了关系人类生死存亡的最后决斗。', '[{"name": "拉娜·沃卓斯基", "image": "https://p1.meituan.net/movie/d36a3566044b8b7c188a36cecc83737243127.jpg@128w_170h_1e_1c"}, {"name": "莉莉·沃卓斯基", "image": "https://p1.meituan.net/moviemachine/b8f407e53cd3c625c11ec7c873afa26144335.jpg@128w_170h_1e_1c"}]', '[{"name": "基努·里维斯", "role": "饰：尼奥 Neo", "image": "https://p0.meituan.net/moviemachine/9b68d244fc10ea28442a34400cfcda34186909.jpg@128w_170h_1e_1c"}, {"name": "雨果·维文", "role": "饰：史密斯探员 Agent Smith", "image": "https://p0.meituan.net/movie/ad36d85b06b564c47467194ed8227caf44912.jpg@128w_170h_1e_1c"}, {"name": "凯瑞-安·莫斯", "role": "饰：崔妮蒂 Trinity", "image": "https://p0.meituan.net/movie/34c487cf8f9be28654342b4831b8ab3a8761.jpg@128w_170h_1e_1c"}, {"name": "劳伦斯·菲什伯恩", "role": "饰：墨菲斯 Morpheus", "image": "https://p1.meituan.net/movie/14d849ee247c5a55d8a76bfa6028b1ef145410.jpg@128w_170h_1e_1c"}, {"name": "玛丽·爱丽丝", "role": "饰：The Oracle", "image": "https://p0.meituan.net/movie/fd362351ffd50d95f99d3778177a3c7e126468.jpg@128w_170h_1e_1c"}, {"name": "凯特·宾汉", "role": "饰：Coat Check Girl", "image": "https://p1.meituan.net/movie/0c0f5d9497b4fe59201f55e2167c7b1a36870.jpg@128w_170h_1e_1c"}, {"name": "莫妮卡·贝鲁奇", "role": "饰：Persephone", "image": "https://p0.meituan.n