INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (83, 63, 'https://ssr1.scrape.center/detail/63', '速度与激情5 - Fast Five', '["动作", "犯罪"]', '美国', 130, '2011-05-12', 'https://p0.meituan.net/movie/845ce32778a1b3f258de089f91a3979b5766154.jpg@464w_644h_1e_1c', '随着这个充满着紧张刺激的各种飞车和爆炸场景的电影系列发展到第5个故事篇章，由此创造出的不仅仅是更加宏大的背景幕布，同时也是在将大众化的影响力扩充至全世界的各个角落，作为开创了这套冒险传奇的动作搭档，前警探布莱恩·奥康纳 （保罗·沃克饰）和曾坐过牢的多米尼克·特莱托 （范·迪塞尔饰）再一次聚首到了一起，因为他们发现自己置身在的是一个异常陌生的环境当中，一起走进了很有异域风情的里约热内卢的犯罪世界。当我们最后一次看到他们的时候，布莱恩和米娅·特莱托 （乔丹娜·布鲁斯特饰）帮助多米尼克摆脱了警方的扣押，然后一口气穿越了很多国家的边境，就为了躲避执法机构的围追堵截，如今，他们退却到了里约热内卢的一个秘密的角落，必须得想办法完成最后一项任务。他们别无选择，只能通过这样的手段去获取期盼已久的真正的自由，他们需要做的就是集结一个顶级的精英团队，全部都是由他们最为信赖且视作家人的朋友组成的，他们需要共同密谋的是一起价值1亿美元的疯狂的抢劫案——多米尼克和布莱恩知道这是他们最后的机会，可以帮助他们永远地摆脱邪恶且堕落的商人赫南·雷耶斯 （乔奎姆·德·阿尔梅达饰）的控制，不过，他并不是惟一一个紧紧追随在他们身后的敌人。 顽固又强悍的联邦特工卢克·霍布斯 （道恩·强森饰）是永远不会让敌人从自己眼前溜走的，当他接受委派追捕多米尼克与布莱恩的时候，他和他的突击队将会不惜一切代价完成任务。可是，他们来到巴西之后，卢克却陷入到了迷惑当中，因为他发现自己已经没办法明确地分辨出，谁是好人，谁又是坏人，他只能依靠自己的本能来完成这次行动了，而且还得抢在别人的前面才有可能成功  。', '[{"name": "林诣彬", "image": "https://p0.meituan.net/moviemachine/c2ed85bb4ae60329093345e97fdf3f0f43112.jpg@128w_170h_1e_1c"}]', '[{"name": "范·迪塞尔", "role": "饰：多米尼克 Dominic Toretto", "image": "https://p0.meituan.net/movie/79ef14565960d0ed9d352ca483edd7bd42454.jpg@128w_170h_1e_1c"}, {"name": "保罗·沃克", "role": "饰：布莱恩 Brian OConner", "image": "https://p1.meituan.net/movie/dee8cb75b5fecaacfbdf60dcc1f9d6b632677.jpg@128w_170h_1e_1c"}, {"name": "道恩·强森", "role": "饰：卢克 Hobbs", "image": "https://p1.meituan.net/movie/7e3067d066c1e285b0cc17bfd5f1b34e108474.jpg@128w_170h_1e_1c"}, {"name": "乔丹娜·布鲁斯特", "role": "饰：Mia", "image": "https://p1.meituan.net/movie/28ef2f4c1202455bd1477ee308657c6055892.jpg@128w_170h_1e_1c"}, {"name": "泰瑞斯·吉布森", "role": "饰：Roman", "image": "https://p0.meituan.net/movie/db6c1f8d667cc0018c43042499b8dfc143451.jpg@128w_170h_1e_1c"}, {"name": "克里斯托弗·布莱恩·布里奇斯"