INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (84, 64, 'https://ssr1.scrape.center/detail/64', '勇敢的心 - Braveheart', '["剧情", "动作", "传记", "历史", "战争"]', '美国', 177, '1995-05-18', 'https://p1.meituan.net/movie/f8e9d5a90224746d15dfdbd53d4fae3d209420.jpg@464w_644h_1e_1c', '在 威廉·华莱士还是孩子的时候，他的父亲，苏格兰的英雄马索·华莱士在与英军的斗争中牺牲了。幼小的他在父亲的好友的指导下学习文化和武术。光阴似箭，英王爱德华为巩固在苏格兰的统治，颁布法令允许英国贵族在苏格兰享有结婚少女的初夜权，以便让贵族效忠皇室。王子妃伊莎贝拉是个决断的才女，她知道这道法令会让英国贵族有意于苏格兰，但更会激起苏格兰人民的反抗。年轻的华莱士学成回到故乡，向美丽的少女梅伦求婚，愿意做一个安分守已的人。然而梅伦却被英军无理抢去，并遭杀害，华莱士终于爆发了。在广大村民高呼“英雄之后”的呼喊声中，他们揭竿而起，杀英兵宣布起义。苏格兰贵族罗伯想成为苏格兰领主， 在其父布斯的教唆下，假意与华莱士联盟。华莱士杀败了前来进攻的英军，苏格兰贵族议会封他为爵士，任命他为苏格兰 护国公。华莱士却发现这些苏格兰贵族考虑的只是自己的利益，丝毫不为人民和国家前途担心。爱德华为了缓和局势，派伊莎贝拉前去和谈。但由于英王根本不考虑人民的自由和平等，只想以收买华莱士为条件，和谈失败了。伊莎贝拉回去后才发觉和谈根本就是幌子，英王汇合了爱尔兰军和法军共同包围华莱士的苏格兰军队，她赶紧送信给华莱士。大军压境之下，贵族们慌作一团，华莱士领兵出战，混战一场，短兵相接中，他意外发现了罗伯竟与英王勾结，不禁倍受打击。伊莎贝拉为华莱士的豪情倾倒，来到驻地向他倾吐了自己的真情，两人陶醉在爱情的幸福之中。英王再次提出和谈。华莱士明知是圈套，但为了和平着想，他依旧答应前去。在爱丁堡布斯设计了阴谋抓住华莱士，并把他送交英王。罗伯对父亲的诡计感到怒不可遏，华莱士终于被判死刑。伊莎贝拉求情不成，在英王临死前，她告诉英王她怀的不是王子的血脉，而这个孩子不久将成为新的英王。华莱士刑前高呼“自由”震憾所有人。几星期后，在受封时，罗伯高呼前为华莱士报仇的口号，英勇地继承华莱士的遗志对抗英军  。', '[{"name": "梅尔·吉布森", "image": "https://p1.meituan.net/movie/598ece75cb3a7a0d970fba5c04d5822b52804.jpg@128w_170h_1e_1c"}]', '[{"name": "梅尔·吉布森", "role": "饰：威廉·华莱士 William Wallace", "image": "https://p1.meituan.net/movie/598ece75cb3a7a0d970fba5c04d5822b52804.jpg@128w_170h_1e_1c"}, {"name": "苏菲·玛索", "role": "饰：伊莎贝尔公主 Princess Isabelle", "image": "https://p0.meituan.net/movie/cdb021a78e3930d9456abfbc74a5a8c164803.jpg@128w_170h_1e_1c"}, {"name": "帕特里克·麦高汉", "role": "饰：国王爱德华一世 Longshanks - King Edward I", "image": "https://p1.meituan.net/movie/c04b9e5f87cd680e8be7bdd45fdb7a3535349.jpg@128w_170h_1e_1c"}, {"name": "凯瑟琳·麦克马克", "role": "饰：莫伦 Murron", "image": "https://p0.meituan.net/movie/0137bbcee07bcc8655d3cde906501d3051805.jpg@128w_170h_1e_1c"}, {"name":