INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (85, 65, 'https://ssr1.scrape.center/detail/65', '三傻大闹宝莱坞 - 3 Idiots', '["剧情", "喜剧", "爱情", "歌舞"]', '印度', 171, '2011-12-08', 'https://p1.meituan.net/movie/ca4a128a5a54d5b5e35ceba622636c831810197.jpg@464w_644h_1e_1c', '本片根据印度畅销书作家奇坦·巴哈特（Chetan Bhagat）的处女作小说《五点人》（Five Point Someone）改编而成。法兰（马德哈万 R Madhavan 饰）、拉杜（沙曼·乔希 Sharman Joshi 饰）与兰乔（阿米尔·汗 Aamir Khan 饰）是皇家工程学院的学生，三人共居一室，结为好友。在以严格著称的学院里，兰乔是个非常与众不同的学生，他不死记硬背，甚至还公然顶撞校长“病毒”（波曼·伊拉尼 Boman Irani 饰），质疑他的教学方法。他不仅鼓动法兰与拉杜去勇敢追寻理想，还劝说校长的二女儿碧雅（卡琳娜·卡普 Kareena Kapoor 饰）离开满眼铜臭的未婚夫。兰乔的特立独行引起了模范学生“消音器”（奥米·维嘉 Omi Vaidya 饰）的不满，他约定十年后再与兰乔一决高下，看哪种生活方式更能取得成功。 本片获孟买电影博览奖最佳影片、最佳导演、最佳配角（波曼·伊拉尼）、最佳剧本等六项大奖，并获国际印度电影协会最佳影片、最佳导演、最佳剧情、最佳摄影等十六项大奖。', '[{"name": "拉吉库马尔·希拉尼", "image": "https://p1.meituan.net/movie/632f70b8c488a65152aa77aa4604b77043490.jpg@128w_170h_1e_1c"}]', '[{"name": "阿米尔·汗", "role": "饰：兰乔 Rancho", "image": "https://p0.meituan.net/moviemachine/e4a015745a6702ddaa02ae22e3c3aab336493.jpg@128w_170h_1e_1c"}, {"name": "黄渤", "role": "饰：兰乔（国语配音）", "image": "https://p0.meituan.net/movie/c6594ef2705dcaf7d9df857d228b5e1645712.jpg@128w_170h_1e_1c"}, {"name": "卡琳娜·卡普", "role": "饰：皮娅 Pia", "image": "https://p1.meituan.net/movie/696715ddaa9955411604dc1acda28a3a29423.jpg@128w_170h_1e_1c"}, {"name": "汤唯", "role": "饰：皮娅（国语配音）", "image": "https://p0.meituan.net/moviemachine/d683d2e788ecc245da1946bc434c889e58890.jpg@128w_170h_1e_1c"}, {"name": "博曼·伊拉尼", "role": "饰：Viru Sahastrabudhhe", "image": "https://p0.meituan.net/movie/ea46f9a1f0a20a31306dddce5941b25f19290.jpg@128w_170h_1e_1c"}, {"name": "马德哈万", "role": "饰：法罕 Farhan Qureshi", "image": "https://p0.meituan.net/movie/35c3e13018fc95f4fdeb9be3105906ec10626.jpg@128w_170h_1e_1c"}, {"name": "沙尔曼·乔希", "role": "饰：莱吉 Raju Rastogi", "image": "https://p1.meituan.net/movie/568463