INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (86, 66, 'https://ssr1.scrape.center/detail/66', '闻香识女人 - Scent of a Woman', '["剧情"]', '美国', 157, '1992-12-23', 'https://p1.meituan.net/movie/8d7b0b902afd4ec1a3dd7a9c6149463c187734.jpg@464w_644h_1e_1c', '查理（克里斯·奥唐纳 饰）是一个普通的中学生，他因为见证着一件恶作剧但又不想出卖朋友，于是面临着一道艰难的选择题——要么坦白，要么被学校勒退。而史法兰（阿尔·帕西诺 饰）是一个退伍军官，因为意外失明，人生从顶点的辉煌滑落谷底。自从两人的人生有了交集，命运的转折慢慢清晰。史法兰打算结束失去了意义的生活，于是在查理的陪伴下，尽情享受着人生最后一趟出行。他吃最美味的佳肴，买光鲜的汽车，在狭窄的街道上飚车，住在豪华的套房里，跟随陌生女子的袅袅香水味，跳一段优雅性感的探戈……极乐的疯狂后，他拿枪对准了自己的头颅。然而，查理声嘶力竭的劝阻改变了一切，曙光亦渐渐在这个老人心中重新升起，二人情深如父子。史法兰在学校礼堂激昂演说，挽救了查理的前途，讽刺了学校的伪善。二人在互相鼓舞中得到重生。', '[{"name": "马丁·布莱斯特", "image": "https://p0.meituan.net/movie/b9d8a261b5216a3616048b1e05a46b7f29256.jpg@128w_170h_1e_1c"}]', '[{"name": "阿尔·帕西诺", "role": "饰：中校弗兰克·斯莱德 Lieutenant Colonel Frank Slade", "image": "https://p0.meituan.net/moviemachine/4015ce1b1bf3c66c46a7cb897a6dc66962381.jpg@128w_170h_1e_1c"}, {"name": "克里斯·奥唐纳", "role": "饰：查理·西姆斯 Charlie Simms", "image": "https://p1.meituan.net/movie/cd306c16f8160d77b21f34ef703e2f1f22545.jpg@128w_170h_1e_1c"}, {"name": "加布里埃尔·安瓦尔", "role": "饰：唐娜 Donna", "image": "https://p1.meituan.net/movie/354c08ff4b413babfdf0c04111381b4234423.jpg@128w_170h_1e_1c"}, {"name": "菲利普·塞默·霍夫曼", "role": "饰：乔治·威利斯 George Willis, Jr.", "image": "https://p1.meituan.net/movie/873a6e177726435a8cd1aef13aa53b6b45650.jpg@128w_170h_1e_1c"}, {"name": "布莱德利·惠特福德", "role": "饰：兰迪 Randy", "image": "https://p1.meituan.net/moviemachine/f9e81024debc7d163a3cbaac42638591173059.jpg@128w_170h_1e_1c"}, {"name": "托德·路易斯", "role": "饰：特伦特·波特 Trent Potter", "image": "https://p0.meituan.net/movie/f1b75aec886741c978e47a898e37711141003.jpg@128w_170h_1e_1c"}, {"name": "朗·埃达德", "role": "饰：官戈尔 Officer Gore", "image": "https://p1.meituan.net/movie/2523b718632768ca2c51f3af41f2f61b39050.jpg@128w_170h_1e_1c"}