INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (87, 67, 'https://ssr1.scrape.center/detail/67', '末代皇帝 - The Last Emperor', '["剧情", "传记", "历史"]', '英国、意大利、中国大陆、法国、美国', 163, '1987-10-23', 'https://p1.meituan.net/movie/21b9211eb1094af360842472018db634286646.jpg@464w_644h_1e_1c', '1950年的冬天，清王朝废帝溥仪 （尊龙饰），作为战犯从苏联被押回中国。火车抵达中苏边境的满洲里火车站后，溥仪认为此去性命难保，便溜进卫生间企图割腕自杀。中国战犯管理所所长 （英若诚饰）发现情况有异，急敲卫生间的门，敲门声使溥仪陷入了回忆。1908年的一个冬夜，清宫卫队长敲开了醇亲王府的大门，按慈禧太后 （卢燕饰）旨意把3岁的溥仪接进宫中教养，准备接位。 在香烟缭绕的坤宁宫内，即将咽气的慈禧接见了溥仪，告诉他要即日登基。在太和殿上隆重举行登基大典时，溥仪在大臣陈宝琛身上发现了一个装着蝈蝈的小笼子。他对蝈蝈的兴趣显然要超过几千名跪在他脚下的文武大臣。登基之后，溥仪成了世界上最缺少管教、也是最孤独的孩子。溥仪从回忆中惊醒过来。他也被管理所长救起，从此开始了接受审判、接受改造的囚徒生活  。', '[{"name": "贝纳尔多·贝托鲁奇", "image": "https://p1.meituan.net/moviemachine/01408be04b865e313c02e8cf99fb955b130086.jpg@128w_170h_1e_1c"}]', '[{"name": "尊龙", "role": "饰：溥仪（成年） Pu Yi (Adult)", "image": "https://p0.meituan.net/movie/3c23dfe0ed2ec3b84810e60484e47f2312816.jpg@128w_170h_1e_1c"}, {"name": "彼得·奥图尔", "role": "饰：庄士敦 Reginald Johnston (R.J.)", "image": "https://p0.meituan.net/movie/64e489be506b646cd59c5dd14a9e9e3512193.jpg@128w_170h_1e_1c"}, {"name": "陈冲", "role": "饰：婉容 Wan Jung", "image": "https://p1.meituan.net/movie/477facf04f4efadd211319719a4751a641858.jpg@128w_170h_1e_1c"}, {"name": "邬君梅", "role": "饰：文绣 Wen Hsiu", "image": "https://p1.meituan.net/movie/36c61f1a9b8a5cbb7c06b0bb6ab1c2df28622.jpg@128w_170h_1e_1c"}, {"name": "英若诚", "role": "饰：监狱长 The Governor", "image": "https://p0.meituan.net/movie/f7f66a28abc26069b9e56e8765a33b2330917.jpg@128w_170h_1e_1c"}, {"name": "黄自强", "role": "饰：陈宝琛 Chen Pao Shen", "image": "https://p1.meituan.net/movie/f9fe5c7216a63f477260b310c66332b737669.jpg@128w_170h_1e_1c"}, {"name": "卢燕", "role": "饰：慈禧太后 Tzu Hsui", "image": "https://p0.meituan.net/movie/82e8df42c096813ec532a6abf83b1acb58513.jpg@128w_170h_1e_1c"}, {"name": "陈凯歌", "role"