INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (89, 69, 'https://ssr1.scrape.center/detail/69', '大话西游之月光宝盒 - A Chinese Odyssey', '["喜剧", "爱情", "奇幻", "古装"]', '中国香港、中国大陆', 87, '2014-10-24', 'https://p0.meituan.net/movie/396266d8b711958841b3536a3fa7b868211445.jpg@464w_644h_1e_1c', '孙悟空（周星驰 饰）护送唐三藏（罗家英 饰）去西天取经路上，与牛魔王合谋欲杀害唐三藏，并偷走了月光宝盒，此举使观音萌生将其铲除心思，经唐三藏请求，孙悟空被判五百年后重新投胎做人赎其罪孽。五百年后孙悟空化身强盗头头至尊宝。当遇见预谋吃唐僧肉的妖怪姐妹蜘蛛精春三十娘（蓝洁瑛 饰）和白骨精白晶晶（莫文蔚 饰）时，因为五百年前孙悟空曾与白晶晶有过一段恋情，至尊宝与她一见钟情，但因菩提老祖将二人妖怪身份相告，至尊宝仍带领众强盗开始与二妖展开周旋，过程中，白晶晶为救至尊宝打伤春三十娘，自己也中毒受伤，为了救白晶晶，至尊宝去找春三十娘，遭白晶晶误会，绝望自杀，至尊宝开始用月光宝盒以期使时光倒流。', '[{"name": "刘镇伟", "image": "https://p0.meituan.net/movie/9a217ecaf62f1425ad9f231721d1a82737169.jpg@128w_170h_1e_1c"}]', '[{"name": "周星驰", "role": "饰：至尊宝,孙悟空", "image": "https://p0.meituan.net/movie/5cbe849bb17c8966a423ee015dc21aca41689.jpg@128w_170h_1e_1c"}, {"name": "莫文蔚", "role": "饰：白晶晶", "image": "https://p1.meituan.net/movie/7a8ec6da5a8612a25519550806545b2e52391.jpg@128w_170h_1e_1c"}, {"name": "吴孟达", "role": "饰：二当家", "image": "https://p1.meituan.net/movie/13d4357722d33b46a9fa52fbe8316f9633831.jpg@128w_170h_1e_1c"}, {"name": "蓝洁瑛", "role": "饰：蜘蛛精", "image": "https://p1.meituan.net/moviemachine/400ee552bb81817f80fd94bcaeed4d1435022.jpg@128w_170h_1e_1c"}, {"name": "朱茵", "role": "饰：紫霞", "image": "https://p0.meituan.net/movie/e08ccd949f407da4c5db2e783c4b7d0646124.jpg@128w_170h_1e_1c"}, {"name": "刘镇伟", "role": "饰：菩提老祖", "image": "https://p0.meituan.net/movie/9a217ecaf62f1425ad9f231721d1a82737169.jpg@128w_170h_1e_1c"}, {"name": "罗家英", "role": "饰：唐三藏", "image": "https://p1.meituan.net/movie/8c2b172e4b3b9a41f05b508fe90985d231462.jpg@128w_170h_1e_1c"}, {"name": "陆树铭", "role": "饰：牛魔王", "image": "https://p1.meituan.net/movie/aaf033c1c0e05588ca6627954e89d4a529516.jpg@128w_170h_1e_1c"}, {"name": "蔡少芬", "role": "饰：铁扇公主", "ima