INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (88, 68, 'https://ssr1.scrape.center/detail/68', '风之谷 - 風の谷のナウシカ', '["动画", "奇幻", "冒险"]', '日本', 117, '1998-10-22', 'https://p0.meituan.net/movie/4f9638ba234c3fb673f23a09968db875371576.jpg@464w_644h_1e_1c', '工业文明的高度发展，却最终带来灾难，一场为期7天的虫族毁灭战争摧毁了人类文明。一千年后，工业文明遗留下来的症结仍在困扰这个星球。带有强烈毒性的植物组成了令人望而却步的“腐海”森林，随着时间的推移，腐海有条不紊地向四周蔓延，蚕食周边世界。在一片腐海森林的旁边，居住着一群御风而行的人类。女主角娜乌茜卡和族人依靠海风的力量抵御着有毒孢子的侵蚀，过着平静祥和的生活。直到某一天，战火烧到了这里。西方强国特洛梅意欲重新建立人类霸权，他们计划统一周边诸国，然后向虫族发起总攻。另一方面，一千年前曾主导摧毁人类的上古怪兽“猛怪”重现人间。毁灭战争一触即发，人类的命运将会如何……', '[{"name": "宫崎骏", "image": "https://p1.meituan.net/movie/5d786f92d2049516338e7be0ea3fa4e048311.jpg@128w_170h_1e_1c"}]', '[{"name": "岛本须美", "role": "饰：风之谷（配音）  Nausicaä (voice)", "image": "https://p0.meituan.net/movie/c9e9cbb67835b1cf88ed88be35beea9336806.jpg@128w_170h_1e_1c"}, {"name": "永井一郎", "role": "饰：米兔（配音） Mito (voice)", "image": "https://p0.meituan.net/movie/ab64e84e4bdd0a6ca0b61c28c850c02528282.jpg@128w_170h_1e_1c"}, {"name": "坂本千夏", "role": "饰：男孩 A（配音） Boy A (voice)", "image": "https://p1.meituan.net/movie/d39dd140c0a2a4a42267a45b8f5340ca32136.jpg@128w_170h_1e_1c"}, {"name": "鳕子", "role": "饰：男孩B（配音） Boy B (voice)", "image": "https://p0.meituan.net/movie/ed7ca697f627d30e899dd97b3cba6e1636657.jpg@128w_170h_1e_1c"}, {"name": "榊原良子", "role": "饰：巴蒂尔（配音） Kushana (voice)", "image": "https://p1.meituan.net/movie/6c7c03018c58b4a26065b0f9a6dadf1f53250.jpg@128w_170h_1e_1c"}, {"name": "大塚芳忠", "role": "饰：Torumekia soldier (voice)", "image": "https://p0.meituan.net/movie/e569c3ec6bccc76d5dbd73453bf02ec16192.jpg@128w_170h_1e_1c"}, {"name": "纽威尔·亚历山大", "role": "饰：Additional voices (voice: English version)", "image": "https://p0.meituan.net/movie/04e86939ad87416acd2236a8ad6cb9f315383.jpg@128w_170h_1e_1c"}, {"name": "弗兰克·维尔克", "role": "饰：Gol (2004) (voice: Engli