INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (13, 14, 'https://ssr1.scrape.center/detail/14', '初恋这件小事 - สิ่งเล็กเล็กที่เรียกว่า...รัก', '["喜剧", "爱情"]', '泰国', 118, '2012-06-05', 'https://p1.meituan.net/movie/05bc2f0ccf97aacfa64fcac4f237cf8082385.jpg@464w_644h_1e_1c', '初中生小水（平采娜·乐维瑟派布恩 饰）相貌平平，家境一般，所以在学校里并不受重视。但是她心地善良，又有一群死党，日子过得倒也开心。某天，她遇见了帅气的学长阿亮（马里奥·毛瑞尔 饰），春心萌动，无 法遏制。她喜欢看他踢足球，看他拍照，如痴如狂。上英语课时，她不停地给死党传纸条 表达对阿亮的爱慕。然而，英语老师则指出她除了英语一无是处。回到家，叔叔从美国捎来了父亲的消息，说如果她能考全校第一，就可以去美国。于是，她按下决心要努力加油。某天，小水等人在买饮料时，碰到篮球队员蛮横插队。阿亮挺身而出，为她们教训了对方，并挨了校长的责骂。小水也第一次听说，阿亮的父亲因为射失点球而退役的事情，理解了他心中的隐痛。由于舞蹈队是给美女准备的，所以小水等一干姐妹准备在话剧社大展身手，没想到学长也来到这个社团。两人还扮演王子公主，他们的恋情会由此展开么？……', '[{"name": "普特鹏·普罗萨卡·那·萨克那卡林", "image": "https://p1.meituan.net/movie/1b7eab45fc6d2f7cbc214acd7695e98559395.jpg@128w_170h_1e_1c"}, {"name": "华森·波克彭", "image": "https://p0.meituan.net/movie/a473620cc3a66c4aea5abdffbc9f518443211.jpg@128w_170h_1e_1c"}]', '[{"name": "马里奥·毛瑞尔", "role": "饰：阿亮学长", "image": "https://p0.meituan.net/movie/879a79ffa6abcbfc1f2705a577048a935647.jpg@128w_170h_1e_1c"}, {"name": "平采娜·乐维瑟派布恩", "role": "饰：小水", "image": "https://p1.meituan.net/movie/bb49fd651350edc8703a04323c3ca7e556912.jpg@128w_170h_1e_1c"}, {"name": "阿查拉那·阿瑞亚卫考", "role": "饰：阿拓", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "华森·波克彭", "role": "饰：校长", "image": "https://p0.meituan.net/movie/a473620cc3a66c4aea5abdffbc9f518443211.jpg@128w_170h_1e_1c"}, {"name": "普特鹏·普罗萨卡·那·萨克那卡林", "role": "饰：阿亮爸爸", "image": "https://p1.meituan.net/movie/1b7eab45fc6d2f7cbc214acd7695e98559395.jpg@128w_170h_1e_1c"}, {"name": "Khachamach Promsaka Na Skolnakor", "role": "饰：小斌", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "皮拉瓦特·赫拉巴特", "role": "饰：Phol", "image": "https:/