INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (14, 15, 'https://ssr1.scrape.center/detail/15', '借东西的小人阿莉埃蒂 - 借りぐらしのアリエッティ', '["动画", "奇幻", "冒险"]', '日本', 94, '2010-07-17', 'https://p1.meituan.net/movie/640cc32445df972b066c9a04b194da141104515.jpg@464w_644h_1e_1c', '虽然患有心脏方面的疾病，但是少年翔（神木隆之介 配音）的父母依然对他疏于呵护。为了准备即将到来的手术，翔来到了位于偏远乡间的姨婆（竹下景子 配音）家静养。姨婆家位于一片幽静的丛林中，这是一幢有着上百年历史的欧式别墅。这里除了生活着姨婆和女佣阿春（树木希林 配音）外，还有一个奇特的三口之家，“借东西一族”——小人阿莉埃蒂（志田未来 配音）和她的爸爸（三浦友和 配音）妈妈（大竹忍 配音），他们生活在别墅的地板下，只有几公分高，过着不为人类察觉的生活。遇到所需的日常用品时，便会在夜深人静之时偷偷潜入厨房借出来。翔无疑中瞥见阿莉埃蒂的身影，他有心接近这些传说中的小人，却不知不觉打扰了他们的生活……', '[{"name": "米林宏昌", "image": "https://p1.meituan.net/movie/ccc0d4f7b5733a27685080f0301e423c27517.jpg@128w_170h_1e_1c"}]', '[{"name": "志田未来", "role": "饰：阿莉埃蒂", "image": "https://p1.meituan.net/moviemachine/0457b26152f31818bc5d3bb7e482e45f39663.jpg@128w_170h_1e_1c"}, {"name": "神木隆之介", "role": "饰：翔", "image": "https://p1.meituan.net/movie/5a995164858cbc247dc33e89b24e5cbc44413.jpg@128w_170h_1e_1c"}, {"name": "大竹忍", "role": "饰：荷米莉", "image": "https://p0.meituan.net/movie/c494715757f1d40767438bd070e6314042342.jpg@128w_170h_1e_1c"}, {"name": "三浦友和", "role": "饰：波德", "image": "https://p0.meituan.net/movie/61429a258d3066ae8a1ebd24144061f232587.jpg@128w_170h_1e_1c"}, {"name": "竹下景子", "role": "饰：贞子", "image": "https://p1.meituan.net/movie/0727e647f1364bd9652c3635681d141618893.jpg@128w_170h_1e_1c"}, {"name": "树木希林", "role": "饰：春", "image": "https://p1.meituan.net/movie/3bba97f9209d19d13795778612011a6639760.jpg@128w_170h_1e_1c"}, {"name": "藤原龙也", "role": "饰：斯莱碧", "image": "https://p1.meituan.net/moviemachine/7ed55bf8046572a3d588eb12d74f0dd247697.jpg@128w_170h_1e_1c"}, {"name": "威尔·阿奈特", "role": "饰：Pod (voice: English version)", "image": "https://p0.meituan.net/moviemachine/267ff8641cc17b13763e2ac42b634c89195522.jpg@128w_170h_1e_1c"}, {"name"