INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (17, 17, 'https://ssr1.scrape.center/detail/17', '美丽人生 - La vita è bella', '["战争", "剧情", "爱情"]', '意大利', 116, '2020-01-03', 'https://p1.meituan.net/movie/580d81a2c78bf204f45323ddb4244b6c6821175.jpg@464w_644h_1e_1c', '犹太青年圭多（罗伯托·贝尼尼 饰）邂逅美丽的女教师朵拉（尼可莱塔·布拉斯基 饰），他彬彬有礼的向多拉鞠躬：“早安！公主！”历经诸多令人啼笑皆非的周折后，天遂人愿，两人幸福美满的生活在一起。然而好景不长，法西斯政权下，圭多和儿子被强行送往犹太人集中营。多拉虽没有犹太血统，毅然同行，与丈夫儿子分开关押在一个集中营里。聪明乐天的圭多哄骗儿子这只是一场游戏，奖品就是一辆大坦克，儿子快乐、天真的生活在纳粹的阴霾之中。尽管集中营的生活艰苦寂寞，圭多仍然带给他人很多快乐，他还趁机在纳粹的广播里问候妻子：“早安！公主！”法西斯政权即将倾覆，纳粹的集中营很快就要接受最后的清理，圭多编给儿子的游戏该怎么结束？他们一家能否平安的度过这黑暗的年代呢？', '[{"name": "罗伯托·贝尼尼", "image": "https://p1.meituan.net/moviemachine/9936db0f423201251cdcfcf290f521b842526.jpg@128w_170h_1e_1c"}]', '[{"name": "罗伯托·贝尼尼", "role": "饰：圭多 Guido Orefice", "image": "https://p1.meituan.net/moviemachine/9936db0f423201251cdcfcf290f521b842526.jpg@128w_170h_1e_1c"}, {"name": "尼可莱塔·布拉斯基", "role": "饰：朵拉 Dora", "image": "https://p0.meituan.net/movie/d51edf48594286f082d797e01cf4b81b54397.jpg@128w_170h_1e_1c"}, {"name": "乔治·坎塔里尼", "role": "饰：乔舒亚 Giosué Orefice", "image": "https://p0.meituan.net/movie/f604e61290c02e2174a0fc19461e55ac53903.jpg@128w_170h_1e_1c"}, {"name": "朱斯蒂诺·杜拉诺", "role": "饰：齐奥 Zio", "image": "https://p0.meituan.net/moviemachine/0a8d40c6b429dde4f561e0623124275c48155.jpg@128w_170h_1e_1c"}, {"name": "赛尔乔·比尼·布斯特里克", "role": "饰：费鲁乔·帕皮尼 Ferruccio Papini", "image": "https://p0.meituan.net/moviemachine/e4fc29a359e0e4f3f901bde6b6fc066346416.jpg@128w_170h_1e_1c"}, {"name": "玛丽萨·帕雷德斯", "role": "饰：马德·雷迪·多拉 Madre di Dora", "image": "https://p0.meituan.net/moviemachine/3cd5c462f398b05b1d889fb2bf435cf649252.jpg@128w_170h_1e_1c"}, {"name": "霍斯特·布赫霍尔茨", "role": "饰：医生莱辛 Doctor Lessing", "image": "https://p1.meituan.net/movie/9feaa3f7e9e2c674154be9841032882368653.jpg@128w_170h_1e_1c"}, {"name