INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (18, 18, 'https://ssr1.scrape.center/detail/18', '海上钢琴师 - La leggenda del pianista sull''oceano', '["剧情", "爱情", "音乐"]', '意大利', 126, '2019-11-15', 'https://p0.meituan.net/movie/609e45bd40346eb8b927381be8fb27a61760914.jpg@464w_644h_1e_1c', '1900年的第一天，往返于欧美两地的邮轮Virginian号上，负责邮轮上添加煤炭的工人丹尼·博德曼 （比尔·努恩饰）在头等舱上欲捡拾有钱人残留下来的事物时，却意外的在钢琴上发现一个被遗弃的新生儿，装在TD牌柠檬的空纸箱内。由于坚信“TD”正代表了Thanks Danny的缩写，于是丹尼不顾其他工人的嘲笑，独立抚育这个婴儿，并为了纪念这特别的一天，将他取名为：1900。海上出生的1900 （蒂姆·罗斯饰），在陆地上却是个从未存在的人，没有亲人、没有户籍，也没有国籍，大海便是他的摇篮，而他也随着Virginian号往返靠泊各个码头，逐渐长大。然而好景不常，一次的海上意外事件，造成抚养1900的丹尼意外丧生，幸而奇迹似的，某天深夜船上的众人被优美的琴声所惊醒，循着琴声而往，居然是无师自通的1900在钢琴前忘我的演奏着，动人的旋律打动了众人，从此，1900展开了在海上弹奏钢琴的旅程，也吸引了愈来愈多慕名而来的旅客。 　　马克斯 （ 普路特·泰勒·文斯 饰）在因缘际会下来到Virginian号加入乐队伴奏，也因此见识到这位传说中的海上钢琴师1900，两人因此结为好友。而1900在与发明爵士乐的传奇钢琴手杰利同船竞技钢琴琴艺之后，声势更是如日中天。但尽管马克斯再三鼓励1900下船去向全世界展露他的天赋，1900却始终未曾踏足陆地一步。直到他在为唱片公司录制个人专辑时，意外见到船舱之外清秀动人的女孩，并在感动之余创作了《1900''s Theme》。随着女孩的下船离去，1900的心开始波动  。', '[{"name": "朱塞佩·托纳多雷", "image": "https://p0.meituan.net/movie/0b1f9ba6fe08248d97063e1fcfc9e36e51684.jpg@128w_170h_1e_1c"}]', '[{"name": "蒂姆·罗斯", "role": "饰：1900 Danny Boodmann T.D. Lemon Nineteen Hundred ''1900''", "image": "https://p1.meituan.net/movie/6d7d09c17121dafefe35432a53f2fae337135.jpg@128w_170h_1e_1c"}, {"name": "比尔·努恩", "role": "饰：丹尼 Danny Boodmann", "image": "https://p1.meituan.net/movie/bcd77409be1e136811067d40de3bfd4723657.jpg@128w_170h_1e_1c"}, {"name": "克兰伦斯·威廉姆斯三世", "role": "饰：莫顿 ''Jelly Roll'' Morton", "image": "https://p0.meituan.net/moviemachine/5c1a88039f6dcb4414bb842c4680c97573696.jpg@128w_170h_1e_1c"}, {"name": "普路特·泰勒·文斯", "role": "饰：麦克斯 Max Tooney", "image": "https://p1.meituan.net/movie/a5855c6e236fc1e37ab25d456674c81922676.jpg@128w_170h_1e_1c"}, {"name": "梅兰尼·蒂埃里", "role": "饰：女孩 The Girl", "image": "https://p0.meituan.net/movie/40d