INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (45, 34, 'https://ssr1.scrape.center/detail/34', '英雄本色 - A Better Tomorrow', '["剧情", "动作", "犯罪"]', '中国香港', 95, '2017-11-17', 'https://p0.meituan.net/movie/3e5f5f3aa4b7e5576521e26c2c7c894d253975.jpg@464w_644h_1e_1c', '宋子豪（狄龙 饰）与Mark（周润发 饰）是一个国际伪钞集团之重要人物，也是情如手足的挚友。宋子豪之弟宋子杰（张国荣 饰）刚刚考入警官学校，其女友钟柔（朱宝意 饰）聪明敏慧，对子杰情深一片。一次，宋子豪带手下谭成（李子雄 饰）去台北与当地黑帮作伪钞交易。不料谭成早已勾结台北黑帮，出卖子豪。在一场枪战中宋子豪受伤，被闻讯而来的警察捕获入狱。Mark得知宋子豪被捕，孤身一人赴台北击毙黑帮头目，自己也身负重伤，艰难地逃离现场。与此同时，台湾黑帮唯恐子豪在狱中向警方泄密，派人至香港绑架子豪之父，混战中老父丧命。宋子豪的弟弟子杰得知兄长原为伪钞集团头目，老父为之而死，遂对子豪及黑社会恨之入骨，决心除暴安良。三年后，宋子豪出狱回到香港，决心弃暗投明，但得不到宋子杰的谅解。当年出卖宋子豪的谭成现已成为老大。他假惺惺地要求宋子豪合作，遭到拒绝，便设计加害宋子杰。宋子豪忍无可忍，联合Mark盗取谭成制造伪钞的电脑软盘，随即交给宋子杰。但同时佯称以软盘与谭成做交易，计划在交易时活捉谭成。岂料谭成早有准备，双方在码头展开枪战。这时，宋子杰也驾车赶来，激战中Mark不幸身亡。警察蜂拥而至，包围了码头。为了不连累宋子杰，宋子豪开枪击毙谭成后，从宋子杰身上取下手铐自缚，向警察自首。两兄弟终于言归于好。', '[{"name": "吴宇森", "image": "https://p0.meituan.net/movie/ef9ed808de1a621eb7473235803f644241848.jpg@128w_170h_1e_1c"}]', '[{"name": "狄龙", "role": "饰：宋子豪", "image": "https://p1.meituan.net/movie/fa1fe623b66fa23d309378aad2691c0731017.jpg@128w_170h_1e_1c"}, {"name": "张国荣", "role": "饰：宋子杰", "image": "https://p0.meituan.net/movie/5de69a492dcbd3f4b014503d4e95d46c28837.jpg@128w_170h_1e_1c"}, {"name": "周润发", "role": "饰：小马哥 Mark", "image": "https://p0.meituan.net/movie/4bec899956ac27c57686c441515edaa647367.jpg@128w_170h_1e_1c"}, {"name": "朱宝意", "role": "饰：Jackie", "image": "https://p1.meituan.net/movie/2a08acfcac0ff2f73426f2d47d4dc1f625378.jpg@128w_170h_1e_1c"}, {"name": "李子雄", "role": "饰：谭成", "image": "https://p0.meituan.net/moviemachine/6939e8cbf85fcacf0dde0d1741669f7b170375.jpg@128w_170h_1e_1c"}, {"name": "曾江", "role": "饰：坚叔", "image": "https://p1.meituan.net/movie/7bc8243c92f587e88cfcef5d6c8b854241667.jpg@128w_170h_1e_1c"}, {"name": "石燕子", "role": "饰：姚先生", "image": "https://p0.meituan.net/m