INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (33, 43, 'https://ssr1.scrape.center/detail/43', '小鞋子 - بچههای آسمان', '["剧情", "家庭"]', '伊朗', 89, NULL, 'https://p1.meituan.net/movie/135c612860fae899df2220149664d97a173555.jpg@464w_644h_1e_1c', '家境贫寒的男孩Ali（Amir Farrokh Hashemian）帮妹妹Zahra（Bahare Seddiqi）取修补好的鞋子时，不慎将鞋子弄丢，为了不被父（Mohammad Amir Naji）、母（Fereshte Sarabandi ）责罚，他央求Zahra暂时保密，说两人可以替换着穿他的鞋子上学，并答应一定会帮她买双新鞋子。Ali原本指望用他和父亲进城打工挣的钱帮Zahra买双新鞋，父亲的意外受伤打消了他的美梦。看到全市长跑比赛季军的奖品是一双运动鞋时，Ali决定参加比赛，但是他错过了报名日期。几经哀求，老师（Dariush Mokhtari ）破例让实力出众的Ali参加了比赛。比赛场上，Ali不断提醒自己，一定要得第三名！', '[{"name": "马基德·马基迪", "image": "https://p1.meituan.net/movie/34bf92cf8149f16d527adf60adabda1c43524.jpg@128w_170h_1e_1c"}]', '[{"name": "默罕默德·阿米尔·纳吉", "role": "饰：Ali''s Father", "image": "https://p1.meituan.net/movie/aada7652b113887ea0553485ac2e4ee329811.jpg@128w_170h_1e_1c"}, {"name": "Kamal Mirkarimi", "role": "饰：Assistant", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Behzad Rafi", "role": "饰：Trainer", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "克里斯托弗·马利基", "role": "饰：Salt Seller", "image": "https://p0.meituan.net/movie/738d249b63550a002f244a049451bb4715410.jpg@128w_170h_1e_1c"}, {"name": "纳菲丝·贾法-穆罕默迪", "role": "饰：Roya", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "巴哈丽·西迪奇", "role": "饰：Zahra", "image": "https://p1.meituan.net/movie/fcbdb8c65fcd87a5293b21a382d815ad23822.jpg@128w_170h_1e_1c"}, {"name": "法拉赫阿米尔·哈什米安", "role": "饰：Ali", "image": "https://p0.meituan.net/movie/ef91989624d3b743a99c6f20116b742816261.jpg@128w_170h_1e_1c"}, {"name": "Mohammad-Hasan Hosseinian", "role": "饰：Roya''s Father", "image": "https://p1.meituan.net/mmdb/3a20