INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (34, 44, 'https://ssr1.scrape.center/detail/44', '熔炉 - 도가니', '["剧情"]', '韩国', 125, '2011-09-22', 'https://p1.meituan.net/movie/2a0783b4fd95566568f24adfad2181bb5392280.jpg@464w_644h_1e_1c', '来自首尔的哑语美术老师仁浩（孔宥 饰）来到雾津，应聘慈爱聋哑人学校。天降大雾，他意外撞车，维修时邂逅了人权组织成员柔珍（郑有美 饰）。仁浩妻子早亡，8岁女儿天生哮喘由祖母照看，所以他不辞辛苦谋职养家。然而，双胞胎的校长与教导主任竟逼仁浩索贿5千万韩元。同时，仁浩逐渐发现学校笼罩着一种紧张压抑的气氛，令人窒息。有三个孩子引人关注：聪颖的金妍斗（金贤秀 饰）、贪吃的陈宥利（郑仁絮 饰）和弟弟自杀身亡的全民秀（白承焕 饰），民秀总是满脸淤青。下课后，仁浩还听到女厕所中有呼喊与哭泣，在门卫的阻拦下他未深究。之后。他意外目睹了校长行贿警察，教导员毒打民秀，宿导溺罚妍斗的行径。一个惊天的隐秘被慢慢揭开，真相令韩国震惊…… 本片取材于2005年光州一所聋哑障碍人学校的真实事件，改编自韩国作家孔枝泳的同名小说。', '[{"name": "黄东赫", "image": "https://p0.meituan.net/movie/0afa977fbab0cdbdec39cc340e38972845036.jpg@128w_170h_1e_1c"}]', '[{"name": "孔刘", "role": "饰：仁浩", "image": "https://p1.meituan.net/moviemachine/75705eaee8ceee0eee43b871bbaec25040803.jpg@128w_170h_1e_1c"}, {"name": "郑有美", "role": "饰：柔珍", "image": "https://p1.meituan.net/movie/d53f13a11a5b901880be79b13a19e22133214.jpg@128w_170h_1e_1c"}, {"name": "金贤秀", "role": "饰：金妍斗", "image": "https://p0.meituan.net/movie/d067a1820a2368c7d7162172d0f4109611448.jpg@128w_170h_1e_1c"}, {"name": "郑仁絮", "role": "饰：陈宥利", "image": "https://p1.meituan.net/movie/027d406d47b7116374297935d35a79f116056.jpg@128w_170h_1e_1c"}, {"name": "白承焕", "role": "饰：全民秀", "image": "https://p1.meituan.net/movie/ebb13460eb55468f47f615efe6b7fe3845650.jpg@128w_170h_1e_1c"}, {"name": "张光", "role": "饰：校长兄弟", "image": "https://p1.meituan.net/movie/af6006b13bbece320d49b6603caaf58835645.jpg@128w_170h_1e_1c"}, {"name": "金志映", "role": "饰：In-ho`s grandmother", "image": "https://p0.meituan.net/movie/4cc29238a043feeec08daca8a2fa80ee28527.jpg@128w_170h_1e_1c"}, {"name": "Baek Seung-Hwan", "role": "饰：Jeon Min-soo", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1