INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (54, 54, 'https://ssr1.scrape.center/detail/54', '鬼子来了 - Devils on the Doorstep', '["剧情", "战争"]', '中国大陆', 139, '2000-05-13', 'https://p0.meituan.net/movie/34f9202c5e823f490ffec4c69d5d0028137395.jpg@464w_644h_1e_1c', '抗日战争末期，河北某偏僻乡村挂家台的老实村民马大三（姜文 饰）迎来棘手难题：某人将分别装有日本鬼子花屋小三郎（香川照之 饰）和汉奸翻译董汉臣的麻袋扔给他，声称不日来取，却迟迟不见其来。厚道的马大三一边将两人当亲爹娘侍奉，一边同村人商议计策，最后决定将两人处死，但终因“天意”不了了之。巧舌如簧的董汉臣为自救，设法令挂甲台村民与花屋小三郎签署合约，称将花屋安全送到日方宪兵队后，村民可得到几大车粮食。马大三与众村民兴高采烈赶到宪兵队，将俘虏交由日方，然而日方并无“以其礼还其礼”的教养。', '[{"name": "姜文", "image": "https://p1.meituan.net/movie/65405524c6f19d3c04a11cfc639a285238873.jpg@128w_170h_1e_1c"}]', '[{"name": "姜文", "role": "饰：马大三", "image": "https://p1.meituan.net/movie/65405524c6f19d3c04a11cfc639a285238873.jpg@128w_170h_1e_1c"}, {"name": "姜宏波", "role": "饰：鱼儿", "image": "https://p1.meituan.net/moviemachine/33172ae09cced1c8455ccd4c7b8fbba0145530.jpg@128w_170h_1e_1c"}, {"name": "陈强", "role": "饰：一刀刘", "image": "https://p0.meituan.net/movie/9ec47522eb77d28dcf2de1bcce04620a27735.jpg@128w_170h_1e_1c"}, {"name": "香川照之", "role": "饰：花屋小三郎", "image": "https://p1.meituan.net/movie/104a8065b6f8a95002c93fae6820f67e90819.jpg@128w_170h_1e_1c"}, {"name": "吴大维", "role": "饰：高少校", "image": "https://p1.meituan.net/movie/027693af33c48aa30750bf4d75a4239935852.jpg@128w_170h_1e_1c"}, {"name": "喜子", "role": "饰：六旺", "image": "https://p0.meituan.net/movie/48fb0367ab077ecc9fe0930c29c7205b36098.jpg@128w_170h_1e_1c"}, {"name": "李海滨", "role": "饰：我", "image": "https://p0.meituan.net/movie/fe5777fec648027b224cdb7d79faff487138.jpg@128w_170h_1e_1c"}, {"name": "泽田谦也", "role": "饰：酒冢猪吉", "image": "https://p1.meituan.net/movie/13fb0d3054c0e48b64de55400a9a487731189.jpg@128w_170h_1e_1c"}, {"name": "梶冈润一", "role": "饰：野野村耕二", "image": "https://p1.meituan.net/moviemachine/2fc6ca3e79a57acba304a327accabd