INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (55, 55, 'https://ssr1.scrape.center/detail/55', '无敌破坏王 - Wreck-It Ralph', '["喜剧", "动画", "奇幻", "冒险"]', '美国', 101, '2012-11-06', 'https://p1.meituan.net/movie/70a574550c4bb928dcc6a40641294785150838.jpg@464w_644h_1e_1c', '无敌破坏王（约翰·C·赖利 配音）生活在一个80年代出品的低精度游戏中。他的设定身份是一个反派，每天的生活就是在游戏《快手阿修》中大搞破坏，其后由玩家操作的英雄人物快手阿修（杰克·麦克布瑞尔 配音） 会及时赶到进行修补，赢得奖牌，包揽一切荣耀。身为反派，破坏王厌倦了自己的生活，眼看阿修被胜利者的光环围绕，自己却日复一日在无趣中过活，他终于决定改变。单纯的他以为只要自己也能得到一枚奖牌，就可以摆脱反派的身份，于是某日在游戏厅歇业后，破坏王偷偷离开了自己的游戏，前去闯荡其他电子游戏的世界。在途中，破坏王结识了来自《英雄使命》的冷酷队长（简·林奇 配音）和来自90年代糖果赛车游戏《甜蜜冲刺》的小女孩云妮（萨拉·丝沃曼 配音）。后者梦想着能上场比赛，但其身份也不允许她梦想成真。破坏王所属的游戏《快手阿修》由于失去了他被认定为系统错误，如不尽快返回，则游戏就会被永久删除；而《甜蜜冲刺》的游戏世界则在悄悄酝酿着一场巨大的、威胁到整个游戏世界的阴谋。这也许是无敌破坏王实现梦想的机会，但也可能是一条不归路…… 他可以扭转乾坤，成为一名真正的英雄吗？', '[{"name": "瑞奇·摩尔", "image": "https://p0.meituan.net/moviemachine/772e88d8cdfeeb3a219f65acaba9d955174627.jpg@128w_170h_1e_1c"}]', '[{"name": "约翰·C·赖利", "role": "饰：拉尔夫 Wreck-It Ralph (voice)", "image": "https://p0.meituan.net/moviemachine/cb04a3746020c74f5be94e3f6ccec1ae146746.jpg@128w_170h_1e_1c"}, {"name": "萨拉·西尔弗曼", "role": "饰：云妮洛普 Vanellope von Schweetz (voice)", "image": "https://p1.meituan.net/moviemachine/1b3762f73494aed7ca2d6c3092584a32150600.jpg@128w_170h_1e_1c"}, {"name": "简·林奇", "role": "饰：卡尔霍恩军士 Sergeant Calhoun (voice)", "image": "https://p1.meituan.net/movie/448e2927c4c658e0d13e7479fbea5b3163742.jpg@128w_170h_1e_1c"}, {"name": "杰克·麦克布瑞尔", "role": "饰：快手阿修 Fix-It Felix (voice)", "image": "https://p0.meituan.net/moviemachine/edcfa1593c5b32e659733a4229275d4d180076.jpg@128w_170h_1e_1c"}, {"name": "斯戴芬妮·斯考特", "role": "饰：娃娃 Moppet", "image": "https://p1.meituan.net/moviemachine/aa772b774279464a0a3c5af30ecfb96648239.jpg@128w_170h_1e_1c"}, {"name": "贾米·埃曼", "role": "饰：图尔 Turtle (voice)", "image": "https://p0.meituan.net/movie/4df7bef6faad165108ee5d