INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (56, 56, 'https://ssr1.scrape.center/detail/56', '致命魔术 - The Prestige', '["剧情", "悬疑", "惊悚"]', '美国、英国', 130, '2006-10-17', 'https://p0.meituan.net/movie/83df1c541e6e0696e67ce7da81cb1e1a251258.jpg@464w_644h_1e_1c', '十九世纪中后期的伦敦，人们还尚未对现代文明有着更加深刻而科学的认识。因此魔术师这一职业在这座堪称国际化的大都市里有着颇高的地位。尤其是贵族出身的魔术师罗伯特·安吉尔（休·杰克曼 饰）更是这一行业的代表人之一。他的同行阿尔弗莱德·伯登（克里斯蒂安·贝尔 饰）虽身家并没有前者的高贵，却也凭借一身的好本事在行内也占得一席之地。实际上，安吉尔与伯登很小的时候就是好朋友，由于两人皆天资聪慧，双双醉心于魔术表演并各自有着不同的特长和本领。但让长大成人后现实中的一切包括名和利种种，渐渐将一对好友推向了敌对的两面。成了同行里的红眼冤家。为了能够成为伦敦城内著名的维多利亚音乐大厅里最受欢迎的魔术师，安吉尔同伯登之间展开了长久而艰苦的争斗。他们一边加强自己的技艺，一边不惜互派卧底，打探彼此的底细，然后加以揭穿或破坏。生性有些偏执的伯登擅长一种能够令观众们难以置信的分身术，他能够在两个封闭的容器内自由穿越，此招数一度将安吉尔的铁杆观众几乎都吸引了过来。安吉尔自然也不甘示弱，他为了能够打败伯登，开始求助于科学家尼姑拉·特斯拉（大卫·鲍伊 饰），请他发明一些奇特的表演道具，其中就包括一个短距离穿越时空的机器，这样在舞台上，他就能以一种不可思议的方式战胜伯登。然而，争强好胜的伯登心头渐渐起了邪念，他想到了更加狠毒的办法来对抗安吉尔。两人的魔术之争也因此逐渐升级、愈演愈烈，直到他们的争斗酿出了一桩惨不忍睹的血案……', '[{"name": "克里斯托弗·诺兰", "image": "https://p1.meituan.net/movie/6efb32d3881c82b1503a0a923de500b6152536.jpg@128w_170h_1e_1c"}]', '[{"name": "休·杰克曼", "role": "饰：罗伯特·安吉尔 Robert Angier", "image": "https://p0.meituan.net/movie/65d592f6786945e5b2c87ddf2c0115e3179475.jpg@128w_170h_1e_1c"}, {"name": "克里斯蒂安·贝尔", "role": "饰：阿尔弗雷德·博登 Alfred Borden", "image": "https://p1.meituan.net/moviemachine/9a631b74966202bd23cf47c7d36c157d44740.jpg@128w_170h_1e_1c"}, {"name": "迈克尔·凯恩", "role": "饰：刀 Cutter", "image": "https://p0.meituan.net/movie/455ed426d5ea2fb7a31a80d6c4eebdfa53569.jpg@128w_170h_1e_1c"}, {"name": "斯嘉丽·约翰逊", "role": "饰：奥利维亚 Olivia Wenscombe", "image": "https://p0.meituan.net/moviemachine/e0cba4ce0e52a2a2f24d25e38f82640d49762.jpg@128w_170h_1e_1c"}, {"name": "派珀·佩拉博", "role": "饰：朱莉娅·安吉尔 Julia Angier", "image": "https://p1.meituan.net/movie/96746315f4df33b56df121ba615e161e45945.jpg@128w_170h_1e_1c"}, {"name": "Brian Tahash", "role": "饰：Blind S