INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (59, 59, 'https://ssr1.scrape.center/detail/59', '怦然心动 - Flipped', '["剧情", "喜剧", "爱情"]', '美国', 90, '2010-07-26', 'https://p0.meituan.net/movie/15f1ac49b6d1ff7b71207672993ed6901536456.jpg@464w_644h_1e_1c', '布莱斯（卡兰·麦克奥利菲 饰）全家搬到小镇，邻家女孩朱丽（玛德琳·卡罗尔 饰）前来帮忙。她对他一见钟情，心愿是获得他的吻。两人是同班同学，她一直想方设法接近他，但是他避之不及。她喜欢爬在高高的梧桐树上看风景。但因为施工，树被要被砍掉，她誓死捍卫，希望他并肩作战，但是他退缩了。她的事迹上了报纸，外公对她颇有好感，令他十分困惑。她凭借鸡下蛋的项目获得了科技展第一名，成了全场焦点，令他黯然失色。她把自家鸡蛋送给他，他听家人怀疑她家鸡蛋不卫生，便偷偷把鸡蛋丢掉。她得知真相，很伤心，两人关系跌入冰点。她跟家人诉说，引发争吵。原来父亲一直攒钱照顾傻弟弟，所以生活拮据。她理解了父母，自己动手，还得到了他外公的鼎力相助。他向她道歉，但是并未解决问题。他开始关注她。鸡蛋风波未平，家庭晚宴与午餐男孩评选又把两人扯在了一起……', '[{"name": "罗伯·莱纳", "image": "https://p1.meituan.net/movie/9234e27bdfe8af67c195dcfde6f5c4aa45213.jpg@128w_170h_1e_1c"}]', '[{"name": "玛德琳·卡罗尔", "role": "饰：朱丽 Juli Baker", "image": "https://p0.meituan.net/movie/19fa2ffcdac374d70c85b6d3fe39326855194.jpg@128w_170h_1e_1c"}, {"name": "卡兰·麦克奥利菲", "role": "饰：布莱斯 Bryce Loski", "image": "https://p1.meituan.net/movie/2811e5729ae354245c55d3392513db9b50358.jpg@128w_170h_1e_1c"}, {"name": "艾丹·奎因", "role": "饰：朱莉父亲 Richard Baker", "image": "https://p1.meituan.net/movie/a9355242616537d71a5c18bb1ab41e857195.jpg@128w_170h_1e_1c"}, {"name": "瑞贝卡·德·莫妮", "role": "饰：帕奇·洛斯基 Patsy Loski", "image": "https://p1.meituan.net/movie/747fb7ddc3956b63c657906e6eef11df16370.jpg@128w_170h_1e_1c"}, {"name": "安东尼·爱德华兹", "role": "饰：史蒂芬·洛斯基 Steven Loski", "image": "https://p0.meituan.net/movie/522398d3865541f0a156401ca254a92b43112.jpg@128w_170h_1e_1c"}, {"name": "约翰·马奥尼", "role": "饰：切特·邓肯 Chet Duncan", "image": "https://p1.meituan.net/movie/e43a8662a781a6679c2732eb7749a82043810.jpg@128w_170h_1e_1c"}, {"name": "佩内洛普·安·米勒", "role": "饰：朱莉母亲 Trina Baker", "image": "https://p1.meituan.net/movie/57fbfe24fd7fd10028284d2f4e128f3150906.jpg@128w_170h_1e_1c"}, {"name": "凯文·韦斯曼",