INSERT INTO "public"."movies" ("id", "source_id", "source_url", "title", "categories", "region", "duration_minutes", "release_date", "poster_url", "drama", "directors", "actors", "rating", "created_at", "updated_at", "subtitle") VALUES (60, 60, 'https://ssr1.scrape.center/detail/60', '驯龙高手 - How to Train Your Dragon', '["喜剧", "动画", "奇幻", "冒险"]', '美国', 98, '2010-05-14', 'https://p0.meituan.net/movie/b0d97e4158b47d653d7a81d66f7dd3092146907.jpg@464w_644h_1e_1c', '维京岛国的少年小嗝嗝（杰伊·巴鲁切尔  配音）是部落统领伟大的斯托里克（杰拉德·巴特勒 配音）的儿子，他非常想像自己的父亲一样亲手屠龙——这些飞龙是岛上维京人放牧羊群的主要天敌——但他每次出现在部落屠龙的战斗中都只给大家徒增烦恼。在一次对抗飞龙的战斗中，希卡普偷偷用射龙器击伤了一只最神秘的“夜之怒龙”，并背着族人放生、豢养，甚至驯服了这只龙，还给它起名“无牙”。希卡普的神秘行径引起了一同训练屠龙技巧的女孩阿斯特丽德（亚美莉卡·费雷拉 配音）的怀疑。阿斯特丽德发现了希卡普的秘密，却同时被身骑“无牙”御风而飞的美妙体验所震撼。格雷决定在屠龙成人礼上向远征归来的斯托里克和族人讲明真相，说服大家放弃屠龙，却偏偏弄巧成拙，害得“无牙”被俘，一场更大的灾难就在眼前……', '[{"name": "迪恩·德布洛斯", "image": "https://p1.meituan.net/movie/5e348db8ee254bda80ace95266c19aba57964.jpg@128w_170h_1e_1c"}, {"name": "克里斯·桑德斯", "image": "https://p0.meituan.net/movie/bbd5224c7d0ef926a42cb6fe3242e04147168.jpg@128w_170h_1e_1c"}]', '[{"name": "杰伊·巴鲁切尔", "role": "饰：小嗝嗝（配音） Hiccup (voice)", "image": "https://p0.meituan.net/moviemachine/4755a3de319fb57c5f6f9f8453518050165265.jpg@128w_170h_1e_1c"}, {"name": "杰拉德·巴特勒", "role": "饰：斯托里克（配音） Stoick (voice)", "image": "https://p0.meituan.net/moviemachine/96984ba6cdd5db86194d48c7387a36a0178495.jpg@128w_170h_1e_1c"}, {"name": "亚美莉卡·费雷拉", "role": "饰：阿斯特丽德（配音） Astrid (voice)", "image": "https://p0.meituan.net/moviemachine/b46faef2560139169f74d3a5648dacfe201996.jpg@128w_170h_1e_1c"}, {"name": "克雷格·费格森", "role": "饰：戈伯（配音） Gobber (voice)", "image": "https://p1.meituan.net/moviemachine/49be8057c82f944eb8e16923b56c70f4156188.jpg@128w_170h_1e_1c"}, {"name": "乔纳·希尔", "role": "饰：鼻涕粗（配音） Snotlout (voice)", "image": "https://p0.meituan.net/moviemachine/c44153849fdf2477d922b607950bc0b9176600.jpg@128w_170h_1e_1c"}, {"name": "克里斯托夫·梅兹-普莱瑟", "role": "饰：鱼脚司（配音） Fishlegs (voice)", "image": "https://p0.meituan.net/moviemachine/a0957066bda9f31f9fde69cccc7619d3208166.jpg@128w_170h_1e_1c"}, {"name": "克里斯汀·韦格", "role": "饰：暴芙那特（配音） Ruffnut (voice)", "image": "https://p0.meituan.net/moviemachine/f7bc8e0e1fc4b6772d9ae63b343d27a0207395.jpg@128w_170h_1e_1c"}, {"name": "T·J·米勒", "role": "饰：悍夫那特（配音） Tuffnut (voice)", "image": "https://p1.meituan.net/moviemachine/bd2e307e50cc9a800ae4e19b63394358195111.jpg@128w_170h_1e_1c"}, {"name": "基隆·埃利奥特", "role": "饰：Viking (uncredited)", "image": "https://p0.meituan.net/movie/818e7180de0df030d8acbf66fbb802fe11813.jpg@128w_170h_1e_1c"}, {"name": "罗宾·阿特金·唐斯", "role": "饰：Ack", "image": "https://p1.meituan.net/movie/aa9803603ff0ac3fcd16611f7836935127630.jpg@128w_170h_1e_1c"}, {"name": "菲利普·麦格雷德", "role": "饰：Starkard (voice)", "image": "https://p1.meituan.net/movie/56759718982aad3ff0418633597dbbc515741.jpg@128w_170h_1e_1c"}, {"name": "阿什利·詹森", "role": "饰：Phlegma the Fierce (voice)", "image": "https://p0.meituan.net/movie/fb961095d9e63164226cb9b7efdee45f51135.jpg@128w_170h_1e_1c"}, {"name": "彼得·奥德", "role": "饰：Havblik den Vældige (voice: Danish Version)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Rasmus Ellersgaard", "role": "饰：Fiskeben (voice: Danish Version)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "罗伯特·汉森", "role": "饰：Hikke (voice: Danish Version)", "image": "https://p0.meituan.net/movie/bbec90238e62541ce85d4b624295332812233.jpg@128w_170h_1e_1c"}, {"name": "Julian Eliot Kellerman", "role": "饰：Stenknold Thorskal (voice: Danish Version)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Sasia Mølgaard", "role": "饰：Benknold (voice: Danish Version)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128w_170h_1e_1c"}, {"name": "Niclas Mortensen", "role": "饰：Snotfjæs (voice: Danish Version)", "image": "https://p1.meituan.net/mmdb/3a2061d771d98566d3e5fa5c08c5e0b33685.png@128